        private void PositionCallsignUpdateIcon()
        {
            if (callsignUpdateLabel == null || callsignDisplayLabel == null)
            {
                return;
            }

            string text = callsignDisplayLabel.Text ?? string.Empty;
            int textWidth = TextRenderer.MeasureText(
                text,
                callsignDisplayLabel.Font,
                new Size(300, callsignDisplayLabel.Height),
                TextFormatFlags.NoPadding | TextFormatFlags.SingleLine).Width;

            int desiredLeft = callsignDisplayLabel.Left + Math.Max(0, textWidth) + S(5);
            int statusBlockLeft = clearanceStatusLabel?.Left ?? 242;
            int maxLeft = Math.Max(callsignDisplayLabel.Left, statusBlockLeft - callsignUpdateLabel.Width - S(12));

            callsignUpdateLabel.Location = new Point(Math.Min(desiredLeft, maxLeft), callsignDisplayLabel.Top);
        }

        private void UpdateCallsignDisplay()
        {
            if (callsignCaptionLabel != null)
            {
                callsignCaptionLabel.Text = "CALLSIGN:";
                callsignCaptionLabel.ForeColor = MainPrimaryTextColor();
            }

            if (callsignDisplayLabel == null)
            {
                return;
            }

            string displayCallsign = GetConnectedPilotCallsign();
            string routeText = BuildActiveFlightRouteText();

            if (string.IsNullOrWhiteSpace(displayCallsign))
            {
                callsignDisplayLabel.Text = "----";
                callsignDisplayLabel.ForeColor = MainPrimaryTextColor();
            }
            else
            {
                callsignDisplayLabel.Text = displayCallsign;
                callsignDisplayLabel.ForeColor = HasActiveVatsimCallsignMismatch()
                    ? Color.FromArgb(255, 86, 74)
                    : Connected ? DcduTheme.Green : MainPrimaryTextColor();
            }

            if (callsignUpdateLabel != null)
            {
                bool showUpdate = HasActiveVatsimCallsignMismatch();
                callsignUpdateLabel.Visible = showUpdate;
                callsignUpdateLabel.Enabled = showUpdate && !callsignMismatchManualCheckInProgress;
                callsignUpdateLabel.Cursor = showUpdate ? Cursors.Hand : Cursors.Default;
                callsignUpdateLabel.Text = callsignMismatchManualCheckInProgress ? "…" : "!";
                callsignUpdateLabel.ForeColor = CallsignMismatchAlarmColor();
                smartStatusToolTip.SetToolTip(callsignUpdateLabel,
                    callsignMismatchManualCheckInProgress
                        ? "Checking VATSIM callsign..."
                        : "Callsign mismatch - click to recheck VATSIM callsign");
                PositionCallsignUpdateIcon();
                callsignUpdateLabel.BringToFront();
            }

            if (routeCaptionLabel != null)
            {
                routeCaptionLabel.Text = "ROUTE:";
                routeCaptionLabel.Visible = true;
                routeCaptionLabel.ForeColor = MainPrimaryTextColor();
            }

            if (callsignRouteLabel != null)
            {
                callsignRouteLabel.Text = routeText;
                callsignRouteLabel.Visible = true;
                if (routeBlinkTimer.Enabled && routeBlinkAmber)
                {
                    callsignRouteLabel.ForeColor = DcduTheme.Amber;
                }
                else
                {
                    callsignRouteLabel.ForeColor = routeText == "----"
                        ? MainPrimaryTextColor()
                        : Connected ? MainAccentColor() : MainPrimaryTextColor();
                }
            }
        }

        private static string NormalizeAtcUnitCallsign(string unit)
        {
            if (string.IsNullOrWhiteSpace(unit))
            {
                return string.Empty;
            }

            string upper = unit.Trim().Trim('@', ':', ';', ',', '.', ' ').ToUpperInvariant();
            Match match = Regex.Match(upper, @"\b[A-Z0-9]{3,10}(?:_[A-Z0-9]{1,10})?\b");

            if (!match.Success)
            {
                return string.Empty;
            }

            string candidate = match.Value;

            string[] reserved =
            {
                "CURRENT", "ATC", "ATS", "UNIT", "LOGON", "ACCEPTED",
                "HANDOVER", "CPDLC", "REQUEST", "CONNECTED", "TO"
            };

            return reserved.Contains(candidate) ? string.Empty : candidate;
        }

        private static string ExtractCurrentAtcUnitFromMessage(string message, string fallbackSender)
        {
            string upper = (message ?? string.Empty).ToUpperInvariant();

            Match explicitUnit = Regex.Match(
                upper,
                @"\bCURRENT\s+AT[SC]\s+UNIT\s*:?\s*([A-Z0-9_]{3,16})\b");

            if (explicitUnit.Success)
            {
                string explicitCallsign = NormalizeAtcUnitCallsign(explicitUnit.Groups[1].Value);
                if (!string.IsNullOrWhiteSpace(explicitCallsign))
                {
                    return explicitCallsign;
                }
            }

            return NormalizeAtcUnitCallsign(fallbackSender);
        }

        private static string BuildFlightPlanSignature(Pilot pilot)
        {
            if (pilot == null)
            {
                return string.Empty;
            }

            Flight_Plan fp = pilot.flight_plan;
            string callsignValue = (pilot.callsign ?? string.Empty).Trim().ToUpperInvariant();

            if (fp == null)
            {
                return callsignValue;
            }

            string departure = fp.departure?.Trim().ToUpperInvariant() ?? string.Empty;
            string arrival = fp.arrival?.Trim().ToUpperInvariant() ?? string.Empty;
            string route = Regex.Replace(fp.route?.Trim().ToUpperInvariant() ?? string.Empty, @"\\s+", " ");
            string cruiseAltitude = fp.altitude?.Trim().ToUpperInvariant() ?? string.Empty;
            string aircraft = fp.aircraft_short?.Trim().ToUpperInvariant() ?? fp.aircraft?.Trim().ToUpperInvariant() ?? string.Empty;

            // Do not include deptime or revision_id. VATSIM can refresh those for the
            // same filed plan, which caused false NEW FP DETECTED prompts after landing.
            return callsignValue + "|" + departure + "|" + arrival + "|" + aircraft + "|" + cruiseAltitude + "|" + route;
        }

        private static string BuildFlightPlanSignature(Prefile prefile)
        {
            if (prefile == null)
            {
                return string.Empty;
            }

            VATSIMFlight_Plan fp = prefile.flight_plan;
            string callsignValue = (prefile.callsign ?? string.Empty).Trim().ToUpperInvariant();

            if (fp == null)
            {
                return callsignValue;
            }

            string departure = fp.departure?.Trim().ToUpperInvariant() ?? string.Empty;
            string arrival = fp.arrival?.Trim().ToUpperInvariant() ?? string.Empty;
            string route = Regex.Replace(fp.route?.Trim().ToUpperInvariant() ?? string.Empty, @"\\s+", " ");
            string cruiseAltitude = fp.altitude?.Trim().ToUpperInvariant() ?? string.Empty;
            string aircraft = fp.aircraft_short?.Trim().ToUpperInvariant() ?? fp.aircraft?.Trim().ToUpperInvariant() ?? string.Empty;

            // Do not include deptime or revision_id. VATSIM can refresh those for the
            // same filed plan, which caused false NEW FP DETECTED prompts after landing.
            return callsignValue + "|" + departure + "|" + arrival + "|" + aircraft + "|" + cruiseAltitude + "|" + route;
        }

        private static string BuildFlightPlanDisplayText(Pilot pilot)
        {
            if (pilot == null)
            {
                return "UNKNOWN";
            }

            string callsignValue = (pilot.callsign ?? string.Empty).Trim().ToUpperInvariant();
            string departure = pilot.flight_plan?.departure?.Trim().ToUpperInvariant() ?? "----";
            string arrival = pilot.flight_plan?.arrival?.Trim().ToUpperInvariant() ?? "----";

            return (string.IsNullOrWhiteSpace(callsignValue) ? "UNKNOWN" : callsignValue) + " " + departure + "-" + arrival;
        }

        private static string BuildFlightPlanDisplayText(Prefile prefile)
        {
            if (prefile == null)
            {
                return "UNKNOWN";
            }

            string callsignValue = (prefile.callsign ?? string.Empty).Trim().ToUpperInvariant();
            string departure = prefile.flight_plan?.departure?.Trim().ToUpperInvariant() ?? "----";
            string arrival = prefile.flight_plan?.arrival?.Trim().ToUpperInvariant() ?? "----";

            return (string.IsNullOrWhiteSpace(callsignValue) ? "UNKNOWN" : callsignValue) + " " + departure + "-" + arrival;
        }

        private static string NormalizeFlightPlanDisplayText(string displayText)
        {
            return Regex.Replace((displayText ?? string.Empty).Trim().ToUpperInvariant(), @"\s+", " ");
        }

        private static bool TryParseFlightPlanDisplayText(string displayText, out string callsignValue, out string departure, out string arrival)
        {
            callsignValue = string.Empty;
            departure = string.Empty;
            arrival = string.Empty;

            string clean = NormalizeFlightPlanDisplayText(displayText);
            Match match = Regex.Match(clean, @"^(?<callsign>[A-Z0-9]{2,12})\s+(?<dep>[A-Z0-9]{4})-(?<arr>[A-Z0-9]{4})$");

            if (!match.Success)
            {
                return false;
            }

            callsignValue = match.Groups["callsign"].Value.Trim().ToUpperInvariant();
            departure = match.Groups["dep"].Value.Trim().ToUpperInvariant();
            arrival = match.Groups["arr"].Value.Trim().ToUpperInvariant();
            return true;
        }

        private bool IsSameAsCurrentLoadedFlightPlanDisplay(string displayText)
        {
            if (!TryParseFlightPlanDisplayText(displayText, out string detectedCallsign, out string detectedDeparture, out string detectedArrival))
            {
                return false;
            }

            string currentRoute = BuildActiveFlightRouteText();
            if (string.IsNullOrWhiteSpace(currentRoute) ||
                string.Equals(currentRoute, "----", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            string expectedRoute = detectedDeparture + "-" + detectedArrival;
            if (!string.Equals(currentRoute.Trim().ToUpperInvariant(), expectedRoute, StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            string activeHoppieCallsign = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string liveVatsimCallsign = (activeVatsimCallsign ?? userVATSIMData?.callsign ?? string.Empty).Trim().ToUpperInvariant();
            string displayedCurrent = GetConnectedPilotCallsign();

            return string.Equals(detectedCallsign, activeHoppieCallsign, StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(detectedCallsign, liveVatsimCallsign, StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(detectedCallsign, displayedCurrent, StringComparison.OrdinalIgnoreCase);
        }

        private bool HasActiveVatsimCallsignMismatch()
        {
            string activeHoppieCallsign = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string onlineCallsign = (activeVatsimCallsign ?? string.Empty).Trim().ToUpperInvariant();
            string pendingCallsign = (pendingHoppieCallsign ?? string.Empty).Trim().ToUpperInvariant();

            if (!Connected || string.IsNullOrWhiteSpace(onlineCallsign))
            {
                return false;
            }

            if (!string.IsNullOrWhiteSpace(pendingCallsign))
            {
                return !string.Equals(onlineCallsign, pendingCallsign, StringComparison.OrdinalIgnoreCase);
            }

            return !string.IsNullOrWhiteSpace(activeHoppieCallsign) &&
                !string.Equals(activeHoppieCallsign, onlineCallsign, StringComparison.OrdinalIgnoreCase);
        }

        private bool HasBlockingCallsignMismatchForMenus()
        {
            if (!Connected)
            {
                return false;
            }

            if (!string.IsNullOrWhiteSpace(pendingHoppieCallsign))
            {
                return true;
            }

            if (vatsimCallsignMismatchWarningActive)
            {
                return true;
            }

            return HasActiveVatsimCallsignMismatch();
        }

        private bool IsHoppieCallsignReadyForInteractiveMenus()
        {
            return DebugUiPreviewMode || (Connected && !HasBlockingCallsignMismatchForMenus());
        }

        private static void CopyLiveVatsimTelemetry(Pilot target, Pilot source)
        {
            if (target == null || source == null)
            {
                return;
            }

            target.cid = source.cid;
            target.name = source.name;
            target.server = source.server;
            target.pilot_rating = source.pilot_rating;
            target.latitude = source.latitude;
            target.longitude = source.longitude;
            target.altitude = source.altitude;
            target.groundspeed = source.groundspeed;
            target.transponder = source.transponder;
            target.heading = source.heading;
            target.qnh_i_hg = source.qnh_i_hg;
            target.qnh_mb = source.qnh_mb;
            target.logon_time = source.logon_time;
            target.last_updated = source.last_updated;
        }

        private void ApplyLiveVatsimPilotUpdate(Pilot refreshedPilot, bool forceMismatchWarning = false)
        {
            if (refreshedPilot == null)
            {
                return;
            }

            string onlineCallsign = refreshedPilot.callsign?.Trim().ToUpperInvariant() ?? string.Empty;
            string activeHoppieCallsign = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string pendingCallsign = (pendingHoppieCallsign ?? string.Empty).Trim().ToUpperInvariant();

            activeVatsimCallsign = onlineCallsign;

            Flight_Plan loadedFlightPlan = userVATSIMData?.flight_plan;
            bool preserveLoadedFlightPlan =
                preserveLoadedFlightPlanOnLiveUpdate &&
                loadedFlightPlan != null &&
                !string.Equals(BuildFlightPlanSignature(refreshedPilot), loadedFlightPlanSignature, StringComparison.OrdinalIgnoreCase);

            if (!string.IsNullOrWhiteSpace(pendingCallsign))
            {
                if (userVATSIMData == null)
                {
                    userVATSIMData = new Pilot { cid = cid };
                }

                // Keep the RLD FP / prefile route active for Quick Actions and TELEX,
                // but keep the Hoppie FROM callsign unchanged until VATSIM actually shows the new callsign.
                CopyLiveVatsimTelemetry(userVATSIMData, refreshedPilot);
                userVATSIMData.callsign = string.IsNullOrWhiteSpace(activeHoppieCallsign)
                    ? onlineCallsign
                    : activeHoppieCallsign;
                userVATSIMData.flight_plan = loadedFlightPlan;

                if (string.Equals(onlineCallsign, pendingCallsign, StringComparison.OrdinalIgnoreCase))
                {
                    string oldHoppieCallsign = activeHoppieCallsign;
                    callsign = pendingCallsign;
                    pendingHoppieCallsign = string.Empty;
                    preserveLoadedFlightPlanOnLiveUpdate = false;
                    userVATSIMData.callsign = callsign;

                    vatsimCallsignMismatchWarningActive = false;
                    lastVatsimCallsignMismatchWarningUtc = DateTime.MinValue;

                    pendingLogon = null;
                    CurrentATCUnit = null;


                    WriteMessage("VATSIM CALLSIGN MATCH OK: " + callsign +
                        ". HOPPIE ACTIVE CALLSIGN SWITCHED" +
                        (string.IsNullOrWhiteSpace(oldHoppieCallsign) ? string.Empty : " FROM " + oldHoppieCallsign) +
                        " TO " + callsign + ". LOGON AGAIN.", "SYSTEM", "SYSTEM");

                    SafeUi(() =>
                    {
                        UpdateCallsignDisplay();
                        UpdateConnectionGatedControls();
                    });
                    return;
                }

                if (forceMismatchWarning ||
                    !vatsimCallsignMismatchWarningActive ||
                    DateTime.UtcNow - lastVatsimCallsignMismatchWarningUtc >= vatsimCallsignMismatchWarningInterval)
                {
                    vatsimCallsignMismatchWarningActive = true;
                    lastVatsimCallsignMismatchWarningUtc = DateTime.UtcNow;

                    WriteMessage("VATSIM CALLSIGN MISMATCH: ONLINE AS " + onlineCallsign +
                        ", NEW FP CALLSIGN IS " + pendingCallsign +
                        ". RED CALLSIGN / HOPPIE STILL USES " + activeHoppieCallsign +
                        " UNTIL VATSIM SHOWS " + pendingCallsign + ".", "SYSTEM", "SYSTEM");
                    PlayCallsignMismatchSound();
                }

                SafeUi(() =>
                {
                    UpdateCallsignDisplay();
                    UpdateConnectionGatedControls();
                });
                return;
            }

            bool mismatch = Connected &&
                !string.IsNullOrWhiteSpace(onlineCallsign) &&
                !string.IsNullOrWhiteSpace(activeHoppieCallsign) &&
                !string.Equals(onlineCallsign, activeHoppieCallsign, StringComparison.OrdinalIgnoreCase);

            if (mismatch || preserveLoadedFlightPlan)
            {
                string preservedCallsign = !string.IsNullOrWhiteSpace(userVATSIMData?.callsign)
                    ? userVATSIMData.callsign.Trim().ToUpperInvariant()
                    : activeHoppieCallsign;

                if (userVATSIMData == null)
                {
                    userVATSIMData = new Pilot { cid = cid };
                }

                CopyLiveVatsimTelemetry(userVATSIMData, refreshedPilot);
                userVATSIMData.callsign = preservedCallsign;
                userVATSIMData.flight_plan = loadedFlightPlan;

                if (mismatch &&
                    (forceMismatchWarning ||
                     !vatsimCallsignMismatchWarningActive ||
                     DateTime.UtcNow - lastVatsimCallsignMismatchWarningUtc >= vatsimCallsignMismatchWarningInterval))
                {
                    vatsimCallsignMismatchWarningActive = true;
                    lastVatsimCallsignMismatchWarningUtc = DateTime.UtcNow;

                    WriteMessage("VATSIM CALLSIGN MISMATCH: ONLINE AS " + onlineCallsign +
                        " BUT EASYCPDLC / HOPPIE USES " + activeHoppieCallsign +
                        ". CHANGE VATSIM CALLSIGN OR DISCONNECT/RECONNECT BEFORE DEPARTURE.", "SYSTEM", "SYSTEM");
                    PlayCallsignMismatchSound();
                }

                SafeUi(() =>
                {
                    UpdateCallsignDisplay();
                    UpdateConnectionGatedControls();
                });
                return;
            }

            userVATSIMData = refreshedPilot;
            preserveLoadedFlightPlanOnLiveUpdate = false;

            if (vatsimCallsignMismatchWarningActive &&
                !string.IsNullOrWhiteSpace(onlineCallsign) &&
                !string.IsNullOrWhiteSpace(activeHoppieCallsign))
            {
                WriteMessage("VATSIM CALLSIGN MATCH OK: " + activeHoppieCallsign, "SYSTEM", "SYSTEM");
            }

            vatsimCallsignMismatchWarningActive = false;
            lastVatsimCallsignMismatchWarningUtc = DateTime.MinValue;
            SafeUi(() =>
            {
                UpdateCallsignDisplay();
                UpdateConnectionGatedControls();
            });
        }

        private static Flight_Plan ConvertPrefileFlightPlan(VATSIMFlight_Plan source)
        {
            if (source == null)
            {
                return null;
            }

            return new Flight_Plan
            {
                flight_rules = source.flight_rules,
                aircraft = source.aircraft,
                aircraft_faa = source.aircraft_faa,
                aircraft_short = source.aircraft_short,
                departure = source.departure,
                arrival = source.arrival,
                alternate = source.alternate,
                cruise_tas = source.cruise_tas,
                altitude = source.altitude,
                deptime = source.deptime,
                enroute_time = source.enroute_time,
                fuel_time = source.fuel_time,
                remarks = source.remarks,
                route = source.route,
                revision_id = source.revision_id,
                assigned_transponder = source.assigned_transponder
            };
        }

        private bool IsAirborneNowForPhase()
        {
            Pilot pilot = userVATSIMData;

            if (pilot == null)
            {
                return false;
            }

            // Altitude-only by design. Groundspeed is deliberately ignored.
            return pilot.altitude > 3000;
        }

        private string GetFlightPhaseSignature(Pilot pilot)
        {
            if (pilot?.flight_plan == null)
            {
                return string.Empty;
            }

            string callsign = (pilot.callsign ?? string.Empty).Trim().ToUpperInvariant();
            string departure = pilot.flight_plan?.departure?.Trim().ToUpperInvariant() ?? string.Empty;
            string arrival = pilot.flight_plan?.arrival?.Trim().ToUpperInvariant() ?? string.Empty;

            return callsign + "|" + departure + "|" + arrival;
        }

        private static string ReadObjectStringProperty(object source, params string[] names)
        {
            if (source == null)
            {
                return string.Empty;
            }

            Type type = source.GetType();
            foreach (string name in names)
            {
                object value = type.GetProperty(name)?.GetValue(source);
                if (value != null)
                {
                    string text = value.ToString();
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        return text.Trim();
                    }
                }
            }

            return string.Empty;
        }

        private static bool TryReadObjectDoubleProperty(object source, out double value, params string[] names)
        {
            value = 0;

            if (source == null)
            {
                return false;
            }

            Type type = source.GetType();
            foreach (string name in names)
            {
                object raw = type.GetProperty(name)?.GetValue(source);
                if (raw == null)
                {
                    continue;
                }

                if (raw is double d)
                {
                    value = d;
                    return true;
                }

                if (raw is float f)
                {
                    value = f;
                    return true;
                }

                if (raw is decimal m)
                {
                    value = (double)m;
                    return true;
                }

                if (double.TryParse(raw.ToString(), System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture, out double parsed))
                {
                    value = parsed;
                    return true;
                }
            }

            return false;
        }

        private bool TryGetSimbriefAirportPosition(string icao, out double lat, out double lon)
        {
            lat = 0;
            lon = 0;

            string target = (icao ?? string.Empty).Trim().ToUpperInvariant();
            if (target.Length != 4 || simbriefData == null)
            {
                return false;
            }

            object fixesObject = simbriefData.GetType().GetProperty("fix")?.GetValue(simbriefData);
            if (fixesObject is not System.Collections.IEnumerable fixes)
            {
                return false;
            }

            foreach (object fix in fixes)
            {
                string ident = ReadObjectStringProperty(fix, "ident", "name", "icao_code", "icao", "id").ToUpperInvariant();
                if (!string.Equals(ident, target, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                if (TryReadObjectDoubleProperty(fix, out lat, "pos_lat", "lat", "latitude") &&
                    TryReadObjectDoubleProperty(fix, out lon, "pos_long", "lon", "lng", "longitude"))
                {
                    return Math.Abs(lat) > 0.0001 || Math.Abs(lon) > 0.0001;
                }
            }

            return false;
        }

        private static double DistanceNm(double lat1, double lon1, double lat2, double lon2)
        {
            const double earthRadiusNm = 3440.065;
            double dLat = (lat2 - lat1) * Math.PI / 180.0;
            double dLon = (lon2 - lon1) * Math.PI / 180.0;
            double rLat1 = lat1 * Math.PI / 180.0;
            double rLat2 = lat2 * Math.PI / 180.0;

            double a =
                Math.Sin(dLat / 2.0) * Math.Sin(dLat / 2.0) +
                Math.Cos(rLat1) * Math.Cos(rLat2) *
                Math.Sin(dLon / 2.0) * Math.Sin(dLon / 2.0);

            return earthRadiusNm * 2.0 * Math.Atan2(Math.Sqrt(a), Math.Sqrt(1.0 - a));
        }

        private bool IsPilotLikelyAtArrivalAirport(Pilot pilot)
        {
            string departure = pilot?.flight_plan?.departure?.Trim().ToUpperInvariant() ?? string.Empty;
            string arrival = pilot?.flight_plan?.arrival?.Trim().ToUpperInvariant() ?? string.Empty;

            if (pilot == null ||
                string.IsNullOrWhiteSpace(arrival) ||
                pilot.altitude > 3000 ||
                !TryGetSimbriefAirportPosition(arrival, out double arrLat, out double arrLon))
            {
                return false;
            }

            double arrivalDistanceNm = DistanceNm(pilot.latitude, pilot.longitude, arrLat, arrLon);
            if (arrivalDistanceNm > 8.0)
            {
                return false;
            }

            if (TryGetSimbriefAirportPosition(departure, out double depLat, out double depLon))
            {
                double departureDistanceNm = DistanceNm(pilot.latitude, pilot.longitude, depLat, depLon);
                return arrivalDistanceNm + 3.0 < departureDistanceNm;
            }

            return true;
        }

        private bool TryGetFlightPhaseAirportDistances(Pilot pilot, out double departureDistanceNm, out double arrivalDistanceNm, out double routeDistanceNm)
        {
            departureDistanceNm = double.MaxValue;
            arrivalDistanceNm = double.MaxValue;
            routeDistanceNm = double.MaxValue;

            string departure = pilot?.flight_plan?.departure?.Trim().ToUpperInvariant() ?? string.Empty;
            string arrival = pilot?.flight_plan?.arrival?.Trim().ToUpperInvariant() ?? string.Empty;

            if (pilot == null ||
                string.IsNullOrWhiteSpace(departure) ||
                string.IsNullOrWhiteSpace(arrival) ||
                !TryGetSimbriefAirportPosition(departure, out double depLat, out double depLon) ||
                !TryGetSimbriefAirportPosition(arrival, out double arrLat, out double arrLon))
            {
                return false;
            }

            departureDistanceNm = DistanceNm(pilot.latitude, pilot.longitude, depLat, depLon);
            arrivalDistanceNm = DistanceNm(pilot.latitude, pilot.longitude, arrLat, arrLon);
            routeDistanceNm = DistanceNm(depLat, depLon, arrLat, arrLon);

            return routeDistanceNm > 20.0 &&
                   departureDistanceNm < double.MaxValue &&
                   arrivalDistanceNm < double.MaxValue;
        }

        private bool IsPilotLikelyInDepartureClimbout(Pilot pilot)
        {
            if (pilot?.flight_plan == null ||
                pilot.altitude <= 3000 ||
                pilot.altitude >= 22000 ||
                !TryGetFlightPhaseAirportDistances(pilot, out double departureDistanceNm, out double arrivalDistanceNm, out double routeDistanceNm))
            {
                return false;
            }

            // If EasyCPDLC is restarted during climbout, this app session did not see the
            // ground phase. Do not assume ARR just because altitude is below FL220.
            // Use position instead: close to departure and clearly not near destination = DEP/AIRBORN.
            if (departureDistanceNm <= 80.0 && departureDistanceNm + 20.0 < arrivalDistanceNm)
            {
                return true;
            }

            if (routeDistanceNm > 120.0 &&
                departureDistanceNm / routeDistanceNm <= 0.28 &&
                departureDistanceNm + 15.0 < arrivalDistanceNm)
            {
                return true;
            }

            return false;
        }

        private bool IsPilotLikelyInArrivalDescent(Pilot pilot)
        {
            if (pilot?.flight_plan == null ||
                pilot.altitude <= 3000 ||
                pilot.altitude >= 22000 ||
                !TryGetFlightPhaseAirportDistances(pilot, out double departureDistanceNm, out double arrivalDistanceNm, out double routeDistanceNm))
            {
                return false;
            }

            // Restarted airborne below FL220 can be ARR only if position agrees:
            // closer to destination and already well past the departure part of the route.
            if (arrivalDistanceNm <= 180.0 && arrivalDistanceNm + 20.0 < departureDistanceNm)
            {
                return true;
            }

            // Low-altitude arrival-side restart/reconnect. This catches cases like
            // being established in descent around 8000 ft without having seen FL220
            // in this EasyCPDLC session.
            if (pilot.altitude <= 12000 &&
                arrivalDistanceNm <= 260.0 &&
                arrivalDistanceNm + 5.0 < departureDistanceNm)
            {
                return true;
            }

            if (routeDistanceNm > 120.0 &&
                arrivalDistanceNm / routeDistanceNm <= 0.45 &&
                arrivalDistanceNm + 10.0 < departureDistanceNm)
            {
                return true;
            }

            return false;
        }

        private void ResetFlightPhaseTrendTracking()
        {
            flightPhaseStartedAirborneBelowEnroute = false;
            flightPhaseDescentTrendSeen = false;
            lastFlightPhaseObservedAltitude = int.MinValue;
        }

        private void TrackFlightPhaseAltitudeTrend(Pilot pilot)
        {
            if (pilot == null || pilot.altitude <= 0)
            {
                return;
            }

            if (lastFlightPhaseObservedAltitude != int.MinValue &&
                pilot.altitude < 22000 &&
                pilot.altitude + 400 < lastFlightPhaseObservedAltitude)
            {
                flightPhaseDescentTrendSeen = true;
            }
            else if (lastFlightPhaseObservedAltitude != int.MinValue &&
                     pilot.altitude < 22000 &&
                     pilot.altitude > lastFlightPhaseObservedAltitude + 400)
            {
                // Clear stale DESC state when the aircraft is clearly climbing.
                flightPhaseDescentTrendSeen = false;
                if (!flightPhaseEnrouteSeen)
                {
                    flightPhaseArrivalSeen = false;
                    preferArrivalStationAfterAirborne = false;
                }
            }

            lastFlightPhaseObservedAltitude = pilot.altitude;
        }

        private bool HasUsableFlightPhaseAirportDistances(Pilot pilot)
        {
            return TryGetFlightPhaseAirportDistances(
                pilot,
                out double departureDistanceNm,
                out double arrivalDistanceNm,
                out double routeDistanceNm) &&
                departureDistanceNm < double.MaxValue &&
                arrivalDistanceNm < double.MaxValue &&
                routeDistanceNm > 20.0;
        }

        private bool IsLowAltitudeAirborneRestartLikelyDescent(Pilot pilot)
        {
            if (pilot?.flight_plan == null ||
                pilot.altitude <= 3000 ||
                pilot.altitude >= 22000 ||
                flightPhaseGroundObservedThisSession)
            {
                return false;
            }

            if (IsPilotLikelyInDepartureClimbout(pilot))
            {
                return false;
            }

            if (IsPilotLikelyInArrivalDescent(pilot))
            {
                return true;
            }

            // If airport coordinates are available and did not support arrival-side
            // descent, do not guess. Position-based logic has priority.
            if (HasUsableFlightPhaseAirportDistances(pilot))
            {
                return false;
            }

            // Never guess DESC just from low altitude after restart. That breaks
            // real climbouts. Without airport coordinates, require an actual observed
            // descent trend from live VATSIM updates.
            return flightPhaseDescentTrendSeen && pilot.altitude <= 18000;
        }

        private void EnsureFlightPhaseSignature(Pilot pilot)
        {
            if (pilot != null && pilot.altitude <= 3000)
            {
                // Session memory: if we really saw the aircraft on/near the ground, then
                // an airborne state below FL220 later is a departure/climbout, not DESC.
                flightPhaseGroundObservedThisSession = true;
            }

            string signature = GetFlightPhaseSignature(pilot);

            if (!string.Equals(signature, lastFlightPhaseSignature, StringComparison.OrdinalIgnoreCase))
            {
                lastFlightPhaseSignature = signature;
                flightPhaseEnrouteSeen = false;
                flightPhaseArrivalSeen = false;
                flightPhaseDepartureSeen = false;
                preferArrivalStationAfterAirborne = false;
                ResetFlightPhaseTrendTracking();

                if (pilot != null)
                {
                    flightPhaseStartedAirborneBelowEnroute = pilot.altitude > 3000 && pilot.altitude < 22000;

                    if (pilot.altitude <= 3000)
                    {
                        flightPhaseGroundObservedThisSession = true;

                        if (IsPilotLikelyAtArrivalAirport(pilot))
                        {
                            // Program was restarted already at/near the destination airport.
                            // Do not fall back to DEP just because this session did not see
                            // the previous descent/arrival sequence.
                            flightPhaseEnrouteSeen = true;
                            flightPhaseArrivalSeen = true;
                            flightPhaseDepartureSeen = true;
                            preferArrivalStationAfterAirborne = true;
                        }
                        else
                        {
                            // Program started at/near the departure ground phase.
                            flightPhaseDepartureSeen = true;
                        }
                    }
                    else if (pilot.altitude < 22000)
                    {
                        if (flightPhaseGroundObservedThisSession || IsPilotLikelyInDepartureClimbout(pilot))
                        {
                            // Normal same-session departure/climbout after the app saw ground,
                            // or program restart during departure climbout near the origin airport.
                            flightPhaseDepartureSeen = true;
                            flightPhaseArrivalSeen = false;
                            preferArrivalStationAfterAirborne = false;
                        }
                        else if (IsPilotLikelyInArrivalDescent(pilot) || IsLowAltitudeAirborneRestartLikelyDescent(pilot))
                        {
                            // Program was started already airborne below FL220 and position,
                            // low altitude, or descent trend supports the arrival/descent side.
                            flightPhaseEnrouteSeen = true;
                            flightPhaseArrivalSeen = true;
                            flightPhaseDepartureSeen = true;
                            preferArrivalStationAfterAirborne = true;
                        }
                        else
                        {
                            // Ambiguous restart below FL220:
                            // do not poison the state as DEP. Keep it neutral so later
                            // SimBrief coordinates or descent trend can correct to DESC.
                            flightPhaseDepartureSeen = false;
                            flightPhaseArrivalSeen = false;
                            preferArrivalStationAfterAirborne = false;
                        }
                    }
                    else
                    {
                        // Program started enroute/cruise.
                        flightPhaseEnrouteSeen = true;
                        flightPhaseDepartureSeen = true;
                    }
                }
            }

            TrackFlightPhaseAltitudeTrend(pilot);
        }

        private bool HasReachedEnrouteForPhase(Pilot pilot)
        {
            if (pilot == null)
            {
                return false;
            }

            // Altitude-only enroute marker.
            // Use FL220 to avoid switching to ARR immediately after departure/climbout.
            return pilot.altitude >= 22000;
        }

        private bool IsLandedAfterArrivalPhase()
        {
            Pilot pilot = userVATSIMData;

            if (pilot == null)
            {
                return false;
            }

            EnsureFlightPhaseSignature(pilot);

            return flightPhaseArrivalSeen &&
                   pilot.altitude <= 3000;
        }

        private bool IsArrivalPhaseLikely()
        {
            Pilot pilot = userVATSIMData;

            if (pilot?.flight_plan == null)
            {
                return false;
            }

            EnsureFlightPhaseSignature(pilot);

            if (pilot.altitude <= 3000)
            {
                flightPhaseGroundObservedThisSession = true;

                if (IsPilotLikelyAtArrivalAirport(pilot))
                {
                    flightPhaseEnrouteSeen = true;
                    flightPhaseArrivalSeen = true;
                    flightPhaseDepartureSeen = true;
                    preferArrivalStationAfterAirborne = true;
                    return true;
                }

                if (!flightPhaseArrivalSeen)
                {
                    flightPhaseDepartureSeen = true;
                }

                return flightPhaseArrivalSeen;
            }

            if (HasReachedEnrouteForPhase(pilot))
            {
                flightPhaseEnrouteSeen = true;
                flightPhaseDepartureSeen = true;
                return false;
            }

            if (IsPilotLikelyInDepartureClimbout(pilot))
            {
                flightPhaseDepartureSeen = true;
                flightPhaseArrivalSeen = false;
                preferArrivalStationAfterAirborne = false;
                return false;
            }

            // If the app was started/reconnected already in descent, SimBrief airport
            // coordinates may only become available after the first phase calculation.
            // Re-check position/low-altitude restart/trend so 8000 ft in descent does not stay AIRBORN.
            if (IsPilotLikelyInArrivalDescent(pilot) || IsLowAltitudeAirborneRestartLikelyDescent(pilot))
            {
                flightPhaseEnrouteSeen = true;
                flightPhaseArrivalSeen = true;
                flightPhaseDepartureSeen = true;
                preferArrivalStationAfterAirborne = true;
                return true;
            }

            // Required normal order:
            // DEP -> AIRBORN -> DESC -> LND -> NEXT FP.
            //
            // Normal climb case:
            // If we have seen the departure/ground phase in this app session, do not
            // enter DESC before an altitude-only enroute marker was reached.
            if (flightPhaseDepartureSeen && !flightPhaseEnrouteSeen)
            {
                return false;
            }

            // Normal descent case:
            // after >= FL220, dropping below FL220 means ARR.
            if (flightPhaseEnrouteSeen && pilot.altitude < 22000)
            {
                flightPhaseArrivalSeen = true;
                preferArrivalStationAfterAirborne = true;
            }

            return flightPhaseArrivalSeen;
        }

        private string BuildFlightPhaseBadgeText()
        {
            if (nextFlightPlanDetected)
            {
                return "🆕 NEXT FP";
            }

            if (!Connected || userVATSIMData?.flight_plan == null)
            {
                return "○ STBY";
            }

            if (IsLandedAfterArrivalPhase())
            {
                return "🧳 LND";
            }

            if (IsAirborneNowForPhase())
            {
                return IsArrivalPhaseLikely()
                    ? "🛬 DESC"
                    : "✈ AIRBORN";
            }

            return "🛫 DEP";
        }

        private Color FlightPhaseStatusColor()
        {
            // Keep FP PHASE deliberately neutral/grey so it looks like part of the DCDU frame
            // instead of another active CLR/PDC/ATIS status light.
            return Color.FromArgb(176, 184, 188);
        }

        private void UpdateFlightPhaseBadge()
        {
            if (flightPhaseLabel == null)
            {
                return;
            }

            if (flightPhaseCaptionLabel != null)
            {
                flightPhaseCaptionLabel.Font = statusCaptionLabel?.Font ?? textFontBold;
                flightPhaseCaptionLabel.ForeColor = MainPrimaryTextColor();
                flightPhaseCaptionLabel.Invalidate();
            }

            flightPhaseLabel.Font = statusValueLabel?.Font ?? textFontBold;
            flightPhaseLabel.Text = BuildFlightPhaseBadgeText();
            flightPhaseLabel.ForeColor = FlightPhaseStatusColor();
            flightPhaseLabel.Invalidate();
        }

        private void AtisStatusLabel_MouseUp(object sender, MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Right)
            {
                _ = QuickWeatherRefreshAsync();
            }
        }

        private Task QuickWeatherRefreshAsync()
        {
            string station = GetSuggestedWeatherStationForRequests();

            if (string.IsNullOrWhiteSpace(station))
            {
                WriteMessage("QUICK ACTIONS FAILED: NO DEP/ARR STATION", "SYSTEM", "SYSTEM");
                return Task.CompletedTask;
            }

            string metarTarget = ResolveWeatherStationForRequest(station);
            string atisTarget = GetPreferredAtisHoverTarget();

            if (string.IsNullOrWhiteSpace(atisTarget))
            {
                atisTarget = metarTarget;
            }

            metarTarget = metarTarget.Trim().ToUpperInvariant();
            atisTarget = atisTarget.Trim().ToUpperInvariant();

            WriteMessage("QUICK ACTIONS WX REFRESH FOR " + FormatAtisTargetForList(atisTarget), "SYSTEM", "SYSTEM");

            WriteMessage("METAR REQUEST", "METAR", metarTarget, true);
            ArtificialDelay("METAR " + metarTarget, "INFOREQ", "REQUEST");

            WriteMessage("ATIS REQUEST", "ATIS", atisTarget, true);
            ArtificialDelay("VATATIS " + atisTarget, "INFOREQ", "REQUEST");

            _ = RefreshVatsimForAtisHoverAsync();
            return Task.CompletedTask;
        }


        private string GetQuickWeatherFlightPlanStation(bool useArrival)
        {
            return (useArrival
                    ? userVATSIMData?.flight_plan?.arrival
                    : userVATSIMData?.flight_plan?.departure)?
                .Trim()
                .ToUpperInvariant() ?? string.Empty;
        }

        private string GetQuickAtisTargetForStation(string station, bool useArrival)
        {
            string normalized = (station ?? string.Empty).Trim().ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(normalized))
            {
                return string.Empty;
            }

            if (TryResolveAtisRequestTarget(normalized, useArrival ? "ARRIVAL" : "DEPARTURE", out string resolvedTarget, out _))
            {
                return resolvedTarget;
            }

            return normalized;
        }

        private static string FormatAtisInlineWarning(string warning)
        {
            string clean = (warning ?? string.Empty)
                .Replace("\r\n", "\n")
                .Replace("\r", "\n")
                .Trim()
                .ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(clean))
            {
                return string.Empty;
            }

            clean = clean.Replace(". SELECT ", ".\nSELECT ");
            clean = clean.Replace(". GENERIC ", ".\nGENERIC ");
            clean = clean.Replace(". ", ".\n");

            return clean;
        }

        public bool TryResolveAtisRequestTarget(string station, string selectedType, out string target, out string warning)
        {
            string normalized = (station ?? string.Empty).Trim().ToUpperInvariant();
            string selection = (selectedType ?? string.Empty).Trim().ToUpperInvariant();

            target = normalized;
            warning = string.Empty;

            if (string.IsNullOrWhiteSpace(normalized))
            {
                warning = "ATIS REQUEST FAILED: NO STATION SELECTED.";
                return false;
            }

            bool hasGeneric = IsAtisOnline(normalized);
            bool hasArrival = IsAtisOnline(normalized + "_A");
            bool hasDeparture = IsAtisOnline(normalized + "_D");

            if (selection == "ARRIVAL" || selection == "ARR")
            {
                target = hasArrival ? normalized + "_A" : normalized;
                return true;
            }

            if (selection == "DEPARTURE" || selection == "DEP")
            {
                target = hasDeparture ? normalized + "_D" : normalized;
                return true;
            }

            if (hasArrival || hasDeparture)
            {
                string available = string.Join(" / ", new[]
                {
                    hasArrival ? "ARRIVAL" : string.Empty,
                    hasDeparture ? "DEPARTURE" : string.Empty
                }.Where(value => !string.IsNullOrWhiteSpace(value)));

                warning = "ATIS SPLIT AVAILABLE FOR " + normalized + ". SELECT " + available + " INSTEAD OF NONE.";
                if (hasGeneric)
                {
                    warning += "\nGENERIC " + normalized + "_ATIS ALSO ONLINE, BUT SPLIT ATIS HAS PRIORITY.";
                }

                return false;
            }

            target = normalized;
            return true;
        }

        private void SendQuickWeatherRequest(bool requestAtis, bool useArrival)
        {
            string station = GetQuickWeatherFlightPlanStation(useArrival);

            if (string.IsNullOrWhiteSpace(station))
            {
                WriteMessage("QUICK ACTIONS FAILED: NO " + (useArrival ? "ARR" : "DEP") + " IN FLIGHT PLAN", "SYSTEM", "SYSTEM");
                return;
            }

            if (requestAtis)
            {
                string atisTarget = GetQuickAtisTargetForStation(station, useArrival);

                WriteMessage("ATIS REQUEST", "ATIS", atisTarget, true);
                ArtificialDelay("VATATIS " + atisTarget, "INFOREQ", "REQUEST");
                _ = RefreshVatsimForAtisHoverAsync();
            }
            else
            {
                string metarTarget = station.Trim().ToUpperInvariant();

                WriteMessage("METAR REQUEST", "METAR", metarTarget, true);
                ArtificialDelay("METAR " + metarTarget, "INFOREQ", "REQUEST");
            }
        }



