            }
            if (callsignUpdateLabel != null)
            {
                callsignUpdateLabel.BringToFront();
            }

            if (routeCaptionLabel != null)
            {
                routeCaptionLabel.BringToFront();
            }
            if (callsignRouteLabel != null)
            {
                callsignRouteLabel.BringToFront();
            }
            flightPhaseLabel.BringToFront();
            ConfigureClearanceTimelinePopup();
            ConfigureAtisAvailabilityPopup();
            ConfigureAtisAutoPopup();
            ConfigureQuickWxPopup();
            messageFilterLabel.BringToFront();
            ConfigureFilterDropdownMenu();
            UpdateSmartStatusLabelColors();
            UpdateMessageFilterLabel();
            UpdateOnlineStatusLabel();
            UpdateClearanceStatusLabel();
            UpdateCallsignDisplay();
            UpdateFlightPhaseBadge();
        }

        private System.Windows.Forms.Label CreateMainStatusBadge(string text, Cursor cursor)
        {
            System.Windows.Forms.Label label = new DcduBadgeLabel
            {
                AutoSize = false,
                BackColor = Color.Transparent,
                BorderStyle = BorderStyle.None,
                TextAlign = ContentAlignment.MiddleCenter,
                Cursor = cursor,
                Text = text ?? string.Empty,
                TabStop = cursor == Cursors.Hand
            };

            label.MouseEnter += (_, __) =>
            {
                label.Invalidate();
            };
            label.MouseLeave += (_, __) =>
            {
                UpdateSmartStatusLabelColors();
                label.Invalidate();
            };
            label.GotFocus += (_, __) => label.Invalidate();
            label.LostFocus += (_, __) => label.Invalidate();

            return label;
        }

        private void ApplyTopInfoFonts()
        {
            bool isBoeing = DcduStyleManager.IsBoeing;
            Font captionFont = isBoeing
                ? CreateDpiStablePointFont("Segoe UI Semibold", 10.2f, FontStyle.Regular)
                : textFontBold;
            Font valueFont = isBoeing
                ? CreateDpiStablePointFont("Segoe UI Semibold", 10.2f, FontStyle.Regular)
                : textFontBold;
            Font headerFont = isBoeing
                ? CreateDpiStablePointFont("Segoe UI Semibold", 10.4f, FontStyle.Regular)
                : textFontBold;

            if (statusCaptionLabel != null)
            {
                statusCaptionLabel.Font = captionFont;
                statusCaptionLabel.UseCompatibleTextRendering = false;
            }

            if (statusValueLabel != null)
            {
                statusValueLabel.Font = valueFont;
                statusValueLabel.UseCompatibleTextRendering = false;
            }

            if (callsignCaptionLabel != null)
            {
                callsignCaptionLabel.Font = captionFont;
                callsignCaptionLabel.UseCompatibleTextRendering = false;
            }

            if (callsignDisplayLabel != null)
            {
                callsignDisplayLabel.Font = valueFont;
                callsignDisplayLabel.UseCompatibleTextRendering = false;
            }

            if (callsignUpdateLabel != null)
            {
                callsignUpdateLabel.Font = CreateDpiStablePixelFont(valueFont.FontFamily, Math.Max(8.4f, valueFont.Size - 1.0f), FontStyle.Bold);
            }

            if (routeCaptionLabel != null)
            {
                routeCaptionLabel.Font = captionFont;
                routeCaptionLabel.UseCompatibleTextRendering = false;
            }

            if (callsignRouteLabel != null)
            {
                callsignRouteLabel.Font = valueFont;
                callsignRouteLabel.UseCompatibleTextRendering = false;
            }

            if (flightPhaseCaptionLabel != null)
            {
                flightPhaseCaptionLabel.Font = captionFont;
                flightPhaseCaptionLabel.UseCompatibleTextRendering = false;
            }

            if (flightPhaseLabel != null)
            {
                flightPhaseLabel.Font = valueFont;
                flightPhaseLabel.UseCompatibleTextRendering = false;
            }

            if (atcUnitLabel != null)
            {
                atcUnitLabel.Font = captionFont;
                atcUnitLabel.UseCompatibleTextRendering = false;
            }

            if (atcUnitDisplay != null)
            {
                atcUnitDisplay.Font = valueFont;
                atcUnitDisplay.UseCompatibleTextRendering = false;
            }

            if (messageHeaderLabel != null)
            {
                messageHeaderLabel.Font = headerFont;
                messageHeaderLabel.UseCompatibleTextRendering = false;
            }
        }

        private void PositionMessageFilterDropdownInline()
        {
            if (messageFilterLabel == null || messageHeaderLabel == null)
            {
                return;
            }

            Size filterSize = SS(DcduStyleManager.IsBoeing ? new Size(50, 18) : new Size(46, 18));
            string headerText = string.IsNullOrWhiteSpace(messageHeaderLabel.Text)
                ? "MESSAGES / DATA"
                : messageHeaderLabel.Text;

            Font headerFont = messageHeaderLabel.Font ?? textFontBold ?? Font;
            int headerWidth = TextRenderer.MeasureText(
                headerText,
                headerFont,
                SS(new Size(260, 24)),
                TextFormatFlags.NoPadding | TextFormatFlags.SingleLine).Width;

            int x = messageHeaderLabel.Left + headerWidth + S(DcduStyleManager.IsBoeing ? 12 : 6);
            int y = messageHeaderLabel.Top + S(1);

            if (screenPanel != null)
            {
                x = Math.Min(x, Math.Max(messageHeaderLabel.Left + S(84), screenPanel.Width - filterSize.Width - S(8)));
            }

            messageFilterLabel.Size = filterSize;
            messageFilterLabel.Location = new Point(x, y);
        }

