        private PdcDiscoveryResult DiscoverPdcAvailability(string departureStation)
        {
            string station = (departureStation ?? string.Empty).Trim().ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(station))
            {
                return new PdcDiscoveryResult
                {
                    StatusText = "--",
                    HoverText = "PDC standby"
                };
            }

            if (!hoppieOnlineStationsLoaded)
            {
                return new PdcDiscoveryResult
                {
                    StatusText = "?",
                    HoverText = "PDC status unknown - Hoppie station list not loaded"
                };
            }

            if (IsHoppieLogonOnline(station))
            {
                return new PdcDiscoveryResult
                {
                    StatusText = "AVAIL",
                    IsAvailable = true,
                    AllowReqClr = true,
                    LogonCode = station,
                    Source = "HOPPIE STATION ONLINE",
                    HoverText = "PDC/DCL available\nLogon: " + station + "\nSource: Hoppie station online"
                };
            }

            List<Controller> localControllers = GetLocalPdcControllers(station).ToList();
            foreach (Controller local in localControllers)
            {
                string info = GetControllerInfoText(local);
                string code = ExtractPdcDclLogonCode(info, station);

                if (!string.IsNullOrWhiteSpace(code) && IsHoppieLogonOnline(code))
                {
                    return new PdcDiscoveryResult
                    {
                        StatusText = "AVAIL",
                        IsAvailable = true,
                        AllowReqClr = true,
                        LogonCode = code,
                        Controller = local.callsign ?? string.Empty,
                        Source = "LOCAL MATCH",
                        HoverText = "PDC/DCL available\nController: " + local.callsign + "\nLogon: " + code + "\nHoppie station online"
                    };
                }
            }

            Controller center = FindPossiblePdcCenterController(station, out string centerCode, out string centerReason);
            if (center != null && !string.IsNullOrWhiteSpace(centerCode) && IsHoppieLogonOnline(centerCode))
            {
                return new PdcDiscoveryResult
                {
                    StatusText = "MAYBE",
                    IsAvailable = true,
                    IsFallbackCandidate = true,
                    AllowReqClr = true,
                    LogonCode = centerCode,
                    Controller = center.callsign ?? string.Empty,
                    Source = string.IsNullOrWhiteSpace(centerReason) ? "CTR/FSS DEP FIR MATCH" : centerReason,
                    HoverText = "PDC/DCL candidate\nController: " + center.callsign + "\nLogon: " + centerCode + "\nDouble check on VATSIM Radar"
                };
            }

            Controller regional = FindPossiblePdcRegionalAppController(station, out string regionalCode, out string regionalReason);
            if (regional != null && !string.IsNullOrWhiteSpace(regionalCode) && IsHoppieLogonOnline(regionalCode))
            {
                return new PdcDiscoveryResult
                {
                    StatusText = "AVAIL",
                    IsAvailable = true,
                    IsFallbackCandidate = true,
                    AllowReqClr = true,
                    LogonCode = regionalCode,
                    Controller = regional.callsign ?? string.Empty,
                    Source = string.IsNullOrWhiteSpace(regionalReason) ? "REGIONAL APP DCL MATCH" : regionalReason,
                    HoverText = "PDC/DCL available\nController: " + regional.callsign + "\nLogon: " + regionalCode + "\nSource: regional DCL info"
                };
            }

            if (localControllers.Count > 0)
            {
                string localNames = string.Join(", ", localControllers.Select(controller => controller.callsign).Where(value => !string.IsNullOrWhiteSpace(value)));
                return new PdcDiscoveryResult
                {
                    StatusText = "NONE",
                    HoverText = "PDC not available\nLocal controller online: " + localNames + "\nNo usable online PDC/DCL logon found in local controller info"
                };
            }

            return new PdcDiscoveryResult
            {
                StatusText = "NONE",
                HoverText = "PDC not available\nNo DEP local DEL/GND/TWR/APP, regional APP, or DEP FIR center with usable online Hoppie logon found"
            };
        }

        private bool IsPilotLikelyOnGroundAtDepartureStation(string station)
        {
            string cleanStation = (station ?? string.Empty).Trim().ToUpperInvariant();

            if (userVATSIMData == null ||
                cleanStation.Length != 4 ||
                userVATSIMData.altitude > 3000 ||
                !TryGetSimbriefAirportPosition(cleanStation, out double depLat, out double depLon))
            {
                return false;
            }

            double distanceNm = DistanceNm(userVATSIMData.latitude, userVATSIMData.longitude, depLat, depLon);
            return distanceNm <= 12.0;
        }

        private static bool ControllerPrefixMatchesDclLogon(string callsign, string code)
        {
            string upperCallsign = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string cleanCode = (code ?? string.Empty).Trim().ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(upperCallsign) || cleanCode.Length < 3)
            {
                return false;
            }

            string callsignPrefix = upperCallsign.Split('_').FirstOrDefault() ?? string.Empty;
            if (callsignPrefix.Length < 3)
            {
                return false;
            }

            // Examples:
            // DOH_R1_APP + DCL [DOHA] -> DOH matches DOHA
            // EBBR_APP + DCL [EBBR]   -> EBBR matches EBBR
            return cleanCode.StartsWith(callsignPrefix, StringComparison.OrdinalIgnoreCase) ||
                   callsignPrefix.StartsWith(cleanCode, StringComparison.OrdinalIgnoreCase) ||
                   cleanCode.StartsWith(callsignPrefix.Substring(0, 3), StringComparison.OrdinalIgnoreCase);
        }

        private Controller FindPossiblePdcRegionalAppController(string station, out string code, out string matchReason)
        {
            code = string.Empty;
            matchReason = string.Empty;

            if (vatsimData?.controllers == null || string.IsNullOrWhiteSpace(station))
            {
                return null;
            }

            if (!IsPilotLikelyOnGroundAtDepartureStation(station))
            {
                matchReason = "not on ground at departure airport";
                return null;
            }

            foreach (Controller controller in vatsimData.controllers
                .Where(ctrl => IsAppLikeControllerCallsign(ctrl?.callsign))
                .OrderBy(ctrl => ctrl?.callsign ?? string.Empty))
            {
                string callsign = (controller?.callsign ?? string.Empty).Trim().ToUpperInvariant();
                string info = GetControllerInfoText(controller);

                if (!IsPdcDclInfoText(info))
                {
                    continue;
                }

                string discoveredCode = ExtractPdcDclLogonCode(info, station);
                if (string.IsNullOrWhiteSpace(discoveredCode) || !IsHoppieLogonOnline(discoveredCode))
                {
                    Logger.Debug("PDC/DCL regional APP skip " + callsign + ": no usable online Hoppie logon in DCL info.");
                    continue;
                }

                if (!ControllerPrefixMatchesDclLogon(callsign, discoveredCode))
                {
                    Logger.Debug("PDC/DCL regional APP skip " + callsign + ": DCL code " + discoveredCode + " does not match controller prefix.");
                    continue;
                }

                code = discoveredCode;
                matchReason = "REGIONAL APP DCL MATCH";
                Logger.Debug("PDC/DCL regional APP candidate " + callsign + " -> " + code + " for departure " + station);
                return controller;
            }

            return null;
        }

        private IEnumerable<Controller> GetLocalPdcControllers(string station)
        {
            if (vatsimData?.controllers == null || string.IsNullOrWhiteSpace(station))
            {
                return Enumerable.Empty<Controller>();
            }

            string cleanStation = station.Trim().ToUpperInvariant();

            return vatsimData.controllers
                .Where(controller => IsLocalPdcControllerCallsign(controller?.callsign, cleanStation))
                .OrderBy(controller => GetLocalPdcControllerSortScore(controller?.callsign, cleanStation))
                .ThenBy(controller => controller?.callsign ?? string.Empty);
        }

        private static bool IsLocalPdcControllerCallsign(string callsign, string station)
        {
            string upper = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string cleanStation = (station ?? string.Empty).Trim().ToUpperInvariant();

            if (cleanStation.Length != 4 || string.IsNullOrWhiteSpace(upper))
            {
                return false;
            }

            return Regex.IsMatch(
                upper,
                "^" + Regex.Escape(cleanStation) + @"(?:_[A-Z0-9]+)*_(?:DEL|GND|TWR|APP)$");
        }

        private static int GetLocalPdcControllerSortScore(string callsign, string station)
        {
            string upper = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string cleanStation = (station ?? string.Empty).Trim().ToUpperInvariant();

            if (upper == cleanStation + "_DEL") return 0;
            if (Regex.IsMatch(upper, "^" + Regex.Escape(cleanStation) + @"_.+_DEL$")) return 1;
            if (upper == cleanStation + "_GND") return 2;
            if (Regex.IsMatch(upper, "^" + Regex.Escape(cleanStation) + @"_.+_GND$")) return 3;
            if (upper == cleanStation + "_TWR") return 4;
            if (Regex.IsMatch(upper, "^" + Regex.Escape(cleanStation) + @"_.+_TWR$")) return 5;
            if (upper == cleanStation + "_APP") return 6;
            if (Regex.IsMatch(upper, "^" + Regex.Escape(cleanStation) + @"_.+_APP$")) return 7;
            return 9;
        }

        private Controller FindPossiblePdcCenterController(string station, out string code, out string matchReason)
        {
            code = string.Empty;
            matchReason = string.Empty;

            if (vatsimData?.controllers == null || string.IsNullOrWhiteSpace(station))
            {
                return null;
            }

            if (!AreFirBoundariesReady())
            {
                _ = EnsureFirBoundariesLoadedAsync(false);
                matchReason = "FIR boundaries loading";
                return null;
            }

            if (!TryGetSimbriefAirportPosition(station, out double stationLat, out double stationLon))
            {
                matchReason = "departure airport position unavailable";
                Logger.Debug("PDC/DCL CTR/FSS fallback skipped for " + station + ": no airport coordinates for FIR check.");
                return null;
            }

            List<FirBoundaryFeature> stationFirs = GetFirBoundaryMatchesForPosition(stationLat, stationLon);
            if (stationFirs.Count == 0)
            {
                matchReason = "no FIR/nearby match for departure airport " + station;
                Logger.Debug("PDC/DCL CTR/FSS fallback skipped for " + station + ": no FIR match at departure airport.");
                return null;
            }

            foreach (Controller controller in vatsimData.controllers
                .Where(IsCenterLikeController)
                .OrderBy(controller => controller.callsign ?? string.Empty))
            {
                string callsign = (controller.callsign ?? string.Empty).Trim().ToUpperInvariant();
                string info = GetControllerInfoText(controller);

                if (!IsPdcDclInfoText(info))
                {
                    continue;
                }

                string discoveredCode = ExtractPdcDclLogonCode(info, station);
                if (string.IsNullOrWhiteSpace(discoveredCode) || !IsHoppieLogonOnline(discoveredCode))
                {
                    Logger.Debug("PDC/DCL CTR/FSS fallback skip " + callsign + ": no usable online Hoppie logon in controller info.");
                    continue;
                }

                foreach (FirBoundaryFeature fir in stationFirs)
                {
                    if (!ControllerMatchesFirStrict(callsign, info, fir))
                    {
                        continue;
                    }

                    code = discoveredCode;
                    string firId = GetFirDisplayName(fir);
                    matchReason = fir.IsNearbyCandidate
                        ? "CTR/FSS DEP FIR NEARBY"
                        : "CTR/FSS DEP FIR MATCH";

                    Logger.Debug("PDC/DCL CTR/FSS fallback candidate " + callsign + " -> " + code + " (" + matchReason + " " + firId + ")");
                    return controller;
                }
            }

            return null;
        }

        private bool IsCpdlcHelperSuppressedByConnection()
        {
            // Only real CPDLC connection/logon/handover states suppress the helper.
            // Being tuned to a normal voice ATC frequency without CPDLC must NOT suppress
            // nearby/upcoming CPDLC suggestions.
            return !string.IsNullOrWhiteSpace(_currentATCUnit) ||
                   !string.IsNullOrWhiteSpace(pendingLogon) ||
                   !string.IsNullOrWhiteSpace(nextAtcUnitText) ||
                   !string.IsNullOrWhiteSpace(cpdlcHandoverTargetCode);
        }

        private bool IsCpdlcHelperAllowedToSearch()
        {
            return cpdlcHelperEnabled &&
                   Connected &&
                   IsHoppieCallsignReadyForInteractiveMenus() &&
                   !IsCpdlcHelperSuppressedByConnection();
        }

        private void SetCpdlcHelperStandbyText(string hoverText)
        {
            cpdlcDiscoveryText = cpdlcHelperEnabled ? "standby" : "disabled";
            cpdlcDiscoveryLogonCode = string.Empty;
            cpdlcDiscoveryController = string.Empty;
            cpdlcDiscoveryCandidates.Clear();
            cpdlcDiscoveryHoverText = string.IsNullOrWhiteSpace(hoverText)
                ? (cpdlcHelperEnabled ? "CPDLC helper standby" : "CPDLC helper disabled")
                : hoverText;
        }

        private void UpdateCpdlcDiscoveryFromVatsim()
        {
            if (!cpdlcHelperEnabled)
            {
                SetCpdlcHelperStandbyText("CPDLC helper disabled\nClick radar icon to enable.");
                return;
            }

            if (!string.IsNullOrWhiteSpace(pendingLogon) ||
                !string.IsNullOrWhiteSpace(nextAtcUnitText) ||
                !string.IsNullOrWhiteSpace(cpdlcHandoverTargetCode))
            {
                string target = !string.IsNullOrWhiteSpace(nextAtcUnitText)
                    ? nextAtcUnitText
                    : (!string.IsNullOrWhiteSpace(pendingLogon) ? pendingLogon : cpdlcHandoverTargetCode);

                SetCpdlcHelperStandbyText("CPDLC handover active\nNext ATS Unit: " + target + "\nHelper paused until handover is complete.");
                return;
            }

            if (!string.IsNullOrWhiteSpace(_currentATCUnit))
            {
                cpdlcDiscoveryText = "connected";
                cpdlcDiscoveryLogonCode = _currentATCUnit;
                cpdlcDiscoveryController = _currentATCUnit;

                if (IsCpdlcHandoverFrequencyPending())
                {
                    cpdlcDiscoveryHoverText =
                        "CPDLC connected\nCurrent ATS Unit: " + _currentATCUnit +
                        "\nFrequency handover pending\nTune/select the new ATC frequency for verified CPDLC.";
                }
                else
                {
                    if (!string.IsNullOrWhiteSpace(cpdlcHandoverTargetCode) &&
                        IsCpdlcUnitVerifiedOnActiveFrequency(_currentATCUnit))
                    {
                        cpdlcHandoverTargetCode = string.Empty;
                        cpdlcHandoverStartedUtc = DateTime.MinValue;
                        cpdlcHandoverBlinkTimer.Stop();
                    }

                    cpdlcDiscoveryHoverText = "CPDLC connected\nCurrent ATS Unit: " + _currentATCUnit;
                }

                return;
            }

            if (!IsCpdlcHelperAllowedToSearch())
            {
                SetCpdlcHelperStandbyText("CPDLC helper standby");
                return;
            }

            CpdlcDiscoveryResult result = DiscoverPossibleAirborneCpdlc();

            if (result.Possible)
            {
                cpdlcDiscoveryText = "possible";
                cpdlcDiscoveryLogonCode = result.Code ?? string.Empty;
                cpdlcDiscoveryController = result.Controller ?? string.Empty;
                cpdlcDiscoveryHoverText = result.IsTunedFrequencyMatch
                    ? "CPDLC best match\nTuned frequency: " + result.FrequencyText + "\nController: " + result.Controller + "\nLogon: " + result.Code + "\nHoppie station online"
                    : "Possible CPDLC available\n" + currentFirDebugText + "\nController: " + result.Controller + "\nLogon: " + result.Code + "\n" + result.MatchReason + "\nHoppie station online\nPlease check with controller";

                MaybeWriteCpdlcStationDetectedMessage(result);
                return;
            }

            cpdlcDiscoveryText = "standby";
            cpdlcDiscoveryLogonCode = string.Empty;
            cpdlcDiscoveryController = string.Empty;
            cpdlcDiscoveryCandidates.Clear();
            cpdlcDiscoveryHoverText = string.IsNullOrWhiteSpace(result.Reason)
                ? "CPDLC standby"
                : result.Reason;
        }

        private void MaybeWriteCpdlcStationDetectedMessage(CpdlcDiscoveryResult result)
        {
            if (result == null ||
                !result.Possible ||
                !Connected ||
                !cpdlcHelperEnabled ||
                IsCpdlcHelperSuppressedByConnection() ||
                !IsAirborneNowForPhase())
            {
                return;
            }

            List<long> currentPilotFreqs = IsVatsimTransceiverDataStale()
                ? new List<long>()
                : GetPilotTunedFrequencies();

            List<CpdlcDiscoveryResult> candidates = cpdlcDiscoveryCandidates
                .Where(candidate => candidate != null &&
                                    candidate.Possible &&
                                    !string.IsNullOrWhiteSpace(candidate.Code) &&
                                    !string.IsNullOrWhiteSpace(candidate.Controller) &&
                                    IsHoppieLogonOnline(candidate.Code))
                .Select(candidate => VerifyCandidateAgainstActiveFrequency(candidate, currentPilotFreqs))
                .GroupBy(candidate => candidate.Code.Trim().ToUpperInvariant() + "|" + (candidate.Controller ?? string.Empty).Trim().ToUpperInvariant())
                .Select(group => group.OrderBy(GetCpdlcCandidateSortScore).First())
                .OrderBy(GetCpdlcCandidateSortScore)
                .ThenBy(candidate => candidate.Controller ?? string.Empty)
                .Take(5)
                .ToList();

            // Only create a SYSTEM notification when the CPDLC station is verified on
            // the active VATSIM frequency. Nearby/FIR candidates stay in the helper popup
            // but should not spam the message list.
            candidates = candidates
                .Where(candidate => candidate.IsTunedFrequencyMatch)
                .Where(candidate => !IsCpdlcVerifiedSuggestionCooldownActive(candidate.Code, candidate.Controller, out _))
                .ToList();

            if (candidates.Count == 0)
            {
                return;
            }

            CpdlcDiscoveryResult primary = candidates.First();
            string code = (primary.Code ?? string.Empty).Trim().ToUpperInvariant();
            string controller = (primary.Controller ?? string.Empty).Trim().ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(code) ||
                string.IsNullOrWhiteSpace(controller) ||
                !IsHoppieLogonOnline(code))
            {
                return;
            }

            Controller primaryController = vatsimData?.controllers?.FirstOrDefault(ctrl =>
                string.Equals((ctrl.callsign ?? string.Empty).Trim().ToUpperInvariant(), controller, StringComparison.OrdinalIgnoreCase));

            if (primaryController == null)
            {
                return;
            }

            bool primaryHasCpdlcKeyword = ContainsCpdlcDiscoveryKeyword(GetControllerInfoText(primaryController));
            bool primaryIsCenterLike = IsCenterLikeControllerCallsign(primaryController.callsign);
            bool primaryUsesOnlineCallsignCode =
                primaryIsCenterLike &&
                string.Equals(GetOnlineHoppieCodeFromControllerCallsign(primaryController.callsign), code, StringComparison.OrdinalIgnoreCase);

            if (!primaryHasCpdlcKeyword && !primaryUsesOnlineCallsignCode)
            {
                Logger.Debug("CPDLC station notification suppressed for " + controller + " / " + code + ": no explicit CPDLC/Hoppie/logon keyword and no online center callsign Hoppie station.");
                return;
            }

            string key = string.Join(";", candidates.Select(candidate =>
                (candidate.Code ?? string.Empty).Trim().ToUpperInvariant() + "|" +
                (candidate.Controller ?? string.Empty).Trim().ToUpperInvariant()));

            DateTime now = DateTime.UtcNow;

            if (string.Equals(lastCpdlcStationDetectedNotificationKey, key, StringComparison.OrdinalIgnoreCase) &&
                now - lastCpdlcStationDetectedNotificationUtc < cpdlcStationDetectedNotificationCooldown)
            {
                return;
            }

            lastCpdlcStationDetectedNotificationKey = key;
            lastCpdlcStationDetectedNotificationUtc = now;

            string match = string.IsNullOrWhiteSpace(primary.MatchReason)
                ? "CPDLC CANDIDATE"
                : primary.MatchReason.Trim().ToUpperInvariant();

            string frequencyLine = !string.IsNullOrWhiteSpace(primary.FrequencyText)
                ? "\nFREQ: " + primary.FrequencyText.Trim()
                : string.Empty;

            string otherCandidates = string.Empty;
            if (candidates.Count > 1)
            {
                otherCandidates =
                    "\n\nOTHER CANDIDATES:\n" +
                    string.Join("\n", candidates.Skip(1).Select(candidate =>
                    {
                        string candidateController = (candidate.Controller ?? string.Empty).Trim().ToUpperInvariant();
                        string candidateCode = (candidate.Code ?? string.Empty).Trim().ToUpperInvariant();
                        string candidateReason = string.IsNullOrWhiteSpace(candidate.MatchReason)
                            ? "CPDLC CANDIDATE"
                            : candidate.MatchReason.Trim().ToUpperInvariant();

                        string candidateFrequency = string.IsNullOrWhiteSpace(candidate.FrequencyText)
                            ? string.Empty
                            : "  FREQ: " + candidate.FrequencyText.Trim();

                        return candidateController + candidateFrequency + "  LOGON: " + candidateCode + "  (" + candidateReason + ")";
                    }));
            }

            string notificationTitle = primary.IsTunedFrequencyMatch
                ? "VERIFIED ACTIVE FREQUENCY CPDLC LOGON"
                : "POSSIBLE CPDLC STATION DETECTED";

            string bestMatchTitle = primary.IsTunedFrequencyMatch
                ? "ATC ON YOUR ACTIVE FREQUENCY HAS CPDLC:"
                : "BEST MATCH:";

            string text =
                notificationTitle + "\n\n" +
                bestMatchTitle + "\n" +
                controller + frequencyLine + "\n" +
                "LOGON: " + code + "\n" +
                "MATCH: " + match +
                otherCandidates + "\n\n" +
                "OPEN MESSAGE AND SELECT LOGON TO " + code;

            Logger.Debug("CPDLC station notification created for " + controller + " / " + code + " (" + candidates.Count + " candidate(s)).");

            // CPDLC WATCH messages are SYSTEM messages, therefore WriteMessage() deliberately
            // does not play the normal inbound CPDLC/TELEX sound for them.
            // A detected CPDLC logon candidate should still alert like a normal CPDLC message,
            // using the currently selected Airbus/Boeing notification sound.
            if (PlaySound)
            {
                PlayInboundMessageSound();
            }

            WriteMessage(text, "SYSTEM", "CPDLC WATCH");
        }

        private static bool IsCpdlcStationDetectedText(string contents)
        {
            string text = (contents ?? string.Empty).Trim();

            return text.StartsWith("POSSIBLE CPDLC STATION DETECTED", StringComparison.OrdinalIgnoreCase) ||
                   text.StartsWith("ACTIVE FREQUENCY CPDLC LOGON DETECTED", StringComparison.OrdinalIgnoreCase) ||
                   text.StartsWith("VERIFIED ACTIVE FREQUENCY CPDLC LOGON", StringComparison.OrdinalIgnoreCase);
        }

        private static string ExtractCpdlcStationDetectedLogonCode(string contents)
        {
            Match match = Regex.Match(contents ?? string.Empty, @"\bLOGON:\s*([A-Z0-9]{4})\b", RegexOptions.IgnoreCase);
            return match.Success
                ? match.Groups[1].Value.Trim().ToUpperInvariant()
                : string.Empty;
        }

        private static string ExtractCpdlcStationDetectedController(string contents)
        {
            string normalized = (contents ?? string.Empty)
                .Replace("\r\n", "\n")
                .Replace("\r", "\n");

            foreach (string line in normalized.Split('\n'))
            {
                string clean = line.Trim().ToUpperInvariant();

                if (string.IsNullOrWhiteSpace(clean) ||
                    clean.StartsWith("POSSIBLE CPDLC", StringComparison.Ordinal) ||
                    clean.StartsWith("LOGON:", StringComparison.Ordinal) ||
                    clean.StartsWith("MATCH:", StringComparison.Ordinal) ||
                    clean.StartsWith("FREQ:", StringComparison.Ordinal) ||
                    clean.StartsWith("OPEN MESSAGE", StringComparison.Ordinal))
                {
                    continue;
                }

                string controller = clean.Split(' ', StringSplitOptions.RemoveEmptyEntries).FirstOrDefault() ?? string.Empty;
                if (controller.Contains("_"))
                {
                    return controller;
                }
            }

            return string.Empty;
        }

        private System.Windows.Forms.Label CreateCpdlcStationDetectedLogonLabel(CPDLCMessage message)
        {
            string code = ExtractCpdlcStationDetectedLogonCode(message?.message ?? string.Empty);
            string controller = ExtractCpdlcStationDetectedController(message?.message ?? string.Empty);

            if (string.IsNullOrWhiteSpace(code))
            {
                return null;
            }

            AccessibleLabel label = CreateSpecialLabel("> LOGON TO " + code, false);
            smartStatusToolTip.SetToolTip(label,
                "Send CPDLC LOGON request to " + code +
                (string.IsNullOrWhiteSpace(controller) ? string.Empty : "\nController: " + controller));

            label.Click += async (_, __) =>
            {
                ClearPreview();
                await QuickCpdlcLogonAsync(code);
            };

            label.KeyDown += async (_, keyEvent) =>
            {
                if (keyEvent.KeyCode == Keys.Enter || keyEvent.KeyCode == Keys.Space)
                {
                    keyEvent.Handled = true;
                    ClearPreview();
                    await QuickCpdlcLogonAsync(code);
                }
            };

            return label;
        }

        private void UpdateCpdlcDiscoveryLabel()
        {
            if (cpdlcDiscoveryLabel == null)
            {
                return;
            }

            cpdlcDiscoveryLabel.Text = "📡";
            cpdlcDiscoveryLabel.ForeColor = CpdlcDiscoveryColor();
            smartStatusToolTip.SetToolTip(cpdlcDiscoveryLabel,
                cpdlcHelperEnabled ? cpdlcDiscoveryHoverText : "CPDLC helper disabled\nClick radar icon to enable.");
            cpdlcDiscoveryLabel.Invalidate();
        }

        private Color CpdlcDiscoveryColor()
        {
            if (!cpdlcHelperEnabled)
            {
                return NeutralStatusBadgeColor();
            }

            if (IsCpdlcHandoverFrequencyPending())
            {
                return (DateTime.UtcNow.Millisecond / 450) % 2 == 0
                    ? DcduTheme.Green
                    : DcduTheme.Amber;
            }

            if (!string.IsNullOrWhiteSpace(_currentATCUnit))
            {
                return DcduTheme.Green;
            }

            if (HasVerifiedActiveFrequencyCpdlcCandidate())
            {
                return DcduTheme.Green;
            }

            if (string.Equals(cpdlcDiscoveryText, "possible", StringComparison.OrdinalIgnoreCase))
            {
                return DcduTheme.Amber;
            }

            return NeutralStatusBadgeColor();
        }

        private bool HasVerifiedActiveFrequencyCpdlcCandidate()
        {
            if (!Connected || !IsAirborneNowForPhase())
            {
                return false;
            }

            if (cpdlcDiscoveryCandidates.Any(candidate =>
                    candidate != null &&
                    candidate.Possible &&
                    candidate.IsTunedFrequencyMatch &&
                    !string.IsNullOrWhiteSpace(candidate.Code) &&
                    IsHoppieLogonOnline(candidate.Code)))
            {
                return true;
            }

            // Re-check visible FIR/nearby candidates against the current VATSIM transceiver data.
            // This keeps the radar icon green even if a candidate was first discovered as nearby
            // and only later became verifiable as the active frequency.
            if (IsVatsimTransceiverDataStale())
            {
                return false;
            }

            List<long> currentPilotFreqs = GetPilotTunedFrequencies();
            if (currentPilotFreqs.Count == 0 || vatsimData?.controllers == null)
            {
                return false;
            }

            foreach (CpdlcDiscoveryResult candidate in cpdlcDiscoveryCandidates)
            {
                if (candidate == null ||
                    !candidate.Possible ||
                    string.IsNullOrWhiteSpace(candidate.Code) ||
                    string.IsNullOrWhiteSpace(candidate.Controller) ||
                    !IsHoppieLogonOnline(candidate.Code))
                {
                    continue;
                }

                string candidateController = candidate.Controller.Trim().ToUpperInvariant();
                Controller controller = vatsimData.controllers.FirstOrDefault(ctrl =>
                    string.Equals((ctrl.callsign ?? string.Empty).Trim().ToUpperInvariant(), candidateController, StringComparison.OrdinalIgnoreCase));

                if (TryGetTunedFrequencyMatch(controller, currentPilotFreqs, out _))
                {
                    return true;
                }
            }

            return false;
        }

        private CpdlcDiscoveryResult DiscoverPossibleAirborneCpdlc()
        {
            cpdlcDiscoveryCandidates.Clear();

            if (!Connected || !IsAirborneNowForPhase() || vatsimData?.controllers == null || !hoppieOnlineStationsLoaded)
            {
                return new CpdlcDiscoveryResult
                {
                    Reason = "CPDLC standby"
                };
            }

            if (IsVatsimTransceiverDataStale())
            {
                _ = RefreshVatsimTransceiversAsync(true);
            }

            string departure = userVATSIMData?.flight_plan?.departure?.Trim().ToUpperInvariant() ?? string.Empty;
            string arrival = userVATSIMData?.flight_plan?.arrival?.Trim().ToUpperInvariant() ?? string.Empty;
            string activeStation = ShouldUseArrivalAtisForHover() ? arrival : departure;

            List<FirBoundaryFeature> currentFirs = new();
            currentFirDebugText = "VATGlasses sectors only";

            Logger.Debug("CPDLC discovery using VATGlasses only" +
                " position=" + (userVATSIMData?.latitude.ToString(System.Globalization.CultureInfo.InvariantCulture) ?? "?") +
                "," + (userVATSIMData?.longitude.ToString(System.Globalization.CultureInfo.InvariantCulture) ?? "?") +
                " nearbyRadiusNm=" + FirNearbyRadiusNm.ToString(System.Globalization.CultureInfo.InvariantCulture));

            AddTunedFrequencyCpdlcCandidates();
            List<long> pilotTunedFrequencies = IsVatsimTransceiverDataStale()
                ? new List<long>()
                : GetPilotTunedFrequencies();

            foreach (Controller controller in vatsimData.controllers
                .Where(IsCpdlcDiscoveryController)
                .OrderBy(controller => controller.callsign ?? string.Empty))
            {
                string callsign = (controller.callsign ?? string.Empty).Trim().ToUpperInvariant();
                string info = GetControllerInfoText(controller);
                bool hasCpdlcKeyword = ContainsCpdlcDiscoveryKeyword(info);
                bool isCenterLike = IsCenterLikeControllerCallsign(callsign);
                bool tunedFrequencyMatch = TryGetTunedFrequencyMatch(controller, pilotTunedFrequencies, out string tunedFrequencyText);

                string code = string.Empty;

                if (hasCpdlcKeyword)
                {
                    code = ExtractCpdlcLogonCode(info, string.Empty);
                    if (string.IsNullOrWhiteSpace(code) || !IsHoppieLogonOnline(code))
                    {
                        code = ExtractAnyOnlineHoppieLogonCodeFromText(info);
                    }
                }

                if ((string.IsNullOrWhiteSpace(code) || !IsHoppieLogonOnline(code)) &&
                    tunedFrequencyMatch &&
                    isCenterLike)
                {
                    // Callsign-prefix Hoppie fallback is safe only when the pilot is
                    // actually tuned to this controller. It must not create "nearby"
                    // candidates by itself.
                    code = GetOnlineHoppieCodeFromControllerCallsign(callsign);
                }

                if (string.IsNullOrWhiteSpace(code))
                {
                    Logger.Debug("CPDLC discovery skip " + callsign + ": no usable explicit logon code" + (tunedFrequencyMatch ? " or tuned callsign-derived Hoppie station." : "."));
                    continue;
                }

                if (!IsHoppieLogonOnline(code))
                {
                    Logger.Debug("CPDLC discovery skip " + callsign + ": logon " + code + " not online on Hoppie.");
                    continue;
                }

                if (IsCpdlcVerifiedSuggestionCooldownActive(code, callsign, out string cooldownRemaining))
                {
                    Logger.Debug("CPDLC discovery skip " + callsign + " / " + code + ": verified suggestion cooldown active for " + cooldownRemaining + ".");
                    continue;
                }

                string coverageAltitudeText = string.Empty;
                IsControllerCoverageCompatibleWithLiveAltitude(controller, out coverageAltitudeText);

                string matchReason = GetCpdlcControllerMatchReason(controller, code, activeStation, departure, arrival, currentFirs);

                if (string.IsNullOrWhiteSpace(matchReason) && !tunedFrequencyMatch)
                {
                    string onlineV2Text = vatsimAtcOnlineCallsigns.Count == 0
                        ? "v2 not loaded"
                        : (vatsimAtcOnlineCallsigns.Contains(callsign) ? "seen in v2 online ATC" : "not seen in v2 online ATC");
                    Logger.Debug("CPDLC discovery skip " + callsign + " / " + code + ": no active frequency or VATGlasses sector match (" + onlineV2Text + ").");
                    continue;
                }

                if (tunedFrequencyMatch)
                {
                    matchReason = "TUNED FREQ MATCH" +
                        (string.IsNullOrWhiteSpace(matchReason) ? string.Empty : " / " + matchReason);
                }

                if (!string.IsNullOrWhiteSpace(coverageAltitudeText))
                {
                    matchReason = string.IsNullOrWhiteSpace(matchReason)
                        ? coverageAltitudeText
                        : matchReason + " / " + coverageAltitudeText;
                }

                cpdlcDiscoveryCandidates.Add(new CpdlcDiscoveryResult
                {
                    Possible = true,
                    Controller = callsign,
                    Code = code,
                    MatchReason = matchReason,
                    FrequencyText = string.IsNullOrWhiteSpace(tunedFrequencyText) ? GetControllerDisplayFrequencyText(controller) : tunedFrequencyText,
                    IsTunedFrequencyMatch = tunedFrequencyMatch
                });

                Logger.Debug("CPDLC discovery candidate " + callsign + " -> " + code + " (" + matchReason + ")");
            }

            if (cpdlcDiscoveryCandidates.Count > 0)
            {
                return cpdlcDiscoveryCandidates
                    .OrderBy(GetCpdlcCandidateSortScore)
                    .ThenBy(candidate => candidate.Controller ?? string.Empty)
                    .First();
            }

            string vatglassesDebug;
            lock (vatglassesDataLock)
            {
                vatglassesDebug = lastVatglassesDebugText;
            }

            return new CpdlcDiscoveryResult
            {
                Reason = "CPDLC standby\n" + currentFirDebugText +
                    (string.IsNullOrWhiteSpace(lastVatsimAtcOnlineDebugText) ? string.Empty : "\n" + lastVatsimAtcOnlineDebugText) +
                    (string.IsNullOrWhiteSpace(vatglassesDebug) ? string.Empty : "\n" + vatglassesDebug) +
                    "\nNo matching online APP/CTR/FSS with usable Hoppie logon found"
            };
        }

        private bool IsVatsimTransceiverDataStale()
        {
            return vatsimTransceiversLoadedUtc == DateTime.MinValue ||
                   DateTime.UtcNow - vatsimTransceiversLoadedUtc > vatsimTransceiverValidLifetime;
        }

        private async Task RefreshVatsimTransceiversAsync(bool force)
        {
            if (vatsimTransceiverRefreshInProgress)
            {
                return;
            }

            if (!force &&
                DateTime.UtcNow - lastVatsimTransceiverRefreshAttemptUtc < vatsimTransceiverRefreshInterval &&
                !IsVatsimTransceiverDataStale())
            {
                return;
            }

            lastVatsimTransceiverRefreshAttemptUtc = DateTime.UtcNow;
            vatsimTransceiverRefreshInProgress = true;

            try
            {
                string data = await webclient.GetStringAsync(VatsimTransceiversDataUrl);
                JToken root = JToken.Parse(data);
                IEnumerable<JToken> clients;

                if (root is JArray array)
                {
                    clients = array;
                }
                else
                {
                    clients = root["clients"] as JArray ??
                              root["data"] as JArray ??
                              root["transceivers"] as JArray ??
                              Enumerable.Empty<JToken>();
                }

                Dictionary<string, List<long>> parsed = new(StringComparer.OrdinalIgnoreCase);

                foreach (JToken client in clients)
                {
                    string clientCallsign = (client["callsign"]?.ToString() ?? string.Empty).Trim().ToUpperInvariant();
                    if (string.IsNullOrWhiteSpace(clientCallsign))
                    {
                        continue;
                    }

                    List<long> freqs = new();

                    JArray transceivers = client["transceivers"] as JArray ?? new JArray();
                    foreach (JToken transceiver in transceivers)
                    {
                        if (TryParseLongFrequency(transceiver["frequency"], out long hz))
                        {
                            freqs.Add(hz);
                        }
                    }

                    if (freqs.Count > 0)
                    {
                        parsed[clientCallsign] = freqs.Distinct().ToList();
                    }
                }

                vatsimTransceiverFrequencies.Clear();
                foreach (KeyValuePair<string, List<long>> item in parsed)
                {
                    vatsimTransceiverFrequencies[item.Key] = item.Value;
                }

                vatsimTransceiversLoadedUtc = DateTime.UtcNow;
                Logger.Debug("Loaded VATSIM transceivers: " + vatsimTransceiverFrequencies.Count + " clients.");
            }
            catch (Exception ex)
            {
                Logger.Debug("VATSIM transceiver refresh failed: " + ex.Message);
            }
            finally
            {
                vatsimTransceiverRefreshInProgress = false;
            }
        }

        private static bool TryParseLongFrequency(JToken token, out long hz)
        {
            hz = 0;

            if (token == null)
            {
                return false;
            }

            if (token.Type == JTokenType.Integer || token.Type == JTokenType.Float)
            {
                double value = token.Value<double>();
                if (value > 1000000)
                {
                    hz = Convert.ToInt64(Math.Round(value));
                    return hz > 0;
                }

                if (value > 100)
                {
                    hz = Convert.ToInt64(Math.Round(value * 1000000.0));
                    return hz > 0;
                }
            }

            return TryParseControllerFrequencyHz(token.ToString(), out hz);
        }

        private static bool TryParseControllerFrequencyHz(string frequency, out long hz)
        {
            hz = 0;
            string clean = (frequency ?? string.Empty).Trim().Replace(",", ".");

            if (string.IsNullOrWhiteSpace(clean))
            {
                return false;
            }

            if (!double.TryParse(clean, System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture, out double mhz))
            {
                return false;
            }

            if (mhz > 1000000)
            {
                hz = Convert.ToInt64(Math.Round(mhz));
            }
            else
            {
                hz = Convert.ToInt64(Math.Round(mhz * 1000000.0));
            }

            return hz > 0;
        }

        private static string FormatFrequencyHz(long hz)
        {
            if (hz <= 0)
            {
                return string.Empty;
            }

            return (hz / 1000000.0).ToString("0.000", System.Globalization.CultureInfo.InvariantCulture);
        }

        private List<long> GetPilotTunedFrequencies()
        {
            string activeCallsign = GetConnectedPilotCallsign();

            if (string.IsNullOrWhiteSpace(activeCallsign))
            {
                return new List<long>();
            }

            if (vatsimTransceiverFrequencies.TryGetValue(activeCallsign.Trim().ToUpperInvariant(), out List<long> freqs))
            {
                return freqs?.Distinct().ToList() ?? new List<long>();
            }

            return new List<long>();
        }

        private List<long> GetControllerTunedFrequencies(Controller controller)
        {
            if (controller == null)
            {
                return new List<long>();
            }

            string callsign = (controller.callsign ?? string.Empty).Trim().ToUpperInvariant();

            if (!string.IsNullOrWhiteSpace(callsign) &&
                vatsimTransceiverFrequencies.TryGetValue(callsign, out List<long> transceiverFreqs) &&
                transceiverFreqs != null &&
                transceiverFreqs.Count > 0)
            {
                return transceiverFreqs.Distinct().ToList();
            }

            if (TryParseControllerFrequencyHz(controller.frequency, out long controllerHz))
            {
                return new List<long> { controllerHz };
            }

            return new List<long>();
        }

        private string GetControllerDisplayFrequencyText(Controller controller)
        {
            List<long> freqs = GetControllerTunedFrequencies(controller);
            if (freqs.Count > 0)
            {
                return FormatFrequencyHz(freqs[0]);
            }

            return string.Empty;
        }

        private bool TryGetTunedFrequencyMatch(Controller controller, List<long> pilotFreqs, out string frequencyText)
        {
            frequencyText = string.Empty;

            if (controller == null || pilotFreqs == null || pilotFreqs.Count == 0)
            {
                return false;
            }

            List<long> controllerFreqs = GetControllerTunedFrequencies(controller);
            if (controllerFreqs.Count == 0)
            {
                return false;
            }

            // Prefer comparing actual VATSIM audio transceiver frequencies in Hz.
            // Fall back to controller.frequency only if no controller transceiver entry exists.
            foreach (long controllerHz in controllerFreqs)
            {
                if (pilotFreqs.Any(freq => Math.Abs(freq - controllerHz) <= 8000))
                {
                    frequencyText = FormatFrequencyHz(controllerHz);
                    return true;
                }
            }

            return false;
        }

        private CpdlcDiscoveryResult VerifyCandidateAgainstActiveFrequency(CpdlcDiscoveryResult candidate, List<long> pilotFreqs)
        {
            if (candidate == null || candidate.IsTunedFrequencyMatch || vatsimData?.controllers == null)
            {
                return candidate;
            }

            string candidateController = (candidate.Controller ?? string.Empty).Trim().ToUpperInvariant();
            if (string.IsNullOrWhiteSpace(candidateController))
            {
                return candidate;
            }

            Controller controller = vatsimData.controllers.FirstOrDefault(ctrl =>
                string.Equals((ctrl.callsign ?? string.Empty).Trim().ToUpperInvariant(), candidateController, StringComparison.OrdinalIgnoreCase));

            if (controller == null || !TryGetTunedFrequencyMatch(controller, pilotFreqs, out string frequencyText))
            {
                return candidate;
            }

            string reason = string.IsNullOrWhiteSpace(candidate.MatchReason)
                ? "TUNED FREQ MATCH"
                : "TUNED FREQ MATCH / " + candidate.MatchReason.Trim();

            return new CpdlcDiscoveryResult
            {
                Possible = candidate.Possible,
                Controller = candidate.Controller,
                Code = candidate.Code,
                MatchReason = reason,
                FrequencyText = frequencyText,
                IsTunedFrequencyMatch = true
            };
        }

        private void AddTunedFrequencyCpdlcCandidates()
        {
            if (vatsimData?.controllers == null)
            {
                return;
            }

            if (IsVatsimTransceiverDataStale())
            {
                _ = RefreshVatsimTransceiversAsync(true);

                if (vatsimTransceiversLoadedUtc == DateTime.MinValue)
                {
                    return;
                }
            }

            List<long> pilotFreqs = GetPilotTunedFrequencies();
            if (pilotFreqs.Count == 0)
            {
                return;
            }

            string departure = userVATSIMData?.flight_plan?.departure?.Trim().ToUpperInvariant() ?? string.Empty;
            string arrival = userVATSIMData?.flight_plan?.arrival?.Trim().ToUpperInvariant() ?? string.Empty;

            foreach (Controller controller in vatsimData.controllers
                .Where(IsCpdlcDiscoveryController)
                .OrderBy(controller => controller.callsign ?? string.Empty))
            {
                string callsign = (controller.callsign ?? string.Empty).Trim().ToUpperInvariant();

                if (IsAppLikeControllerCallsign(callsign) &&
                    !IsAppControllerForFlightPlan(callsign, departure, arrival))
                {
                    Logger.Debug("CPDLC tuned-frequency APP candidate " + callsign + " ignored: APP is not DEP/ARR airport.");
                    continue;
                }

                if (!TryGetTunedFrequencyMatch(controller, pilotFreqs, out string tunedFrequencyText))
                {
                    continue;
                }

                string info = GetControllerInfoText(controller);
                bool hasCpdlcKeyword = ContainsCpdlcDiscoveryKeyword(info);
                bool isCenterLike = IsCenterLikeControllerCallsign(callsign);

                string code = string.Empty;

                if (hasCpdlcKeyword)
                {
                    code = ExtractCpdlcLogonCode(info, string.Empty);
                    if (string.IsNullOrWhiteSpace(code) || !IsHoppieLogonOnline(code))
                    {
                        // Active frequency is strong proof that this ATC is relevant.
                        // Some sectors publish only a raw online Hoppie code such as MWS2,
                        // without a clean CPDLC/LOGON label.
                        code = ExtractAnyOnlineHoppieLogonCodeFromText(info);
                    }
                }

                if ((string.IsNullOrWhiteSpace(code) || !IsHoppieLogonOnline(code)) && isCenterLike)
                {
                    code = GetOnlineHoppieCodeFromControllerCallsign(callsign);
                }

                if (string.IsNullOrWhiteSpace(code) && !hasCpdlcKeyword)
                {
                    Logger.Debug("CPDLC tuned-frequency match " + callsign + " ignored: no explicit CPDLC/Hoppie/logon keyword and no online callsign-derived Hoppie station.");
                    continue;
                }

                if (string.IsNullOrWhiteSpace(code) || !IsHoppieLogonOnline(code))
                {
                    Logger.Debug("CPDLC tuned-frequency match " + callsign + " ignored: no online Hoppie logon code.");
                    continue;
                }

                string tunedMatchReason = "TUNED FREQ MATCH";

                cpdlcDiscoveryCandidates.Add(new CpdlcDiscoveryResult
                {
                    Possible = true,
                    Controller = callsign,
                    Code = code,
                    MatchReason = tunedMatchReason,
                    FrequencyText = tunedFrequencyText,
                    IsTunedFrequencyMatch = true
                });

                Logger.Debug("CPDLC tuned-frequency candidate " + callsign + " " + tunedFrequencyText + " -> " + code);
            }
        }

        private bool IsControllerCoverageCompatibleWithLiveAltitude(Controller controller, out string coverageAltitudeText)
        {
            // Deliberately disabled for helper discovery.
            //
            // Controller ATIS often contains altitude text for separate services
            // (FIS/Information/ATIS, sector notes, briefing text, etc.). Using that
            // text as a hard filter is too unreliable and can hide valid nearby/active
            // CPDLC centers such as LHCC_W_CTR with "(CPDLC LHCW)".
            //
            // Helper visibility is now based on active frequency / current-nearby FIR /
            // route relevance / online Hoppie station, never on altitude restrictions.
            coverageAltitudeText = string.Empty;
            return true;
        }

        private bool TryGetLivePilotAltitudeFeet(out int altitudeFeet, out string source)
        {
            altitudeFeet = 0;
            source = string.Empty;

            try
            {
                if (userVATSIMData != null && userVATSIMData.altitude > -1500 && userVATSIMData.altitude < 100000)
                {
                    altitudeFeet = userVATSIMData.altitude;
                    source = "VATSIM live";
                    return true;
                }
            }
            catch
            {
                // Continue to simulator fallback.
            }

            try
            {
                if (UseFSUIPC && fsConnectionOpen && fsuipc != null)
                {
                    double simulatorAltitudeFeet = fsuipc.altitude.Feet;
                    if (!double.IsNaN(simulatorAltitudeFeet) && !double.IsInfinity(simulatorAltitudeFeet) &&
                        simulatorAltitudeFeet > -1500 && simulatorAltitudeFeet < 100000)
                    {
                        altitudeFeet = (int)Math.Round(simulatorAltitudeFeet);
                        source = "FSUIPC live";
                        return true;
                    }
                }
            }
            catch
            {
                // Deliberately do not fall back to filed altitude. Filed altitude is not current aircraft altitude.
            }

            return false;
        }

        private static bool LooksLikeNonSectorInformationAltitudeText(string upper)
        {
            if (string.IsNullOrWhiteSpace(upper))
            {
                return false;
            }

            // Example LHCC_W_CTR:
            // "(Budapest West Information 125.500 below 9500 feet)"
            // This describes the FIS/Information frequency, not the CTR sector coverage.
            // Do not use it to reject CPDLC on the active LHCC_W_CTR frequency.
            if (Regex.IsMatch(upper, @"\b(?:INFORMATION|FIS|ATIS)\b.{0,80}\b(?:BELOW|UNDER|UP\s+TO|UNTIL|AT\s+OR\s+BELOW)\b.{0,30}\b\d{3,5}\s*(?:FT|FEET)?\b"))
            {
                return true;
            }

            if (Regex.IsMatch(upper, @"\b\d{3}\.\d{3}\b.{0,60}\b(?:BELOW|UNDER|UP\s+TO|UNTIL|AT\s+OR\s+BELOW)\b.{0,30}\b\d{3,5}\s*(?:FT|FEET)?\b"))
            {
                return true;
            }

            return false;
        }

        private static bool TryParseControllerAltitudeCoverage(string text, out int? minAltitudeFeet, out int? maxAltitudeFeet, out string coverageText)
        {
            minAltitudeFeet = null;
            maxAltitudeFeet = null;
            coverageText = string.Empty;

            string upper = Regex.Replace(text ?? string.Empty, @"\s+", " ").Trim().ToUpperInvariant();
            if (string.IsNullOrWhiteSpace(upper))
            {
                return false;
            }

            if (LooksLikeNonSectorInformationAltitudeText(upper))
            {
                return false;
            }

            Match plus = Regex.Match(upper, @"\b(?<alt>FL\s*\d{2,3}|\d{4,5}\s*(?:FT|FEET)?)\s*\+\b");
            if (plus.Success && TryParseAltitudeReferenceFeet(plus.Groups["alt"].Value, out int plusFeet))
            {
                minAltitudeFeet = plusFeet;
                coverageText = "at/above " + FormatAltitudeForCoverage(plusFeet);
                return true;
            }

            Match range = Regex.Match(upper,
                @"\b(?<min>SFC|GND|GROUND|SURFACE|FL\s*\d{2,3}|\d{2,3}|\d{4,5}\s*(?:FT|FEET)?)\s*(?:-|–|—|/|\bTO\b)\s*(?<max>SFC|GND|GROUND|SURFACE|FL\s*\d{2,3}|\d{2,3}|\d{4,5}\s*(?:FT|FEET)?)\b");
            if (range.Success)
            {
                string minToken = range.Groups["min"].Value;
                string maxToken = range.Groups["max"].Value;

                if ((AltitudeTokenLooksExplicit(minToken) || AltitudeTokenLooksExplicit(maxToken)) &&
                    TryParseAltitudeReferenceFeet(minToken, out int minFeet) &&
                    TryParseAltitudeReferenceFeet(maxToken, out int maxFeet))
                {
                    minAltitudeFeet = Math.Min(minFeet, maxFeet);
                    maxAltitudeFeet = Math.Max(minFeet, maxFeet);
                    coverageText = FormatAltitudeForCoverage(minAltitudeFeet.Value) + "-" + FormatAltitudeForCoverage(maxAltitudeFeet.Value);
                    return true;
                }
            }

            Match maxMatch = Regex.Match(upper,
                @"\b(?:ONLY\s+)?(?:BELOW|UNDER|UP\s+TO|UNTIL|AT\s+OR\s+BELOW|MAX(?:IMUM)?)\s+(?<alt>(?:FL\s*)?\d{2,3}|\d{4,5}\s*(?:FT|FEET)?)\b");
            if (!maxMatch.Success)
            {
                maxMatch = Regex.Match(upper,
                    @"\b(?<alt>FL\s*\d{2,3}|\d{4,5}\s*(?:FT|FEET)?|\d{2,3})\s+(?:AND\s+)?(?:BELOW|UNDER)\b");
            }

            if (maxMatch.Success && TryParseAltitudeReferenceFeet(maxMatch.Groups["alt"].Value, out int maxOnlyFeet))
            {
                maxAltitudeFeet = maxOnlyFeet;
                coverageText = "below " + FormatAltitudeForCoverage(maxOnlyFeet);
                return true;
            }

            Match minMatch = Regex.Match(upper,
                @"\b(?:ONLY\s+)?(?:ABOVE|OVER|AT\s+OR\s+ABOVE|MIN(?:IMUM)?|FROM)\s+(?<alt>(?:FL\s*)?\d{2,3}|\d{4,5}\s*(?:FT|FEET)?)\b");
            if (!minMatch.Success)
            {
                minMatch = Regex.Match(upper,
                    @"\b(?<alt>FL\s*\d{2,3}|\d{4,5}\s*(?:FT|FEET)?|\d{2,3})\s+(?:AND\s+)?(?:ABOVE|OVER)\b");
            }

            if (minMatch.Success && TryParseAltitudeReferenceFeet(minMatch.Groups["alt"].Value, out int minOnlyFeet))
            {
                minAltitudeFeet = minOnlyFeet;
                coverageText = "above " + FormatAltitudeForCoverage(minOnlyFeet);
                return true;
            }

            return false;
        }

        private static bool AltitudeTokenLooksExplicit(string token)
        {
            string upper = (token ?? string.Empty).Trim().ToUpperInvariant();
            return upper.Contains("FL") ||
                   upper.Contains("FT") ||
                   upper.Contains("FEET") ||
                   upper.Contains("SFC") ||
                   upper.Contains("GND") ||
                   upper.Contains("GROUND") ||
                   upper.Contains("SURFACE");
        }

        private static bool TryParseAltitudeReferenceFeet(string token, out int altitudeFeet)
        {
            altitudeFeet = 0;
            string value = (token ?? string.Empty).Trim().ToUpperInvariant();
            if (string.IsNullOrWhiteSpace(value))
            {
                return false;
            }

            if (Regex.IsMatch(value, @"\b(?:SFC|GND|GROUND|SURFACE)\b"))
            {
                altitudeFeet = 0;
                return true;
            }

            Match flightLevel = Regex.Match(value, @"\bFL\s*(?<level>\d{2,3})\b");
            if (flightLevel.Success && int.TryParse(flightLevel.Groups["level"].Value, out int fl))
            {
                altitudeFeet = fl * 100;
                return altitudeFeet >= 0 && altitudeFeet < 100000;
            }

            Match feet = Regex.Match(value, @"\b(?<feet>\d{4,5})\s*(?:FT|FEET)?\b");
            if (feet.Success && int.TryParse(feet.Groups["feet"].Value, out int parsedFeet))
            {
                altitudeFeet = parsedFeet;
                return altitudeFeet >= 0 && altitudeFeet < 100000;
            }

            Match plainFlightLevel = Regex.Match(value, @"\b(?<level>\d{2,3})\b");
            if (plainFlightLevel.Success && int.TryParse(plainFlightLevel.Groups["level"].Value, out int plainFl))
            {
                altitudeFeet = plainFl * 100;
                return altitudeFeet >= 0 && altitudeFeet < 100000;
            }

            return false;
        }

        private static string FormatAltitudeForCoverage(int altitudeFeet)
        {
            if (altitudeFeet <= 0)
            {
                return "SFC";
            }

            if (altitudeFeet >= 10000 || altitudeFeet % 100 == 0)
            {
                int flightLevel = (int)Math.Round(altitudeFeet / 100.0);
                return "FL" + flightLevel.ToString("000", System.Globalization.CultureInfo.InvariantCulture);
            }

            return altitudeFeet.ToString(System.Globalization.CultureInfo.InvariantCulture) + " ft";
        }

        private const double CpdlcRouteUpcomingVatglassesRadiusNm = 450.0;

        private bool TryGetExplicitFlightPlanRouteFirCandidate(string callsign, string info, string code, out string routeFir)
        {
            routeFir = string.Empty;

            if (string.IsNullOrWhiteSpace(callsign) || string.IsNullOrWhiteSpace(code))
            {
                return false;
            }

            if (userVATSIMData?.flight_plan == null)
            {
                return false;
            }

            List<string> routeFirs = GetFlightPlanRouteFirCodesForCpdlc();

            foreach (string fir in routeFirs)
            {
                if (!ControllerMatchesRouteFirCode(callsign, info, code, fir))
                {
                    continue;
                }

                routeFir = fir;
                return true;
            }

            return false;
        }

        private string GetCpdlcControllerMatchReason(Controller controller, string code, string activeStation, string departure, string arrival, List<FirBoundaryFeature> currentFirs)
        {
            string callsign = (controller?.callsign ?? string.Empty).Trim().ToUpperInvariant();
            code = (code ?? string.Empty).Trim().ToUpperInvariant();
            activeStation = (activeStation ?? string.Empty).Trim().ToUpperInvariant();
            departure = (departure ?? string.Empty).Trim().ToUpperInvariant();
            arrival = (arrival ?? string.Empty).Trim().ToUpperInvariant();

            bool isApp = IsAppLikeControllerCallsign(callsign);

            // APP remains conservative and does not use generic nearby matching.
            if (isApp)
            {
                if (!IsAirborneNowForPhase() && AppCallsignMatchesAirport(callsign, departure))
                {
                    return "APP matches DEP " + departure;
                }

                if (AppCallsignMatchesAirport(callsign, arrival))
                {
                    bool arrivalAppRelevant =
                        IsArrivalPhaseLikely() ||
                        (flightPhaseEnrouteSeen &&
                         string.Equals(activeStation, arrival, StringComparison.OrdinalIgnoreCase) &&
                         userVATSIMData?.altitude < 25000);

                    if (arrivalAppRelevant)
                    {
                        return "APP matches ARR " + arrival;
                    }
                }

                return string.Empty;
            }

            if (IsCenterLikeControllerCallsign(callsign))
            {
                VatglassesSectorMatch sectorMatch = TryGetVatglassesSectorMatch(controller, code, Enumerable.Empty<FirBoundaryFeature>());
                string routeFir = string.Empty;
                bool explicitRouteFirCandidate = TryGetExplicitFlightPlanRouteFirCandidate(callsign, GetControllerInfoText(controller), code, out routeFir);

                if (sectorMatch == null && explicitRouteFirCandidate)
                {
                    // Route FIR pre-alert: only for controllers explicitly present in the
                    // filed route/EET and still backed by VATGlasses geometry. This keeps
                    // far-away online centers out while allowing near-upcoming FIRs such
                    // as EPWW before the standard 200 NM helper radius.
                    sectorMatch = TryGetVatglassesSectorMatch(
                        controller,
                        code,
                        Enumerable.Empty<FirBoundaryFeature>(),
                        CpdlcRouteUpcomingVatglassesRadiusNm);
                }

                if (sectorMatch == null)
                {
                    return string.Empty;
                }

                string sectorText = string.IsNullOrWhiteSpace(sectorMatch.AirspaceId)
                    ? sectorMatch.PositionId
                    : sectorMatch.AirspaceId + "/" + sectorMatch.PositionId;

                if (explicitRouteFirCandidate && sectorMatch.IsNearbyCandidate && sectorMatch.DistanceNmFromAircraft > FirNearbyRadiusNm)
                {
                    return "VATGlasses upcoming route FIR " + routeFir + " " + sectorText + " (" + Math.Round(sectorMatch.DistanceNmFromAircraft) + " NM)";
                }

                return sectorMatch.IsNearbyCandidate
                    ? "VATGlasses nearby sector " + sectorText + " (" + Math.Round(sectorMatch.DistanceNmFromAircraft) + " NM)"
                    : "VATGlasses current sector " + sectorText;
            }

            return string.Empty;
        }

        private void EnsureVatglassesDatasetsLoadedForContext(IEnumerable<FirBoundaryFeature> currentFirs, string departure, string arrival, string code, string callsign, string info)
        {
            List<string> keys = GetVatglassesDataKeysForContext(currentFirs, departure, arrival, code, callsign, info).ToList();

            lock (vatglassesDataLock)
            {
                if (keys.Count > 0)
                {
                    lastVatglassesDebugText = "VATGlasses keys: " + string.Join(", ", keys);
                }
            }

            foreach (string key in keys)
            {
                _ = EnsureVatglassesDatasetLoadedAsync(key, false);
            }
        }

        private IEnumerable<string> GetVatglassesDataKeysForContext(IEnumerable<FirBoundaryFeature> currentFirs, string departure, string arrival, string code, string callsign, string info)
        {
            HashSet<string> keys = new(StringComparer.OrdinalIgnoreCase);

            void AddKey(string value)
            {
                string clean = (value ?? string.Empty).Trim().ToLowerInvariant();
                clean = Regex.Replace(clean, @"[^a-z0-9-]", string.Empty);

                if (!string.IsNullOrWhiteSpace(clean) &&
                    clean.Length >= 2 &&
                    clean.Length <= 20)
                {
                    keys.Add(clean);
                }
            }

            void AddKeysFromIcaoOrFirId(string value)
            {
                string clean = Regex.Replace((value ?? string.Empty).Trim().ToUpperInvariant(), @"[^A-Z0-9]", string.Empty);
                if (clean.Length < 2 || !char.IsLetter(clean[0]) || !char.IsLetter(clean[1]))
                {
                    return;
                }

                // US ARTCCs are commonly identified in FIR data as KZNY/KZDC/etc.
                // VATGlasses only contains some US ARTCC data folders. Only add real
                // dataset keys here; other US centers still work through the FIR boundary
                // fallback below without causing repeated 404 downloads.
                if (Regex.IsMatch(clean, @"^KZ[A-Z0-9]{2}$"))
                {
                    string artccKey = clean.Substring(1).ToLowerInvariant();

                    if (string.Equals(artccKey, "zqm", StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(artccKey, "zqx", StringComparison.OrdinalIgnoreCase))
                    {
                        AddKey("zqm-zqx");
                    }
                    else if (VatglassesKnownUsDataSetKeys.Contains(artccKey))
                    {
                        AddKey(artccKey);
                    }

                    return;
                }

                if (Regex.IsMatch(clean, @"^Z[A-Z0-9]{2}$"))
                {
                    string artccKey = clean.ToLowerInvariant();

                    if (string.Equals(artccKey, "zqm", StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(artccKey, "zqx", StringComparison.OrdinalIgnoreCase))
                    {
                        AddKey("zqm-zqx");
                    }
                    else if (VatglassesKnownUsDataSetKeys.Contains(artccKey))
                    {
                        AddKey(artccKey);
                    }

                    return;
                }

                // Normal country/region files: LTAA/LT78 -> lt, LOVV -> lo, ENOR -> en.
                AddKey(clean.Substring(0, 2).ToLowerInvariant());

                // Some VATGlasses datasets/position packs use a more specific key.
                // Keep this as an additional non-blocking lookup for explicit CPDLC
                // codes such as EPWW, so upcoming FIRs are loaded before crossing.
                if (clean.Length == 4)
                {
                    AddKey(clean.ToLowerInvariant());
                }
            }

            foreach (FirBoundaryFeature fir in currentFirs ?? Enumerable.Empty<FirBoundaryFeature>())
            {
                AddKeysFromIcaoOrFirId(fir?.Id);

                // Some FIR ids are hidden in the search text/name instead of the primary Id.
                foreach (Match match in Regex.Matches((fir?.SearchText ?? string.Empty) + " " + (fir?.Name ?? string.Empty), @"\b(?:KZ[A-Z0-9]{2}|Z[A-Z0-9]{2}|[A-Z]{2}[A-Z0-9]{2})\b"))
                {
                    AddKeysFromIcaoOrFirId(match.Value);
                }
            }

            AddKeysFromIcaoOrFirId(departure);
            AddKeysFromIcaoOrFirId(arrival);
            AddKeysFromIcaoOrFirId(code);

            foreach (string routeFir in GetFlightPlanRouteFirCodesForCpdlc())
            {
                AddKeysFromIcaoOrFirId(routeFir);
            }

            // No vats.im/... front-end URL parsing here on purpose:
            // dataset selection is driven by current/nearby FIR ids, FP ICAOs and Hoppie code.
            // The controller itself is matched later against owner ids inside the selected data.

            // Shared FSS data is small and useful for upper/large sectors.
            AddKey("fss");

            return keys.Where(key => !string.IsNullOrWhiteSpace(key)).Take(8).ToList();
        }

        private void RefreshCpdlcHelperAfterVatglassesLoad()
        {
            // Do not run full CPDLC discovery immediately from every VATGlasses
            // background load completion. Several datasets can finish within seconds
            // after startup and recursively trigger expensive discovery/UI refreshes.
            // The normal VATSIM/helper timer will pick up the loaded data shortly.
            try
            {
                SafeUi(UpdateCpdlcDiscoveryLabel);
            }
            catch (Exception ex)
            {
                Logger.Debug("VATGlasses post-load label refresh failed: " + ex.Message);
            }
        }

        private async Task EnsureVatglassesDatasetLoadedAsync(string key, bool force)
        {
            key = (key ?? string.Empty).Trim().ToLowerInvariant();
            if (!Regex.IsMatch(key, @"^[a-z0-9-]{2,20}$"))
            {
                return;
            }

            lock (vatglassesDataLock)
            {
                if (!force &&
                    vatglassesDatasets.TryGetValue(key, out VatglassesDataset cached) &&
                    cached != null &&
                    DateTime.UtcNow - cached.LoadedUtc < vatglassesDatasetCacheLifetime)
                {
                    return;
                }

                if (!force &&
                    vatglassesUnavailableUtc.TryGetValue(key, out DateTime unavailableUtc) &&
                    DateTime.UtcNow - unavailableUtc < vatglassesUnavailableRetry)
                {
                    return;
                }

                if (vatglassesLoadInProgress.Contains(key))
                {
                    return;
                }

                vatglassesLoadInProgress.Add(key);
                lastVatglassesDebugText = "VATGlasses loading data/" + key + ".json";
            }

            try
            {
                VatglassesDataset dataset = null;
                string loadedPath = string.Empty;
                Exception singleFileException = null;

                try
                {
                    string url = VatglassesRawDataBaseUrl + key + ".json";
                    string json = await webclient.GetStringAsync(url);
                    dataset = ParseVatglassesStaticDataset(key, json);
                    loadedPath = "data/" + key + ".json";
                }
                catch (Exception ex)
                {
                    singleFileException = ex;
                }

                if (dataset == null)
                {
                    // Some VATGlasses data sets are folders, e.g. data/zab/airspace.json
                    // plus data/zab/positions.json.
                    string airspaceUrl = VatglassesRawDataBaseUrl + key + "/airspace.json";
                    string airspaceJson = await webclient.GetStringAsync(airspaceUrl);
                    dataset = ParseVatglassesStaticDataset(key, airspaceJson);
                    loadedPath = "data/" + key + "/airspace.json";

                    try
                    {
                        string positionsUrl = VatglassesRawDataBaseUrl + key + "/positions.json";
                        string positionsJson = await webclient.GetStringAsync(positionsUrl);
                        ParseVatglassesPositionsIntoDataset(dataset, positionsJson);
                        loadedPath += " + positions.json";
                    }
                    catch (Exception positionsEx)
                    {
                        Logger.Debug("VATGlasses optional positions load failed for " + key + ": " + positionsEx.Message);
                    }
                }

                lock (vatglassesDataLock)
                {
                    vatglassesDatasets[key] = dataset;
                    vatglassesUnavailableUtc.Remove(key);
                    lastVatglassesDebugText = "VATGlasses loaded " + key + " (" + loadedPath + "): " + dataset.Positions.Count + " positions, " + dataset.Airspaces.Count + " airspaces";
                }

                Logger.Debug("Loaded VATGlasses data " + key + " (" + loadedPath + "): " + dataset.Positions.Count + " positions, " + dataset.Airspaces.Count + " airspaces.");
                RefreshCpdlcHelperAfterVatglassesLoad();
            }
            catch (Exception ex)
            {
                lock (vatglassesDataLock)
                {
                    vatglassesUnavailableUtc[key] = DateTime.UtcNow;
                    lastVatglassesDebugText = "VATGlasses failed " + key + ": " + ex.Message;
                }

                Logger.Debug("VATGlasses data load failed for " + key + ": " + ex.Message);
                RefreshCpdlcHelperAfterVatglassesLoad();
            }
            finally
            {
                lock (vatglassesDataLock)
                {
                    vatglassesLoadInProgress.Remove(key);
                }
            }
        }

        private VatglassesDataset ParseVatglassesStaticDataset(string key, string json)
        {
            JToken root = JToken.Parse(string.IsNullOrWhiteSpace(json) ? "[]" : json);
            VatglassesDataset dataset = new()
            {
                Key = key,
                LoadedUtc = DateTime.UtcNow
            };

            JObject rootObject = root as JObject;
            JObject positions = rootObject?["positions"] as JObject;
            if (positions != null)
            {
                foreach (JProperty property in positions.Properties())
                {
                    VatglassesPosition position = ParseVatglassesPosition(property.Name, property.Value);
                    if (position != null && !string.IsNullOrWhiteSpace(position.Id))
                    {
                        dataset.Positions[position.Id] = position;
                    }
                }
            }

            JArray airspace =
                root as JArray ??
                rootObject?["airspace"] as JArray ??
                rootObject?["sectors"] as JArray;

            if (airspace != null)
            {
                foreach (JToken item in airspace)
                {
                    VatglassesAirspace parsed = ParseVatglassesAirspace(item);
                    if (parsed != null && parsed.Sectors.Count > 0)
                    {
                        dataset.Airspaces.Add(parsed);
                    }
                }
            }

            return dataset;
        }

        private void ParseVatglassesPositionsIntoDataset(VatglassesDataset dataset, string json)
        {
            if (dataset == null || string.IsNullOrWhiteSpace(json))
            {
                return;
            }

            JToken root = JToken.Parse(json);
            JObject rootObject = root as JObject;
            JObject positions = rootObject?["positions"] as JObject ?? rootObject;

            if (positions == null)
            {
                return;
            }

            foreach (JProperty property in positions.Properties())
            {
                VatglassesPosition position = ParseVatglassesPosition(property.Name, property.Value);
                if (position != null && !string.IsNullOrWhiteSpace(position.Id))
                {
                    dataset.Positions[position.Id] = position;
                }
            }
        }

        private VatglassesPosition ParseVatglassesPosition(string id, JToken token)
        {
            if (token == null)
            {
                return null;
            }

            VatglassesPosition position = new()
            {
                Id = NormalizeVatglassesOwnerId(id),
                Type = (token["type"]?.ToString() ?? string.Empty).Trim().ToUpperInvariant(),
                Frequency = (token["frequency"]?.ToString() ?? token["freq"]?.ToString() ?? string.Empty).Trim()
            };

            foreach (string prefix in ReadVatglassesStringArray(token["pre"]))
            {
                string cleanPrefix = prefix.Trim().ToUpperInvariant();
                if (!string.IsNullOrWhiteSpace(cleanPrefix))
                {
                    position.Prefixes.Add(cleanPrefix);
                }
            }

            if (TryParseControllerFrequencyHz(position.Frequency, out long hz))
            {
                position.FrequencyHz = hz;
            }

            return position;
        }

        private VatglassesAirspace ParseVatglassesAirspace(JToken token)
        {
            if (token == null)
            {
                return null;
            }

            VatglassesAirspace airspace = new()
            {
                Id = (token["id"]?.ToString() ?? string.Empty).Trim().ToUpperInvariant()
            };

            foreach (string owner in ReadVatglassesStringArray(token["owner"]))
            {
                string cleanOwner = NormalizeVatglassesOwnerId(owner);
                if (!string.IsNullOrWhiteSpace(cleanOwner))
                {
                    airspace.Owners.Add(cleanOwner);
                }
            }

            foreach (JToken sectorToken in token["sectors"] as JArray ?? new JArray())
            {
                GeoPolygon polygon = ParseVatglassesPointsPolygon(sectorToken["points"]);
                if (polygon == null)
                {
                    continue;
                }

                airspace.Sectors.Add(new VatglassesAirspaceSector
                {
                    MinAltitude = TryReadVatglassesAltitude(sectorToken["min"], out int minAlt) ? minAlt : null,
                    MaxAltitude = TryReadVatglassesAltitude(sectorToken["max"], out int maxAlt) ? maxAlt : null,
                    Polygon = polygon
                });
            }

            return airspace;
        }

        private static IEnumerable<string> ReadVatglassesStringArray(JToken token)
        {
            if (token == null || token.Type == JTokenType.Null)
            {
                yield break;
            }

            if (token is JArray array)
            {
                foreach (JToken item in array)
                {
                    string value = item?.ToString();
                    if (!string.IsNullOrWhiteSpace(value))
                    {
                        yield return value;
                    }
                }

                yield break;
            }

            string single = token.ToString();
            if (!string.IsNullOrWhiteSpace(single))
            {
                yield return single;
            }
        }

        private static bool TryReadVatglassesAltitude(JToken token, out int altitude)
        {
            altitude = 0;
            if (token == null || token.Type == JTokenType.Null)
            {
                return false;
            }

            if (!int.TryParse(token.ToString(), System.Globalization.NumberStyles.Integer, System.Globalization.CultureInfo.InvariantCulture, out int value))
            {
                return false;
            }

            altitude = NormalizeVatglassesAltitude(value);
            return true;
        }

        private static int NormalizeVatglassesAltitude(int altitude)
        {
            // VATGlasses files may use FL-style small values in some data sets.
            // Treat 1..599 as flight levels and larger values as feet.
            if (altitude > 0 && altitude < 600)
            {
                return altitude * 100;
            }

            return altitude;
        }

        private GeoPolygon ParseVatglassesPointsPolygon(JToken pointsToken)
        {
            if (pointsToken is not JArray points)
            {
                return null;
            }

            GeoPolygon polygon = new();
            List<GeoPoint> ring = new();

            foreach (JToken pointToken in points)
            {
                if (pointToken is not JArray pair || pair.Count < 2)
                {
                    continue;
                }

                if (!TryParseVatglassesCoordinate(pair[0]?.ToString(), out double lat) ||
                    !TryParseVatglassesCoordinate(pair[1]?.ToString(), out double lon))
                {
                    continue;
                }

                ring.Add(new GeoPoint { Lat = lat, Lon = lon });

                polygon.MinLat = Math.Min(polygon.MinLat, lat);
                polygon.MaxLat = Math.Max(polygon.MaxLat, lat);
                polygon.MinLon = Math.Min(polygon.MinLon, lon);
                polygon.MaxLon = Math.Max(polygon.MaxLon, lon);
            }

            if (ring.Count < 3)
            {
                return null;
            }

            polygon.Rings.Add(ring);
            return polygon;
        }

        private static bool TryParseVatglassesCoordinate(string value, out double degrees)
        {
            degrees = 0;

            string clean = (value ?? string.Empty).Trim();
            if (string.IsNullOrWhiteSpace(clean))
            {
                return false;
            }

            if (double.TryParse(clean, System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture, out double decimalDegrees) &&
                clean.Contains("."))
            {
                degrees = decimalDegrees;
                return true;
            }

            int sign = 1;
            if (clean.StartsWith("-", StringComparison.Ordinal))
            {
                sign = -1;
                clean = clean.Substring(1);
            }
            else if (clean.StartsWith("+", StringComparison.Ordinal))
            {
                clean = clean.Substring(1);
            }

            clean = Regex.Replace(clean, @"[^0-9]", string.Empty);
            if (clean.Length < 4)
            {
                return false;
            }

            if (clean.Length < 6)
            {
                clean = clean.PadLeft(6, '0');
            }

            string secondsText = clean.Substring(clean.Length - 2, 2);
            string minutesText = clean.Substring(clean.Length - 4, 2);
            string degreesText = clean.Substring(0, clean.Length - 4);

            if (!int.TryParse(degreesText, out int deg) ||
                !int.TryParse(minutesText, out int min) ||
                !int.TryParse(secondsText, out int sec))
            {
                return false;
            }

            degrees = sign * (deg + (min / 60.0) + (sec / 3600.0));
            return Math.Abs(degrees) <= 180.0;
        }

        private static bool VatglassesAirspaceIdMatchesExplicitCode(string airspaceId, string code, string callsign, string info)
        {
            string cleanCode = Regex.Replace((code ?? string.Empty).Trim().ToUpperInvariant(), @"[^A-Z0-9]", string.Empty);
            if (cleanCode.Length != 4)
            {
                return false;
            }

            string cleanAirspace = Regex.Replace((airspaceId ?? string.Empty).Trim().ToUpperInvariant(), @"[^A-Z0-9]", string.Empty);
            string cleanCallsign = Regex.Replace((callsign ?? string.Empty).Trim().ToUpperInvariant(), @"[^A-Z0-9]", string.Empty);
            string upperInfo = (info ?? string.Empty).Trim().ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(cleanAirspace))
            {
                return false;
            }

            return cleanAirspace.Contains(cleanCode, StringComparison.OrdinalIgnoreCase) ||
                   cleanAirspace.Contains(cleanCode.Substring(2), StringComparison.OrdinalIgnoreCase) ||
                   cleanCallsign.StartsWith(cleanCode, StringComparison.OrdinalIgnoreCase) ||
                   Regex.IsMatch(upperInfo, @"\[" + Regex.Escape(cleanCode) + @"\]");
        }

        private VatglassesSectorMatch TryGetVatglassesSectorMatch(Controller controller, string code, IEnumerable<FirBoundaryFeature> currentFirs, double radiusNm = FirNearbyRadiusNm)
        {
            Pilot pilot = userVATSIMData;
            if (pilot == null || controller == null)
            {
                return null;
            }

            string callsign = (controller.callsign ?? string.Empty).Trim().ToUpperInvariant();
            HashSet<string> candidateKeys = new(GetVatglassesDataKeysForContext(currentFirs, string.Empty, string.Empty, code, callsign, GetControllerInfoText(controller)), StringComparer.OrdinalIgnoreCase);
            HashSet<string> controllerOwnerIds = GetVatglassesOwnerIdsForController(controller, code);

            VatglassesSectorMatch best = null;
            string debugBestReject = string.Empty;

            foreach (string key in candidateKeys)
            {
                VatglassesDataset dataset;
                lock (vatglassesDataLock)
                {
                    vatglassesDatasets.TryGetValue(key, out dataset);
                }

                if (dataset == null)
                {
                    lock (vatglassesDataLock)
                    {
                        lastVatglassesDebugText = "VATGlasses waiting for data/" + key + ".json";
                    }

                    Logger.Debug("VATGlasses sector match waiting for data/" + key + ".json.");
                    _ = EnsureVatglassesDatasetLoadedAsync(key, false);
                    continue;
                }

                if (dataset.Airspaces.Count == 0)
                {
                    debugBestReject = "VATGlasses " + key + " loaded but no airspace parsed";
                    continue;
                }

                HashSet<string> candidatePositions = GetVatglassesPositionIdsForController(dataset, controller, code);
                HashSet<string> allCandidateOwners = new(controllerOwnerIds, StringComparer.OrdinalIgnoreCase);

                foreach (string position in candidatePositions)
                {
                    allCandidateOwners.Add(position);
                }

                if (allCandidateOwners.Count == 0)
                {
                    debugBestReject = "VATGlasses " + key + " loaded but no owner token for " + callsign + " / " + code;
                    continue;
                }

                bool ownerFoundInDataset = false;
                double nearestRejectedDistance = double.MaxValue;
                string nearestRejectedOwner = string.Empty;
                string nearestRejectedAirspace = string.Empty;

                foreach (VatglassesAirspace airspace in dataset.Airspaces)
                {
                    string matchingOwner = airspace.Owners
                        .Select(NormalizeVatglassesOwnerId)
                        .FirstOrDefault(owner => VatglassesOwnerMatchesCandidate(owner, allCandidateOwners));

                    bool explicitCodeAirspaceMatch = false;
                    if (string.IsNullOrWhiteSpace(matchingOwner) &&
                        radiusNm > FirNearbyRadiusNm &&
                        VatglassesAirspaceIdMatchesExplicitCode(airspace.Id, code, callsign, GetControllerInfoText(controller)))
                    {
                        matchingOwner = NormalizeVatglassesOwnerId(code);
                        explicitCodeAirspaceMatch = true;
                    }

                    if (string.IsNullOrWhiteSpace(matchingOwner))
                    {
                        continue;
                    }

                    ownerFoundInDataset = true;

                    foreach (VatglassesAirspaceSector sector in airspace.Sectors)
                    {
                        // Helper discovery intentionally ignores sector altitude filters.
                        // Controller data often contains layered/conditional sectors and
                        // altitude filtering has hidden valid nearby CPDLC controllers.
                        bool inside = PointInGeoPolygon(pilot.latitude, pilot.longitude, sector.Polygon);
                        double distanceNm = inside ? 0 : DistanceNmToGeoPolygon(pilot.latitude, pilot.longitude, sector.Polygon, radiusNm);

                        if (!inside && distanceNm > radiusNm)
                        {
                            if (distanceNm < nearestRejectedDistance)
                            {
                                nearestRejectedDistance = distanceNm;
                                nearestRejectedOwner = matchingOwner;
                                nearestRejectedAirspace = airspace.Id;
                            }

                            continue;
                        }

                        VatglassesSectorMatch match = new()
                        {
                            DataKey = dataset.Key,
                            PositionId = explicitCodeAirspaceMatch ? matchingOwner + "-EXPLICIT" : matchingOwner,
                            AirspaceId = airspace.Id,
                            IsNearbyCandidate = !inside,
                            DistanceNmFromAircraft = distanceNm
                        };

                        if (best == null ||
                            (!match.IsNearbyCandidate && best.IsNearbyCandidate) ||
                            match.DistanceNmFromAircraft < best.DistanceNmFromAircraft)
                        {
                            best = match;
                        }
                    }
                }

                if (!ownerFoundInDataset)
                {
                    debugBestReject = "VATGlasses " + key + " loaded: owner not found for " + callsign + " / " + code + " tokens " + string.Join(",", allCandidateOwners.Take(8));
                }
                else if (nearestRejectedDistance < double.MaxValue)
                {
                    debugBestReject = "VATGlasses " + key + " nearest " + nearestRejectedAirspace + "/" + nearestRejectedOwner + " " + Math.Round(nearestRejectedDistance) + " NM > " + Math.Round(radiusNm) + " NM";
                }
            }

            lock (vatglassesDataLock)
            {
                if (best != null)
                {
                    lastVatglassesDebugText = "VATGlasses match " + best.DataKey + " " + best.AirspaceId + "/" + best.PositionId + " " + Math.Round(best.DistanceNmFromAircraft) + " NM";
                }
                else if (!string.IsNullOrWhiteSpace(debugBestReject))
                {
                    lastVatglassesDebugText = debugBestReject;
                }
            }

            return best;
        }

        private HashSet<string> GetVatglassesPositionIdsForController(VatglassesDataset dataset, Controller controller, string code)
        {
            HashSet<string> matches = new(StringComparer.OrdinalIgnoreCase);

            if (dataset == null || controller == null)
            {
                return matches;
            }

            foreach (VatglassesPosition position in dataset.Positions.Values)
            {
                if (VatglassesPositionMatchesController(position, controller, code))
                {
                    matches.Add(position.Id);
                }
            }

            return matches;
        }

        private HashSet<string> GetVatglassesOwnerIdsForController(Controller controller, string code)
        {
            HashSet<string> owners = new(StringComparer.OrdinalIgnoreCase);

            string callsign = (controller?.callsign ?? string.Empty).Trim().ToUpperInvariant();
            string advertisedCode = (code ?? string.Empty).Trim().ToUpperInvariant();

            void AddOwner(string value)
            {
                string clean = NormalizeVatglassesOwnerId(value);
                if (!string.IsNullOrWhiteSpace(clean))
                {
                    owners.Add(clean);

                    string compact = Regex.Replace(clean, @"[^A-Z0-9]", string.Empty);
                    if (!string.IsNullOrWhiteSpace(compact))
                    {
                        owners.Add(compact);
                    }
                }
            }

            if (!string.IsNullOrWhiteSpace(callsign))
            {
                AddOwner(callsign);

                string[] parts = callsign.Split(new[] { '_' }, StringSplitOptions.RemoveEmptyEntries)
                    .Select(part => part.Trim().ToUpperInvariant())
                    .Where(part => !string.IsNullOrWhiteSpace(part))
                    .ToArray();

                for (int i = 0; i < parts.Length; i++)
                {
                    string part = parts[i];
                    if (part == "CTR" || part == "FSS" || part == "APP" || part == "TWR" || part == "GND" || part == "DEL")
                    {
                        continue;
                    }

                    AddOwner(part);

                    if (string.Equals(part, "ALL", StringComparison.OrdinalIgnoreCase))
                    {
                        AddOwner("ALLFIR");
                    }

                    if (i > 0)
                    {
                        AddOwner(parts[0] + part);
                        AddOwner(parts[0] + "_" + part);
                    }
                }
            }

            if (!string.IsNullOrWhiteSpace(advertisedCode))
            {
                AddOwner(advertisedCode);

                if (advertisedCode.Length == 4)
                {
                    string shortCode = advertisedCode.Substring(2);
                    AddOwner(shortCode);

                    if (callsign.Contains("_ALL_", StringComparison.OrdinalIgnoreCase) ||
                        callsign.Contains("_ALL", StringComparison.OrdinalIgnoreCase))
                    {
                        AddOwner("ALL");
                        AddOwner("ALLFIR");
                        AddOwner(advertisedCode + "ALL");
                        AddOwner(advertisedCode + "_ALL");
                        AddOwner(shortCode + "ALL");
                        AddOwner(shortCode + "_ALL");
                    }
                }

                string digits = Regex.Replace(advertisedCode, @"\D", string.Empty);
                if (!string.IsNullOrWhiteSpace(digits))
                {
                    AddOwner(digits);

                    // Turkey/common sector style: Hoppie LT78 can correspond to owner W78.
                    AddOwner("W" + digits);
                    AddOwner("E" + digits);
                    AddOwner("N" + digits);
                    AddOwner("S" + digits);
                }
            }

            return owners;
        }

        private static bool VatglassesOwnerMatchesCandidate(string owner, IEnumerable<string> candidates)
        {
            string cleanOwner = NormalizeVatglassesOwnerId(owner);
            if (string.IsNullOrWhiteSpace(cleanOwner))
            {
                return false;
            }

            foreach (string candidate in candidates ?? Enumerable.Empty<string>())
            {
                string cleanCandidate = NormalizeVatglassesOwnerId(candidate);
                if (string.IsNullOrWhiteSpace(cleanCandidate))
                {
                    continue;
                }

                if (string.Equals(cleanOwner, cleanCandidate, StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }

                string compactOwner = Regex.Replace(cleanOwner, @"[^A-Z0-9]", string.Empty);
                string compactCandidate = Regex.Replace(cleanCandidate, @"[^A-Z0-9]", string.Empty);

                if (!string.IsNullOrWhiteSpace(compactOwner) &&
                    string.Equals(compactOwner, compactCandidate, StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }

                if (string.Equals(compactOwner, "ALLFIR", StringComparison.OrdinalIgnoreCase) &&
                    string.Equals(compactCandidate, "ALL", StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }

                if (string.Equals(compactOwner, "ALL", StringComparison.OrdinalIgnoreCase) &&
                    string.Equals(compactCandidate, "ALLFIR", StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }

                if (compactCandidate.Length == 4 &&
                    compactOwner.Length == 2 &&
                    string.Equals(compactOwner, compactCandidate.Substring(2), StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }

                string ownerDigits = Regex.Replace(cleanOwner, @"\D", string.Empty);
                string candidateDigits = Regex.Replace(cleanCandidate, @"\D", string.Empty);

                if (!string.IsNullOrWhiteSpace(ownerDigits) &&
                    ownerDigits.Length >= 2 &&
                    string.Equals(ownerDigits, candidateDigits, StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }
            }

            return false;
        }

        private bool VatglassesPositionMatchesController(VatglassesPosition position, Controller controller, string code = "")
        {
            if (position == null || controller == null)
            {
                return false;
            }

            HashSet<string> ownerTokens = GetVatglassesOwnerIdsForController(controller, code);
            if (VatglassesOwnerMatchesCandidate(position.Id, ownerTokens))
            {
                return true;
            }

            string callsign = (controller.callsign ?? string.Empty).Trim().ToUpperInvariant();
            string[] parts = callsign.Split(new[] { '_' }, StringSplitOptions.RemoveEmptyEntries);
            string prefix = parts.Length > 0 ? parts[0].Trim().ToUpperInvariant() : string.Empty;
            string suffix = parts.Length > 1 ? parts[parts.Length - 1].Trim().ToUpperInvariant() : string.Empty;

            if (!string.IsNullOrWhiteSpace(position.Type) &&
                !string.Equals(position.Type, suffix, StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            if (position.Prefixes.Count > 0 &&
                !position.Prefixes.Any(item => string.Equals(item, prefix, StringComparison.OrdinalIgnoreCase)))
            {
                return false;
            }

            if (position.FrequencyHz > 0)
            {
                List<long> controllerFreqs = GetControllerTunedFrequencies(controller);
                if (controllerFreqs.Count > 0 &&
                    !controllerFreqs.Any(freq => Math.Abs(freq - position.FrequencyHz) <= 8000))
                {
                    return false;
                }
            }

            return position.Prefixes.Count > 0 &&
                   !string.IsNullOrWhiteSpace(position.Type) &&
                   string.IsNullOrWhiteSpace(position.Frequency);
        }

        private static bool VatglassesAltitudeMatchesSector(VatglassesAirspaceSector sector, int altitude)
        {
            if (sector == null)
            {
                return false;
            }

            if (sector.MinAltitude.HasValue && altitude < sector.MinAltitude.Value)
            {
                return false;
            }

            if (sector.MaxAltitude.HasValue && altitude > sector.MaxAltitude.Value)
            {
                return false;
            }

            return true;
        }

        private static string NormalizeVatglassesOwnerId(string value)
        {
            string clean = (value ?? string.Empty).Trim().ToUpperInvariant();
            if (string.IsNullOrWhiteSpace(clean))
            {
                return string.Empty;
            }

            int slash = clean.LastIndexOf('/');
            if (slash >= 0 && slash < clean.Length - 1)
            {
                clean = clean.Substring(slash + 1);
            }

            clean = Regex.Replace(clean, @"\s+", string.Empty);
            clean = clean.Trim('_');

            foreach (string suffix in new[] { "_CTR", "_FSS", "_APP", "_TWR", "_GND", "_DEL" })
            {
                if (clean.EndsWith(suffix, StringComparison.OrdinalIgnoreCase))
                {
                    clean = clean.Substring(0, clean.Length - suffix.Length);
                    break;
                }
            }

            return clean;
        }

        private static bool IsAppLikeControllerCallsign(string callsign)
        {
            string upper = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            return upper.EndsWith("_APP", StringComparison.OrdinalIgnoreCase) ||
                   upper.Contains("_APP_") ||
                   Regex.IsMatch(upper, @"^[A-Z0-9]{4}.*APP$");
        }

        private static bool AppCallsignMatchesAirport(string callsign, string airport)
        {
            string upper = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string station = (airport ?? string.Empty).Trim().ToUpperInvariant();

            if (station.Length != 4)
            {
                return false;
            }

            return Regex.IsMatch(upper, "^" + Regex.Escape(station) + @".*APP$");
        }

        private static bool IsAppControllerForFlightPlan(string callsign, string departure, string arrival)
        {
            return AppCallsignMatchesAirport(callsign, departure) ||
                   AppCallsignMatchesAirport(callsign, arrival);
        }

        private static bool IsCenterLikeControllerCallsign(string callsign)
        {
            string upper = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            return upper.EndsWith("_CTR", StringComparison.OrdinalIgnoreCase) ||
                   upper.EndsWith("_FSS", StringComparison.OrdinalIgnoreCase);
        }

        private static bool ControllerMatchesFir(string callsign, string info, FirBoundaryFeature fir)
        {
            if (fir == null)
            {
                return false;
            }

            string upperCallsign = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string upperInfo = (info ?? string.Empty).Trim().ToUpperInvariant();
            string id = (fir.Id ?? string.Empty).Trim().ToUpperInvariant();
            string name = (fir.Name ?? string.Empty).Trim().ToUpperInvariant();

            if (!string.IsNullOrWhiteSpace(id))
            {
                if (upperCallsign.StartsWith(id, StringComparison.OrdinalIgnoreCase) ||
                    upperInfo.Contains(id))
                {
                    return true;
                }

            }

            if (!string.IsNullOrWhiteSpace(name) && upperInfo.Contains(name))
            {
                return true;
            }

            string searchText = (fir.SearchText ?? string.Empty).Trim().ToUpperInvariant();
            if (!string.IsNullOrWhiteSpace(searchText))
            {
                foreach (string token in searchText.Split(new[] { ' ', ',', ';', '/', '|', '_' }, StringSplitOptions.RemoveEmptyEntries))
                {
                    if (token.Length >= 4 &&
                        (upperCallsign.StartsWith(token, StringComparison.OrdinalIgnoreCase) || upperInfo.Contains(token)))
                    {
                        return true;
                    }
                }
            }

            return false;
        }
        private static bool IsGenericFirNameWord(string token)
        {
            string clean = (token ?? string.Empty).Trim().ToUpperInvariant();

            return string.IsNullOrWhiteSpace(clean) ||
                   clean == "FIR" ||
                   clean == "UIR" ||
                   clean == "CTA" ||
                   clean == "CTR" ||
                   clean == "ARTCC" ||
                   clean == "ACC" ||
                   clean == "CENTER" ||
                   clean == "CENTRE" ||
                   clean == "CONTROL" ||
                   clean == "CONTROLS" ||
                   clean == "SECTOR" ||
                   clean == "SECTORS" ||
                   clean == "AIRSPACE" ||
                   clean == "BOUNDARY" ||
                   clean == "RADAR" ||
                   clean == "OCEANIC" ||
                   clean == "DOMESTIC" ||
                   clean == "UPPER" ||
                   clean == "LOWER";
        }

        private static IEnumerable<string> GetFirNameDerivedPrefixes(string text)
        {
            string upper = (text ?? string.Empty).Trim().ToUpperInvariant();

            foreach (Match match in Regex.Matches(upper, @"\b[A-Z][A-Z0-9]{2,}\b"))
            {
                string token = match.Value.Trim().ToUpperInvariant();

                if (IsGenericFirNameWord(token))
                {
                    continue;
                }

                if (Regex.IsMatch(token, @"^KZ[A-Z0-9]{2}$"))
                {
                    yield return token.Substring(1);
                    continue;
                }

                if (Regex.IsMatch(token, @"^Z[A-Z0-9]{2}$"))
                {
                    yield return token;
                    continue;
                }

                if (token.Length >= 5 && token.All(char.IsLetter))
                {
                    // Generic city/radio-name contraction:
                    // "DENVER ARTCC" -> DEN so live sector callsigns like DEN_17_CTR
                    // can match the already-current KZDV boundary without any DEN hardcode.
                    yield return token.Substring(0, 3);
                }
                else if (token.Length == 3 && token.All(char.IsLetterOrDigit))
                {
                    yield return token;
                }
            }
        }
        private static IEnumerable<string> GetBoundaryScopedUsArtccLivePrefixes(string firId)
        {
            string id = Regex.Replace((firId ?? string.Empty).Trim().ToUpperInvariant(), @"[^A-Z0-9]", string.Empty);
            if (Regex.IsMatch(id, @"^KZ[A-Z0-9]{2}$"))
            {
                id = id.Substring(1);
            }

            // Boundary-scoped US VATSIM callsign resolver.
            // This is only used after the aircraft is already inside/near that exact boundary.
            // It is needed because many US ARTCCs use live callsigns like DEN_17_CTR instead of ZDV_17_CTR.
            switch (id)
            {
                case "ZAB": yield return "ABQ"; break;
                case "ZAN": yield return "ANC"; break;
                case "ZAU": yield return "CHI"; break;
                case "ZBW": yield return "BOS"; break;
                case "ZDC": yield return "DC"; yield return "DCA"; break;
                case "ZDV": yield return "DEN"; break;
                case "ZFW": yield return "FTW"; break;
                case "ZHU": yield return "HOU"; break;
                case "ZID": yield return "IND"; break;
                case "ZJX": yield return "JAX"; break;
                case "ZKC": yield return "KC"; break;
                case "ZLA": yield return "LAX"; break;
                case "ZLC": yield return "SLC"; break;
                case "ZMA": yield return "MIA"; break;
                case "ZME": yield return "MEM"; break;
                case "ZMP": yield return "MSP"; break;
                case "ZNY": yield return "NY"; yield return "NYC"; break;
                case "ZOA": yield return "OAK"; break;
                case "ZOB": yield return "CLE"; break;
                case "ZSE": yield return "SEA"; break;
                case "ZTL": yield return "ATL"; break;
                case "ZUA": yield return "GUM"; break;
                case "ZHN": yield return "HCF"; yield return "HNL"; break;
                case "ZSU": yield return "SJU"; break;
            }
        }




        private static IEnumerable<string> GetStrictFirControllerPrefixes(FirBoundaryFeature fir)
        {
            HashSet<string> prefixes = new(StringComparer.OrdinalIgnoreCase);

            void AddPrefix(string value)
            {
                string clean = (value ?? string.Empty).Trim().ToUpperInvariant();
                if (!string.IsNullOrWhiteSpace(clean) && clean.Length >= 2)
                {
                    prefixes.Add(clean);
                }
            }

            string id = (fir?.Id ?? string.Empty).Trim().ToUpperInvariant();
            string name = (fir?.Name ?? string.Empty).Trim().ToUpperInvariant();
            string searchText = (fir?.SearchText ?? string.Empty).Trim().ToUpperInvariant();

            AddPrefix(id);

            // Generic US ARTCC normalization:
            // Boundary/FIR ids may be KZNY/KZDC while VATSIM callsigns are ZNY_CTR/ZDC_CTR.
            // This is not a hardcoded center list; it is a format normalization after the
            // aircraft is already inside/near that exact FIR boundary.
            if (Regex.IsMatch(id, @"^KZ[A-Z0-9]{2}$"))
            {
                AddPrefix(id.Substring(1));
            }

            // Aliases are only used after the aircraft/DEP airport position is inside
            // the exact FIR polygon. They are not standalone prefix shortcuts.
            switch (id)
            {
                case "EGTT":
                    AddPrefix("LON");
                    AddPrefix("MAN");
                    break;
                case "EGPX":
                    AddPrefix("SCO");
                    break;
                case "EISN":
                    AddPrefix("SNN");
                    AddPrefix("SHA");
                    break;
            }

            foreach (string token in (name + " " + searchText).Split(new[] { ' ', ',', ';', '/', '|', '_' }, StringSplitOptions.RemoveEmptyEntries))
            {
                string cleanToken = token.Trim().ToUpperInvariant();
                if (cleanToken.Length >= 4)
                {
                    AddPrefix(cleanToken);

                    if (Regex.IsMatch(cleanToken, @"^KZ[A-Z0-9]{2}$"))
                    {
                        AddPrefix(cleanToken.Substring(1));
                    }
                }
                else if (Regex.IsMatch(cleanToken, @"^Z[A-Z0-9]{2}$"))
                {
                    AddPrefix(cleanToken);
                }
            }

            foreach (string derivedPrefix in GetFirNameDerivedPrefixes(name + " " + searchText))
            {
                AddPrefix(derivedPrefix);
            }

            foreach (string scopedUsPrefix in GetBoundaryScopedUsArtccLivePrefixes(id))
            {
                AddPrefix(scopedUsPrefix);
            }

            return prefixes;
        }

        private static bool CallsignStartsWithFirPrefix(string callsign, string prefix)
        {
            string upper = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string cleanPrefix = (prefix ?? string.Empty).Trim().ToUpperInvariant();

            return !string.IsNullOrWhiteSpace(cleanPrefix) &&
                   (string.Equals(upper, cleanPrefix, StringComparison.OrdinalIgnoreCase) ||
                    upper.StartsWith(cleanPrefix + "_", StringComparison.OrdinalIgnoreCase));
        }

        private static bool ControllerMatchesFirStrict(string callsign, string info, FirBoundaryFeature fir)
        {
            if (fir == null)
            {
                return false;
            }

            string upperInfo = (info ?? string.Empty).Trim().ToUpperInvariant();
            string name = (fir.Name ?? string.Empty).Trim().ToUpperInvariant();

            foreach (string prefix in GetStrictFirControllerPrefixes(fir))
            {
                if (CallsignStartsWithFirPrefix(callsign, prefix) ||
                    (!string.IsNullOrWhiteSpace(upperInfo) &&
                     Regex.IsMatch(upperInfo, @"\b" + Regex.Escape(prefix) + @"\b")))
                {
                    return true;
                }
            }

            if (!string.IsNullOrWhiteSpace(name) && upperInfo.Contains(name))
            {
                return true;
            }

            // If the controller ATIS/info contains the FIR radio/city name, accept it
            // only after the aircraft is already inside/near that exact FIR boundary.
            // Example: KZDV boundary name contains DENVER, controller DEN_17_CTR info
            // may say DENVER CENTER.
            foreach (Match match in Regex.Matches(name + " " + (fir.SearchText ?? string.Empty), @"\b[A-Z]{5,}\b"))
            {
                string token = match.Value.Trim().ToUpperInvariant();
                if (!IsGenericFirNameWord(token) && upperInfo.Contains(token))
                {
                    return true;
                }
            }

            return false;
        }
        private List<string> GetFlightPlanRouteFirCodesForCpdlc()
        {
            List<string> firs = new();
            string remarks = userVATSIMData?.flight_plan?.remarks ?? string.Empty;

            void AddFir(string value)
            {
                string clean = (value ?? string.Empty).Trim().ToUpperInvariant();
                if (Regex.IsMatch(clean, @"^[A-Z]{4}$") && !firs.Contains(clean, StringComparer.OrdinalIgnoreCase))
                {
                    firs.Add(clean);
                }
            }

            string upperRemarks = remarks.ToUpperInvariant();
            Match eetMatch = Regex.Match(upperRemarks, @"\bEET/(?<tail>.*)$");
            if (eetMatch.Success)
            {
                string tail = eetMatch.Groups["tail"].Value;

                // Stop at the next ICAO flight-plan field, e.g. SEL/, OPR/, RMK/, REG/.
                Match nextField = Regex.Match(tail, @"\s\b[A-Z]{2,5}/");
                if (nextField.Success)
                {
                    tail = tail.Substring(0, nextField.Index);
                }

                foreach (Match firToken in Regex.Matches(tail, @"\b(?<fir>[A-Z]{4})(?:\d{4})?\b"))
                {
                    AddFir(firToken.Groups["fir"].Value);
                }
            }

            // Also accept clearly filed FIR codes in the route string. This is not used
            // by itself to scan random ATC; the controller still has to match the code
            // and the Hoppie station must be online.
            string route = userVATSIMData?.flight_plan?.route ?? string.Empty;
            foreach (Match firToken in Regex.Matches(route.ToUpperInvariant(), @"\b(?<fir>[A-Z]{4})(?:\d{4})?\b"))
            {
                AddFir(firToken.Groups["fir"].Value);
            }

            return firs;
        }

        private static bool ControllerMatchesRouteFirCode(string callsign, string info, string code, string routeFir)
        {
            string fir = (routeFir ?? string.Empty).Trim().ToUpperInvariant();
            if (!Regex.IsMatch(fir, @"^[A-Z]{4}$"))
            {
                return false;
            }

            string upperCallsign = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string upperInfo = (info ?? string.Empty).Trim().ToUpperInvariant();
            string upperCode = (code ?? string.Empty).Trim().ToUpperInvariant();

            return string.Equals(upperCode, fir, StringComparison.OrdinalIgnoreCase) ||
                   CallsignStartsWithFirPrefix(upperCallsign, fir) ||
                   Regex.IsMatch(upperInfo, @"\b" + Regex.Escape(fir) + @"\b");
        }

        private static bool FirBoundaryMatchesRouteFirCode(FirBoundaryFeature fir, string routeFir)
        {
            if (fir == null)
            {
                return false;
            }

            string target = (routeFir ?? string.Empty).Trim().ToUpperInvariant();
            if (!Regex.IsMatch(target, @"^[A-Z]{4}$"))
            {
                return false;
            }

            string haystack = ((fir.Id ?? string.Empty) + " " + (fir.Name ?? string.Empty) + " " + (fir.SearchText ?? string.Empty)).ToUpperInvariant();
            return Regex.IsMatch(haystack, @"\b" + Regex.Escape(target) + @"\b") ||
                   string.Equals((fir.Id ?? string.Empty).Trim(), target, StringComparison.OrdinalIgnoreCase);
        }

        private bool IsRouteFirCandidateRelevant(string routeFir, List<string> routeFirs, IEnumerable<FirBoundaryFeature> currentFirs)
        {
            if (routeFirs == null || routeFirs.Count == 0)
            {
                return false;
            }

            int candidateIndex = routeFirs.FindIndex(fir => string.Equals(fir, routeFir, StringComparison.OrdinalIgnoreCase));
            if (candidateIndex < 0)
            {
                return false;
            }

            int currentIndex = -1;
            foreach (FirBoundaryFeature fir in currentFirs ?? Enumerable.Empty<FirBoundaryFeature>())
            {
                for (int index = 0; index < routeFirs.Count; index++)
                {
                    if (FirBoundaryMatchesRouteFirCode(fir, routeFirs[index]))
                    {
                        currentIndex = currentIndex < 0 ? index : Math.Min(currentIndex, index);
                    }
                }
            }

            if (currentIndex >= 0)
            {
                // Show the current route FIR and the next two route FIRs. This catches
                // LSZH-LHBP around Salzburg: after/near LOVV, LHCC is the next planned FIR.
                return candidateIndex >= currentIndex && candidateIndex <= currentIndex + 2;
            }

            string arrival = userVATSIMData?.flight_plan?.arrival?.Trim().ToUpperInvariant() ?? string.Empty;
            if (arrival.Length == 4 && routeFir.StartsWith(arrival.Substring(0, 2), StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            // Short regional routes often only contain a few FIRs in EET. Showing those
            // filed-route centers is still safer than scanning arbitrary online ATC.
            return routeFirs.Count <= 4;
        }

        private bool TryGetRouteFirCpdlcMatch(string callsign, string info, string code, IEnumerable<FirBoundaryFeature> currentFirs, out string matchReason)
        {
            matchReason = string.Empty;
            List<string> routeFirs = GetFlightPlanRouteFirCodesForCpdlc();

            foreach (string routeFir in routeFirs)
            {
                if (!ControllerMatchesRouteFirCode(callsign, info, code, routeFir))
                {
                    continue;
                }

                if (!IsRouteFirCandidateRelevant(routeFir, routeFirs, currentFirs))
                {
                    Logger.Debug("CPDLC route FIR candidate " + callsign + " / " + code + " ignored: " + routeFir + " is filed but not current/upcoming enough.");
                    continue;
                }

                matchReason = "flight plan route FIR " + routeFir;
                return true;
            }

            if (TryGetDestinationCountryCenterCpdlcMatch(callsign, code, out string destinationReason))
            {
                matchReason = destinationReason;
                return true;
            }

            return false;
        }



        private static bool IsCenterLikeController(Controller controller)
        {
            return IsCenterLikeControllerCallsign(controller?.callsign);
        }

        private static bool IsCpdlcDiscoveryController(Controller controller)
        {
            string callsign = (controller?.callsign ?? string.Empty).Trim().ToUpperInvariant();
            return IsCenterLikeControllerCallsign(callsign) || IsAppLikeControllerCallsign(callsign);
        }

        private static string GetControllerInfoText(Controller controller)
        {
            if (controller?.text_atis == null || controller.text_atis.Length == 0)
            {
                return string.Empty;
            }

            return string.Join(" ", controller.text_atis)
                .Replace("\r", " ")
                .Replace("\n", " ")
                .Trim()
                .ToUpperInvariant();
        }

        private static bool ContainsCpdlcDiscoveryKeyword(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            string upper = text.ToUpperInvariant();

            // CPDLC WATCH is only for real CPDLC/FANS/Hoppie logon capability.
            // Do not treat normal controller ATIS text, PDC/DCL clearance text, or
            // "Estimated Logoff Time" as a CPDLC logon advertisement.
            return Regex.IsMatch(upper, @"\bCPDLC\b") ||
                   Regex.IsMatch(upper, @"\bHOPPIE\b") ||
                   Regex.IsMatch(upper, @"\bLOGON\b") ||
                   Regex.IsMatch(upper, @"\bDATALINK\b") ||
                   Regex.IsMatch(upper, @"\bDATA\s+LINK\b") ||
                   Regex.IsMatch(upper, @"\bACARS\b") ||
                   Regex.IsMatch(upper, @"\bFANS\b");
        }

        private string GetOnlineHoppieCodeFromControllerCallsign(string callsign)
        {
            string upper = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            if (string.IsNullOrWhiteSpace(upper))
            {
                return string.Empty;
            }

            string prefix = upper.Split('_').FirstOrDefault() ?? string.Empty;
            prefix = Regex.Replace(prefix, @"[^A-Z0-9]", string.Empty);

            if (IsPossibleHoppieLogonCode(prefix) && IsHoppieLogonOnline(prefix))
            {
                return prefix;
            }

            return string.Empty;
        }

        private bool TryGetDestinationCountryCenterCpdlcMatch(string callsign, string code, out string matchReason)
        {
            matchReason = string.Empty;

            string arrival = userVATSIMData?.flight_plan?.arrival?.Trim().ToUpperInvariant() ?? string.Empty;
            if (arrival.Length != 4 || userVATSIMData == null || !IsAirborneNowForPhase())
            {
                return false;
            }

            // Do not show far-ahead destination ACC while still in obvious departure climbout.
            if (IsPilotLikelyInDepartureClimbout(userVATSIMData))
            {
                return false;
            }

            string countryPrefix = arrival.Substring(0, 2);
            string upperCallsign = (callsign ?? string.Empty).Trim().ToUpperInvariant();
            string upperCode = (code ?? string.Empty).Trim().ToUpperInvariant();
            string callsignPrefix = upperCallsign.Split('_').FirstOrDefault() ?? string.Empty;

            bool matchesDestinationCountry =
                upperCode.StartsWith(countryPrefix, StringComparison.OrdinalIgnoreCase) ||
                callsignPrefix.StartsWith(countryPrefix, StringComparison.OrdinalIgnoreCase);

            if (!matchesDestinationCountry)
            {
                return false;
            }

            // This is only a CTR/FSS fallback and still requires the derived/parsed
            // Hoppie code to be online. It does not apply to APP ATIS text.
            if (string.IsNullOrWhiteSpace(upperCode) || !IsHoppieLogonOnline(upperCode))
            {
                return false;
            }

            matchReason = "destination FIR/country " + countryPrefix + " for " + arrival;
            return true;
        }

        private string ExtractAnyOnlineHoppieLogonCodeFromText(string text)
        {
            if (string.IsNullOrWhiteSpace(text) || !ContainsCpdlcDiscoveryKeyword(text))
            {
                return string.Empty;
            }

            string upper = text.ToUpperInvariant();

            // Safety first: never scan arbitrary ATIS text or URLs for any 4-letter
            // online Hoppie token. The token must be explicitly tied to CPDLC/Hoppie/
            // ACARS/FANS/logon wording.
            string[] labelledPatterns =
            {
                @"\b(?:CPDLC|HOPPIE|LOGON|DATALINK|DATA\s+LINK|ACARS|FANS)\b[^A-Z0-9]{0,12}([A-Z0-9]{4})\b",
                @"\b(?:CPDLC|HOPPIE|LOGON|DATALINK|DATA\s+LINK|ACARS|FANS)\b[^\[]*\[([A-Z0-9]{4})\]",
                @"\[([A-Z0-9]{4})\][^\[]*\b(?:CPDLC|HOPPIE|LOGON|DATALINK|DATA\s+LINK|ACARS|FANS)\b"
            };

            foreach (string pattern in labelledPatterns)
            {
                foreach (Match match in Regex.Matches(upper, pattern))
                {
                    string token = match.Groups[1].Value.Trim().ToUpperInvariant();

                    if (IsPossibleHoppieLogonCode(token) && IsHoppieLogonOnline(token))
                    {
                        Logger.Debug("CPDLC labelled online-token fallback parsed: " + token);
                        return token;
                    }
                }
            }

            return string.Empty;
        }

        private string ExtractPdcDclLogonCode(string text, string preferredStation)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return string.Empty;
            }

            string upper = text.ToUpperInvariant();

            // PDC/DCL controller infos are not consistent. We need to accept:
            // DCL: LOGA
            // DCL LOGON LOGA
            // DCL LOGON CODE LOGA
            // PDC/DCL: LOGA
            // LOGA DCL
            // DCL [DOHA]
            // "Doha Radar" - DCL [DOHA]
            string[] pdcDclPatterns =
            {
                @"\b(?:PDC|DCL)\b[^\[]*\[([A-Z0-9]{4})\]",
                @"\[([A-Z0-9]{4})\][^\[]*\b(?:PDC|DCL)\b",
                @"\b(?:PDC|DCL)\b(?:[\s:/=\-]+(?:PDC|DCL|LOGON|CODE|HOPPIE|ACARS|VIA|USE|STATION|CALLSIGN|IS|AVAILABLE|AVBL))*[\s:/=\-]+([A-Z0-9]{4})\b",
                @"\b(?:PREDEP(?:ARTURE)?\s*CLEARANCE|DEPARTURE\s*CLEARANCE|DATALINK\s*CLEARANCE)\b(?:[\s:/=\-]+(?:LOGON|CODE|HOPPIE|ACARS|VIA|USE|STATION|CALLSIGN))*[\s:/=\-]+([A-Z0-9]{4})\b",
                @"\b([A-Z0-9]{4})\b[\s:/=\-]+(?:PDC|DCL)\b"
            };

            foreach (string pattern in pdcDclPatterns)
            {
                foreach (Match match in Regex.Matches(upper, pattern))
                {
                    string code = match.Groups[1].Value.Trim().ToUpperInvariant();

                    if (IsPossibleHoppieLogonCode(code))
                    {
                        Logger.Debug("PDC/DCL logon parsed: " + code + " from controller info.");
                        return code;
                    }
                }
            }

            string station = (preferredStation ?? string.Empty).Trim().ToUpperInvariant();

            if (station.Length == 4 &&
                IsPdcDclInfoText(upper) &&
                IsHoppieLogonOnline(station))
            {
                Logger.Debug("PDC/DCL logon fallback to station: " + station);
                return station;
            }

            // Final fallback: old generic parser. This keeps older CPDLC/Hoppie wording working.
            string generic = ExtractCpdlcLogonCode(text, preferredStation);
            if (!string.IsNullOrWhiteSpace(generic))
            {
                Logger.Debug("PDC/DCL logon parsed by generic fallback: " + generic);
            }

            return generic;
        }

        private static bool IsPdcDclInfoText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            string upper = text.ToUpperInvariant();
            return upper.Contains("PDC") ||
                   upper.Contains("DCL") ||
                   upper.Contains("PREDEP CLEARANCE") ||
                   upper.Contains("PREDEPARTURE CLEARANCE") ||
                   upper.Contains("DEPARTURE CLEARANCE") ||
                   upper.Contains("DATALINK CLEARANCE");
        }

        private string ExtractCpdlcLogonCode(string text, string preferredStation)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return string.Empty;
            }

            string upper = text.ToUpperInvariant();

            // VATGER/Eurocenter style often advertises CPDLC like:
            // "CPDLC above FL315 [EDMZ]". The old parser did not understand
            // bracketed logon codes, so the active-frequency check could never
            // verify stations such as EDMM_ZUG_CTR -> EDMZ.
            string[] bracketPatterns =
            {
                @"\b(?:CPDLC|HOPPIE|LOGON|ACARS|PDC|DCL)\b[^\[]*\[([A-Z0-9]{4})\]",
                @"\[([A-Z0-9]{4})\][^\[]*\b(?:CPDLC|HOPPIE|LOGON|ACARS|PDC|DCL)\b"
            };

            foreach (string pattern in bracketPatterns)
            {
                foreach (Match match in Regex.Matches(upper, pattern))
                {
                    string code = match.Groups[1].Value.Trim().ToUpperInvariant();

                    if (IsPossibleHoppieLogonCode(code))
                    {
                        return code;
                    }
                }
            }

            string[] patterns =
            {
                @"\b(?:PDC|DCL|CPDLC|HOPPIE|LOGON|LOGON\s*CODE|DATALINK|DATA\s*LINK|ACARS|FANS)\b(?:[\s:/=\-]+(?:PDC|DCL|CPDLC|HOPPIE|LOGON|CODE|ACARS|DATALINK|DATA|LINK|FANS|VIA|USE|STATION|CALLSIGN|IS|AVAILABLE|AVBL))*[\s:/=\-]+([A-Z0-9]{4})\b",
                @"\b([A-Z0-9]{4})\b[\s:/=\-]+(?:PDC|DCL|CPDLC|HOPPIE|LOGON|DATALINK|DATA\s*LINK|ACARS|FANS)\b"
            };

            foreach (string pattern in patterns)
            {
                foreach (Match match in Regex.Matches(upper, pattern))
                {
                    string code = match.Groups[1].Value.Trim().ToUpperInvariant();

                    if (IsPossibleHoppieLogonCode(code))
                    {
                        return code;
                    }
                }
            }

            string station = (preferredStation ?? string.Empty).Trim().ToUpperInvariant();
            if (station.Length == 4 && ContainsCpdlcDiscoveryKeyword(upper) && IsHoppieLogonOnline(station))
            {
                return station;
            }

            return string.Empty;
        }

        private static bool IsPossibleHoppieLogonCode(string code)
        {
            if (string.IsNullOrWhiteSpace(code) || code.Length != 4)
            {
                return false;
            }

            string upper = code.ToUpperInvariant();
            string[] reserved =
            {
                "PDC", "DCL", "ATIS", "METR", "METAR", "INFO", "CODE",
                "LOGO", "LOGN", "NONE", "ONLY", "TEXT", "WITH", "FREE",
                "IFR", "VFR", "AUTO", "DATA", "LINK", "FREQ", "UNIC",
                "AVBL", "AVAI", "VIA", "USE", "STAN", "CALL"
            };

            return Regex.IsMatch(upper, "^[A-Z0-9]{4}$") && !reserved.Contains(upper);
        }

        private bool IsHoppieLogonOnline(string code)
        {
            if (DebugUiPreviewMode)
            {
                return !string.IsNullOrWhiteSpace(code) && IsPossibleHoppieLogonCode(code);
            }

            if (!hoppieOnlineStationsLoaded || string.IsNullOrWhiteSpace(code))
            {
                return false;
            }

            string upper = code.Trim().ToUpperInvariant();

            return hoppieOnlineStations.Any(station =>
            {
                string candidate = (station ?? string.Empty).Trim().ToUpperInvariant();
                return candidate == upper ||
                       candidate.StartsWith(upper + "_", StringComparison.Ordinal);
            });
        }




        private bool AreFirBoundariesReady()
        {
            return firBoundaryFeatures.Count > 0 &&
                   DateTime.UtcNow - firBoundaryLoadedUtc < firBoundaryCacheLifetime;
        }

        private async Task EnsureFirBoundariesLoadedAsync(bool force)
        {
            if (firBoundaryLoadInProgress)
            {
                return;
            }

            if (!force && AreFirBoundariesReady())
            {
                return;
            }

            firBoundaryLoadInProgress = true;

            try
            {
                if (!webclient.DefaultRequestHeaders.UserAgent.Any())
                {
                    webclient.DefaultRequestHeaders.UserAgent.ParseAdd("EasyCPDLC");
                }

                List<FirBoundaryFeature> merged = new();

                void AddUniqueBoundaries(IEnumerable<FirBoundaryFeature> source, string sourceName)
                {
                    foreach (FirBoundaryFeature item in source ?? Enumerable.Empty<FirBoundaryFeature>())
                    {
                        string id = (item.Id ?? string.Empty).Trim().ToUpperInvariant();
                        string name = (item.Name ?? string.Empty).Trim().ToUpperInvariant();

                        bool exists = merged.Any(existing =>
                            !string.IsNullOrWhiteSpace(id) &&
                            string.Equals((existing.Id ?? string.Empty).Trim().ToUpperInvariant(), id, StringComparison.OrdinalIgnoreCase));

                        if (!exists && string.IsNullOrWhiteSpace(id))
                        {
                            exists = merged.Any(existing =>
                                !string.IsNullOrWhiteSpace(name) &&
                                string.Equals((existing.Name ?? string.Empty).Trim().ToUpperInvariant(), name, StringComparison.OrdinalIgnoreCase));
                        }

                        if (!exists)
                        {
                            item.SearchText = ((item.SearchText ?? string.Empty) + " " + sourceName).Trim();
                            merged.Add(item);
                        }
                    }
                }

                try
                {
                    Logger.Debug("Loading VATSpy FIR/ARTCC boundaries in memory.");
                    string vatspyGeoJson = await webclient.GetStringAsync(VatspyBoundariesGeoJsonUrl);
                    List<FirBoundaryFeature> vatspy = ParseFirBoundaryGeoJson(vatspyGeoJson);
                    AddUniqueBoundaries(vatspy, "VATSPY_MEMORY");
                    Logger.Debug("Loaded VATSpy boundary features in memory: " + vatspy.Count);
                }
                catch (Exception ex)
                {
                    Logger.Debug("VATSpy in-memory boundary load failed: " + ex.Message);
                }

                // Fallback only if VATSpy could not be loaded at all.
                // This fallback is also in-memory only and is not written to disk.
                if (merged.Count == 0)
                {
                    try
                    {
                        Logger.Debug("Loading official VATSIM map_data FIR boundaries as in-memory fallback.");
                        string mapDataJson = await webclient.GetStringAsync(VatsimMapDataUrl);
                        JObject mapData = JObject.Parse(mapDataJson);
                        string geoJsonUrl = mapData["fir_boundaries_geojson_url"]?.ToString();

                        if (!string.IsNullOrWhiteSpace(geoJsonUrl))
                        {
                            string firGeoJson = await webclient.GetStringAsync(geoJsonUrl);
                            List<FirBoundaryFeature> official = ParseFirBoundaryGeoJson(firGeoJson);
                            AddUniqueBoundaries(official, "VATSIM_MAP_DATA_MEMORY");
                            Logger.Debug("Loaded VATSIM map_data boundary features in memory: " + official.Count);
                        }
                        else
                        {
                            Logger.Debug("VATSIM map_data returned no fir_boundaries_geojson_url.");
                        }
                    }
                    catch (Exception ex)
                    {
                        Logger.Debug("VATSIM map_data in-memory fallback load failed: " + ex.Message);
                    }
                }

                if (merged.Count > 0)
                {
                    ApplyFirBoundaryFeatures(merged, "in-memory boundary load");
                }
                else
                {
                    Logger.Debug("No FIR/ARTCC boundary features loaded in memory.");
                }
            }
            catch (Exception ex)
            {
                Logger.Debug("FIR boundary load failed: " + ex.Message);
            }
            finally
            {
                firBoundaryLoadInProgress = false;
            }
        }

        private void ApplyFirBoundaryFeatures(IEnumerable<FirBoundaryFeature> features, string sourceText)
        {
            List<FirBoundaryFeature> list = (features ?? Enumerable.Empty<FirBoundaryFeature>())
                .Where(item => item != null && item.Polygons.Count > 0)
                .ToList();

            if (list.Count == 0)
            {
                return;
            }

            firBoundaryFeatures.Clear();
            firBoundaryFeatures.AddRange(list);
            firBoundaryLoadedUtc = DateTime.UtcNow;
            currentFirDebugText = "Loaded boundary features: " + firBoundaryFeatures.Count + " (" + sourceText + ")";
            Logger.Debug(currentFirDebugText);

            SafeUi(() =>
            {
                UpdateOnlineStatusLabel();
                UpdateCpdlcDiscoveryLabel();
            });
        }

        private List<FirBoundaryFeature> ParseFirBoundaryGeoJson(string geoJson)
        {
            List<FirBoundaryFeature> result = new();

            if (string.IsNullOrWhiteSpace(geoJson))
            {
                return result;
            }

            JObject root = JObject.Parse(geoJson);
            JArray features = root["features"] as JArray;

            if (features == null)
            {
                return result;
            }

            foreach (JToken feature in features)
            {
                try
                {
                    FirBoundaryFeature parsed = ParseFirBoundaryFeature(feature);
                    if (parsed != null && parsed.Polygons.Count > 0)
                    {
                        result.Add(parsed);
                    }
                }
                catch (Exception ex)
                {
                    Logger.Debug("Skipping FIR boundary feature: " + ex.Message);
                }
            }

            return result;
        }

        private FirBoundaryFeature ParseFirBoundaryFeature(JToken feature)
        {
            JToken properties = feature["properties"];
            JToken geometry = feature["geometry"];
            string type = geometry?["type"]?.ToString() ?? string.Empty;
            JToken coordinates = geometry?["coordinates"];

            if (coordinates == null)
            {
                return null;
            }

            FirBoundaryFeature parsed = new()
            {
                Id = GetFirProperty(properties, "id", "icao", "fir", "fir_id", "fir_icao", "ident", "prefix", "callsign", "boundary_id", "firId", "firID"),
                Name = GetFirProperty(properties, "name", "fir_name", "firname", "label", "description", "display_name", "firName", "fir_name_short")
            };

            parsed.SearchText = BuildFirSearchText(properties, parsed.Id, parsed.Name);

            if (string.Equals(type, "Polygon", StringComparison.OrdinalIgnoreCase))
            {
                GeoPolygon polygon = ParseGeoPolygon(coordinates);
                if (polygon != null)
                {
                    parsed.Polygons.Add(polygon);
                }
            }
            else if (string.Equals(type, "MultiPolygon", StringComparison.OrdinalIgnoreCase))
            {
                foreach (JToken polygonToken in coordinates.Children())
                {
                    GeoPolygon polygon = ParseGeoPolygon(polygonToken);
                    if (polygon != null)
                    {
                        parsed.Polygons.Add(polygon);
                    }
                }
            }

            if (string.IsNullOrWhiteSpace(parsed.Id) && !string.IsNullOrWhiteSpace(parsed.Name))
            {
                parsed.Id = parsed.Name.Length > 4 ? parsed.Name.Substring(0, 4).ToUpperInvariant() : parsed.Name.ToUpperInvariant();
            }

            return parsed;
        }

        private static string GetFirProperty(JToken properties, params string[] names)
        {
            if (properties == null)
            {
                return string.Empty;
            }

            List<JProperty> props = properties.Children<JProperty>().ToList();

            foreach (string name in names)
            {
                JProperty prop = props.FirstOrDefault(item =>
                    string.Equals(item.Name, name, StringComparison.OrdinalIgnoreCase));

                string value = prop?.Value?.ToString()?.Trim().ToUpperInvariant();

                if (!string.IsNullOrWhiteSpace(value))
                {
                    return NormalizeFirToken(value);
                }
            }

            return string.Empty;
        }

        private static string NormalizeFirToken(string value)
        {
            string upper = (value ?? string.Empty).Trim().ToUpperInvariant();

            Match usArtcc = Regex.Match(upper, @"\bKZ[A-Z0-9]{2}\b");
            if (usArtcc.Success)
            {
                return usArtcc.Value;
            }

            Match usShort = Regex.Match(upper, @"\bZ[A-Z0-9]{2}\b");
            if (usShort.Success)
            {
                return usShort.Value;
            }

            Match match = Regex.Match(upper, @"\b[A-Z]{2}[A-Z0-9]{2}\b");
            if (match.Success)
            {
                return match.Value;
            }

            return upper;
        }

        private static string BuildFirSearchText(JToken properties, string id, string name)
        {
            List<string> parts = new();

            if (!string.IsNullOrWhiteSpace(id))
            {
                parts.Add(id.Trim().ToUpperInvariant());
            }

            if (!string.IsNullOrWhiteSpace(name))
            {
                parts.Add(name.Trim().ToUpperInvariant());
            }

            if (properties != null)
            {
                foreach (JProperty prop in properties.Children<JProperty>())
                {
                    string value = prop.Value?.ToString()?.Trim().ToUpperInvariant();
                    if (!string.IsNullOrWhiteSpace(value) && value.Length <= 80)
                    {
                        parts.Add(value);
                    }
                }
            }

            return string.Join(" ", parts.Distinct());
        }

        private GeoPolygon ParseGeoPolygon(JToken polygonToken)
        {
            GeoPolygon polygon = new();

            foreach (JToken ringToken in polygonToken.Children())
            {
                List<GeoPoint> ring = new();

                foreach (JToken pointToken in ringToken.Children())
                {
                    if (pointToken is not JArray pair || pair.Count < 2)
                    {
                        continue;
                    }

                    double lon = pair[0]?.Value<double>() ?? 0;
                    double lat = pair[1]?.Value<double>() ?? 0;

                    ring.Add(new GeoPoint { Lat = lat, Lon = lon });

                    polygon.MinLat = Math.Min(polygon.MinLat, lat);
                    polygon.MaxLat = Math.Max(polygon.MaxLat, lat);
                    polygon.MinLon = Math.Min(polygon.MinLon, lon);
                    polygon.MaxLon = Math.Max(polygon.MaxLon, lon);
                }

                if (ring.Count >= 3)
                {
                    polygon.Rings.Add(ring);
                }
            }

            return polygon.Rings.Count == 0 ? null : polygon;
        }

        private List<FirBoundaryFeature> GetCurrentFirBoundaryMatches()
        {
            Pilot pilot = userVATSIMData;

            if (pilot == null)
            {
                return new List<FirBoundaryFeature>();
            }

            return GetFirBoundaryMatchesForPosition(pilot.latitude, pilot.longitude);
        }

        private List<FirBoundaryFeature> GetFirBoundaryMatchesForPosition(double lat, double lon)
        {
            List<FirBoundaryFeature> exact = new();
            List<FirBoundaryFeature> nearby = new();

            if (firBoundaryFeatures.Count == 0)
            {
                return exact;
            }

            foreach (FirBoundaryFeature fir in firBoundaryFeatures)
            {
                fir.IsNearbyCandidate = false;
                fir.DistanceNmFromAircraft = 0;

                bool inside = false;
                double bestDistanceNm = double.MaxValue;

                foreach (GeoPolygon polygon in fir.Polygons)
                {
                    if (PointInGeoPolygon(lat, lon, polygon))
                    {
                        inside = true;
                        bestDistanceNm = 0;
                        break;
                    }

                    double distanceNm = DistanceNmToGeoPolygon(lat, lon, polygon);
                    if (distanceNm < bestDistanceNm)
                    {
                        bestDistanceNm = distanceNm;
                    }
                }

                if (inside)
                {
                    exact.Add(fir);
                    continue;
                }

                double nearbyRadius = exact.Count > 0 ? FirNearbyRadiusWhenInsideNm : FirNearbyRadiusNm;
                if (bestDistanceNm <= nearbyRadius)
                {
                    fir.IsNearbyCandidate = true;
                    fir.DistanceNmFromAircraft = bestDistanceNm;
                    nearby.Add(fir);
                }
            }

            return exact
                .Concat(nearby.OrderBy(item => item.DistanceNmFromAircraft).Take(4))
                .Distinct()
                .ToList();
        }

        private static string GetFirDisplayName(FirBoundaryFeature fir)
        {
            if (fir == null)
            {
                return "UNKNOWN";
            }

            string id = (fir.Id ?? string.Empty).Trim().ToUpperInvariant();
            string name = (fir.Name ?? string.Empty).Trim().ToUpperInvariant();

            if (!string.IsNullOrWhiteSpace(id))
            {
                return fir.IsNearbyCandidate && fir.DistanceNmFromAircraft > 0
                    ? id + " near"
                    : id;
            }

            if (!string.IsNullOrWhiteSpace(name))
            {
                return fir.IsNearbyCandidate && fir.DistanceNmFromAircraft > 0
                    ? name + " near"
                    : name;
            }

            return "UNKNOWN";
        }

        private static bool PointInGeoPolygon(double lat, double lon, GeoPolygon polygon)
        {
            if (polygon == null || polygon.Rings.Count == 0)
            {
                return false;
            }

            if (lat < polygon.MinLat || lat > polygon.MaxLat || lon < polygon.MinLon || lon > polygon.MaxLon)
            {
                return false;
            }

            if (!PointInRing(lat, lon, polygon.Rings[0]))
            {
                return false;
            }

            // Inner rings are holes.
            for (int index = 1; index < polygon.Rings.Count; index++)
            {
                if (PointInRing(lat, lon, polygon.Rings[index]))
                {
                    return false;
                }
            }

            return true;
        }

        private static bool PointInRing(double lat, double lon, List<GeoPoint> ring)
        {
            bool inside = false;

            for (int i = 0, j = ring.Count - 1; i < ring.Count; j = i++)
            {
                double yi = ring[i].Lat;
                double yj = ring[j].Lat;
                double xi = ring[i].Lon;
                double xj = ring[j].Lon;

                bool intersect = ((yi > lat) != (yj > lat)) &&
                                 (lon < (xj - xi) * (lat - yi) / ((yj - yi) == 0 ? double.Epsilon : (yj - yi)) + xi);

                if (intersect)
                {
                    inside = !inside;
                }
            }

            return inside;
        }

        private static double DistanceNmToGeoPolygon(double lat, double lon, GeoPolygon polygon)
        {
            return DistanceNmToGeoPolygon(lat, lon, polygon, FirNearbyRadiusNm);
        }

        private static double DistanceNmToGeoPolygon(double lat, double lon, GeoPolygon polygon, double paddingRadiusNm)
        {
            if (polygon == null || polygon.Rings.Count == 0)
            {
                return double.MaxValue;
            }

            // Quick bounding-box skip with a generous degree conversion.
            double paddingDeg = Math.Max(FirNearbyRadiusNm, paddingRadiusNm) / 60.0 + 0.3;
            if (lat < polygon.MinLat - paddingDeg ||
                lat > polygon.MaxLat + paddingDeg ||
                lon < polygon.MinLon - paddingDeg ||
                lon > polygon.MaxLon + paddingDeg)
            {
                return double.MaxValue;
            }

            double best = double.MaxValue;

            foreach (List<GeoPoint> ring in polygon.Rings)
            {
                for (int i = 0, j = ring.Count - 1; i < ring.Count; j = i++)
                {
                    double distance = DistanceNmPointToSegment(lat, lon, ring[j].Lat, ring[j].Lon, ring[i].Lat, ring[i].Lon);
                    if (distance < best)
                    {
                        best = distance;
                    }
                }
            }

            return best;
        }

        private static double DistanceNmPointToSegment(double lat, double lon, double lat1, double lon1, double lat2, double lon2)
        {
            // Local equirectangular projection in NM. Good enough for nearby FIR-boundary buffering.
            double meanLatRad = DegreesToRadians((lat + lat1 + lat2) / 3.0);
            double px = lon * Math.Cos(meanLatRad) * 60.0;
            double py = lat * 60.0;
            double ax = lon1 * Math.Cos(meanLatRad) * 60.0;
            double ay = lat1 * 60.0;
            double bx = lon2 * Math.Cos(meanLatRad) * 60.0;
            double by = lat2 * 60.0;

            double dx = bx - ax;
            double dy = by - ay;

            if (Math.Abs(dx) < 0.000001 && Math.Abs(dy) < 0.000001)
            {
                return Math.Sqrt(Math.Pow(px - ax, 2) + Math.Pow(py - ay, 2));
            }

            double t = ((px - ax) * dx + (py - ay) * dy) / (dx * dx + dy * dy);
            t = Math.Max(0, Math.Min(1, t));

            double closestX = ax + t * dx;
            double closestY = ay + t * dy;

            return Math.Sqrt(Math.Pow(px - closestX, 2) + Math.Pow(py - closestY, 2));
        }

        private static double DegreesToRadians(double degrees)
        {
            return degrees * Math.PI / 180.0;
        }

        private static int GetCpdlcCandidateSortScore(CpdlcDiscoveryResult candidate)
        {
            if (candidate?.IsTunedFrequencyMatch == true)
            {
                return 0;
            }

            string reason = (candidate?.MatchReason ?? string.Empty).ToUpperInvariant();

            if (reason.Contains("APP STATION") || reason.Contains("APP MATCHES"))
            {
                return 1;
            }

            if (reason.Contains("VATSPY BOUNDARY POSITION MATCH") ||
                reason.Contains("MAP BOUNDARY POSITION MATCH") ||
                reason.Contains("VATGLASSES FALLBACK SECTOR MATCH") ||
                reason.Contains("VATGLASSES SECTOR MATCH") ||
                reason.Contains("FIR POSITION MATCH") ||
                reason.Contains("APP REGIONAL FIR MATCH"))
            {
                return 2;
            }

            if (reason.Contains("UPCOMING VATSPY BOUNDARY MATCH") ||
                reason.Contains("UPCOMING MAP BOUNDARY MATCH") ||
                reason.Contains("VATGLASSES FALLBACK SECTOR NEARBY") ||
                reason.Contains("VATGLASSES SECTOR NEARBY") ||
                reason.Contains("NEAR FIR BUFFER MATCH") ||
                reason.Contains("APP NEAR FIR BUFFER"))
            {
                return 3;
            }

            if (reason.Contains("FLIGHT PLAN ROUTE FIR"))
            {
                return 4;
            }

            if (reason.Contains("INFO MENTIONS"))
            {
                return 4;
            }

            if (reason.Contains("PREFIX"))
            {
                return 5;
            }

            return 4;
        }

