            {
                actionLabel.ForeColor = MainPrimaryTextColor();
                actionLabel.Text = normalCaption;
            };
            actionLabel.Click += async (_, __) =>
            {
                HideCpdlcLogonPopup();
                await QuickCpdlcLogonAsync(cleanCode);
