        private const string ELoadControlApiKeySettingName = "ELoadControlApiKey";

        public static string SavedELoadControlApiKey
        {
            get
            {
                string storedValue = ReadFixedStringSetting(ELoadControlApiKeySettingName, string.Empty);
                return TryReadProtectedSetting(storedValue, "eLoadControl API key", out string decryptedValue)
                    ? decryptedValue
                    : string.Empty;
            }
            set
            {
                string cleanedValue = (value ?? string.Empty).Trim();
                if (cleanedValue.Length == 0)
                {
                    SaveFixedStringSetting(ELoadControlApiKeySettingName, string.Empty);
                    return;
                }

                if (!TryProtectStringForCurrentUser(cleanedValue, out string protectedValue))
                {
                    throw new InvalidOperationException("WINDOWS COULD NOT SECURELY SAVE THE ELOADCONTROL API KEY.");
                }

                string storedValue = DpapiProtectedSettingPrefix + protectedValue;
                SaveFixedStringSetting(ELoadControlApiKeySettingName, storedValue);
                if (!string.Equals(ReadFixedStringSetting(ELoadControlApiKeySettingName, string.Empty), storedValue, StringComparison.Ordinal))
                {
                    throw new InvalidOperationException("ELOADCONTROL API KEY COULD NOT BE SAVED TO THE USER PROFILE.");
                }
            }
        }

        private static DatalinkPrinterMode PrinterMode
        {
            get
            {
                string value = ReadFixedStringSetting(PrinterModeSettingName, "ESC/POS");
                if (value.Contains("MOCK", StringComparison.OrdinalIgnoreCase) || value.Contains("FILE", StringComparison.OrdinalIgnoreCase))
                {
                    return DatalinkPrinterMode.MockFile;
                }
                return value.Contains("ESC", StringComparison.OrdinalIgnoreCase)
                    ? DatalinkPrinterMode.RawEscPos
                    : DatalinkPrinterMode.Windows;
            }
            set
            {
                string stored = value switch
                {
                    DatalinkPrinterMode.RawEscPos => "ESC/POS",
                    DatalinkPrinterMode.MockFile => "MOCK FILE",
                    _ => "WINDOWS"
                };
                SaveFixedStringSetting(PrinterModeSettingName, stored);
            }
        }

        public static string SelectedPrinterName
        {
            get => ReadFixedStringSetting(PrinterNameSettingName, string.Empty).Trim();
            set => SaveFixedStringSetting(PrinterNameSettingName, (value ?? string.Empty).Trim());
        }

        private static DatalinkPrinterProfile PrinterProfile
        {
            get
            {
                string value = ReadFixedStringSetting(PrinterProfileSettingName, "CITIZEN CT-S4000 112MM");
                return value.Contains("80", StringComparison.OrdinalIgnoreCase) ||
                    value.Contains("RONGTA", StringComparison.OrdinalIgnoreCase) ||
                    value.Contains("GENERIC", StringComparison.OrdinalIgnoreCase)
                    ? DatalinkPrinterProfile.GenericEscPos80Mm
                    : DatalinkPrinterProfile.CitizenCtS4000_112Mm;
            }
            set
            {
                SaveFixedStringSetting(PrinterProfileSettingName, DatalinkPrinter.GetProfileDisplayName(value));
                PrinterColumns = DatalinkPrinter.GetNormalColumns(value);
            }
        }

        public static int PrinterColumns
        {
            get
            {
                int fallback = DatalinkPrinter.GetNormalColumns(PrinterProfile);
                string stored = ReadFixedStringSetting(PrinterColumnsSettingName, fallback.ToString(System.Globalization.CultureInfo.InvariantCulture));
                return NormalizePrinterColumns(stored, PrinterProfile);
            }
            set => SaveFixedStringSetting(
                PrinterColumnsSettingName,
                DatalinkPrinter.NormalizeProfileColumns(PrinterProfile, value).ToString(System.Globalization.CultureInfo.InvariantCulture));
        }

