        private static bool IsHoppieNetworkLoadResponse(string response)
        {
            string upper = (response ?? string.Empty).Trim().ToUpperInvariant();

            return upper.Contains("TOO HEAVY") ||
                   upper.Contains("HEAVY ON THE NETWORK") ||
                   upper.Contains("TOO MANY REQUESTS") ||
                   upper.Contains("RATE LIMIT");
        }

        private void HandleHoppieNetworkLoadResponse(string response)
        {
            hoppiePollPausedUntilUtc = DateTime.UtcNow + hoppieNetworkLoadBackoff;

            if (DateTime.UtcNow - lastHoppieNetworkLoadWarningUtc < TimeSpan.FromSeconds(60))
            {
                return;
            }

            lastHoppieNetworkLoadWarningUtc = DateTime.UtcNow;
            Logger.Debug("Hoppie network load/backoff response: " + SafeLogValue(response, 96));
            SafeUi(() => WriteMessage("HOPPIE SERVER RATE LIMIT: TOO HEAVY ON THE NETWORK. EASYCPDLC WILL BACK OFF BRIEFLY AND TRY AGAIN.", "SYSTEM", "SYSTEM"));
        }

        private async Task PeriodicCheckMessage(TimeSpan interval, CancellationToken cancellationToken)
        {
            try
            {
                // Do not poll Hoppie immediately after connect. Login/setup already
                // performs VATSIM/Hoppie helper refreshes and the user may click LOGON.
                await Task.Delay(hoppieInitialPollDelay, cancellationToken);
            }
            catch (TaskCanceledException)
            {
                return;
            }

            while (!cancellationToken.IsCancellationRequested)
            {
                if (DateTime.UtcNow < hoppiePollPausedUntilUtc)
                {
                    TimeSpan pauseRemaining = hoppiePollPausedUntilUtc - DateTime.UtcNow;
                    TimeSpan delay = pauseRemaining < interval ? pauseRemaining : interval;

                    Logger.Debug("Hoppie poll delayed by explicit server backoff for " + (int)Math.Max(0, delay.TotalMilliseconds) + "ms");

                    try
                    {
                        await Task.Delay(delay, cancellationToken);
                    }
                    catch (TaskCanceledException)
                    {
                        break;
                    }

                    continue;
                }

                Logger.Debug("Attempting to poll Hoppie for new messages");

                await SendCPDLCMessage("NONE", "poll", "");

                try
                {
                    await Task.Delay(interval, cancellationToken);
                }
                catch (TaskCanceledException)
                {
                    break;
                }

                if (UseFSUIPC && fsConnectionOpen)
                {
                    try
                    {
                        await fsuipc.RefreshData();
                        fsuipcErrorCount = 1;
                    }
                    catch (FSUIPCException)
                    {
                        if (fsuipcErrorCount <= 3)
                        {
                            try
                            {
                                fsConnectionOpen = FSUIPCData.OpenConnection();
                            }
                            catch { }
                            WriteMessage(String.Format("UNABLE TO CHECK FLIGHT SIM DATA. RETRYING (ATTEMPT {0} OF 3)", fsuipcErrorCount), "SYSTEM", "SYSTEM");
                            fsuipcErrorCount += 1;
                        }
                        else
                        {
                            WriteMessage("FLIGHT SIM DATA RETRIEVAL FAILED 3 TIMES CONSECUTIVELY. DISCONNECTING FROM FLIGHT SIM", "SYSTEM", "SYSTEM");
                            fsConnectionOpen = FSUIPCData.CloseConnection();
                            fsuipcErrorCount = 1;
                        }

                    }
                }

                await RefreshCurrentVatsimPilotDataForPhaseAsync();
                SafeUi(UpdateFlightPhaseBadge);
                await CheckForNextFlightPlanAfterArrivalAsync();

            }
        }
        private void SafeUi(Action action)
        {
            if (action == null || IsDisposed)
            {
                return;
            }

            try
            {
                if (IsHandleCreated && InvokeRequired)
                {
                    BeginInvoke(action);
                }
                else
                {
                    action();
                }
            }
            catch (ObjectDisposedException)
            {
                // The form is closing.
            }
            catch (InvalidOperationException)
            {
                // The form is closing or its handle is no longer available.
            }
        }

        private void UpdateSendingProgress(Action action)
        {
            SafeUi(() =>
            {
                if (SendingProgress != null && !SendingProgress.IsDisposed)
                {
                    action();
                }
            });
        }

        private static string SafeLogValue(string value, int maxLength = 48)
        {
            string cleaned = (value ?? string.Empty)
                .Replace("\r", " ")
                .Replace("\n", " ")
                .Trim();

            if (cleaned.Length <= maxLength)
            {
                return cleaned;
            }

            return cleaned.Substring(0, Math.Max(0, maxLength - 1)) + "…";
        }

        private static string ClassifyHoppieResponseForLog(string responseString)
        {
            string cleaned = (responseString ?? string.Empty).Trim().ToUpperInvariant();

            if (cleaned == "OK")
            {
                return "OK";
            }

            if (cleaned.Contains("ERROR"))
            {
                return "ERROR";
            }

            if (cleaned.StartsWith("{") || cleaned.Contains("/DATA", StringComparison.OrdinalIgnoreCase))
            {
                return "DATA";
            }

            return "OTHER";
        }

        public async Task SendCPDLCMessage(string recipient, string messageType, string packetData, bool _write = true)
        {
            var connectionValues = new Dictionary<string, string> {
                {"logon", logonCode ?? String.Empty},
                {"from", callsign ?? String.Empty},
                {"to", recipient ?? String.Empty},
                {"type", messageType ?? String.Empty},
                {"packet", packetData ?? String.Empty}
            };

            var content = new FormUrlEncodedContent(connectionValues);

            if (DebugUiPreviewMode)
            {
                if (_write && messageType != "poll")
                {
                    string previewText = messageType == "CPDLC"
                        ? (packetData ?? string.Empty).Split('/').LastOrDefault() ?? string.Empty
                        : packetData ?? string.Empty;
                    WriteMessage("UI PREVIEW - NOT SENT: " + previewText, messageType, recipient, true);
                }

                Logger.Debug(String.Format("DEBUG UI PREVIEW: suppressed outbound packet to={0} | type={1} | packetLen={2}", SafeLogValue(recipient), SafeLogValue(messageType), (packetData ?? string.Empty).Length));
                UpdateSendingProgress(() => SendingProgress.Visible = false);
                return;
            }

            try
            {

                if (_write && messageType != "poll")
                {
                    UpdateSendingProgress(() => SendingProgress.Visible = true);
                    UpdateSendingProgress(() => SendingProgress.Value = 0);
                    UpdateSendingProgress(() => SendingProgress.PerformStep());
                }

                var response = await webclient.PostAsync(HoppieConnectUrl, content);

                UpdateSendingProgress(() => SendingProgress.PerformStep());

                Logger.Debug(String.Format("PACKET SENT: to={0} | type={1} | packetLen={2} | write={3}", SafeLogValue(recipient), SafeLogValue(messageType), (packetData ?? string.Empty).Length, _write));
                var responseString = await response.Content.ReadAsStringAsync();
                string printString = responseString.ToString().ToUpper().Trim();
                Logger.Debug(String.Format("HOPPIE RESPONSE: status={0} | length={1}", ClassifyHoppieResponseForLog(responseString), (responseString ?? string.Empty).Length));

                if (IsHoppieNetworkLoadResponse(printString))
                {
                    HandleHoppieNetworkLoadResponse(printString);
                    UpdateSendingProgress(() => SendingProgress.Visible = false);
                    return;
                }

                if (printString.Contains("ERROR"))
                {
                    throw new HttpRequestException();
                }
                else
                {
                    if (isErrorState)
                    {
                        WriteMessage("HOPPIE CONNECTIVITY RESTORED.", "SYSTEM", "SYSTEM");
                        isErrorState = false;
                    }

                    UpdateSendingProgress(() => SendingProgress.PerformStep());

                    if (_write && messageType != "poll")
                    {
                        WriteMessage(messageType == "CPDLC" ? packetData.Split('/').Last() : packetData, messageType, recipient, true);
                    }
                }

                if (printString != "OK")
                {
                    await TelexParser(printString);
                }

                UpdateSendingProgress(() => SendingProgress.Visible = false);
            }

            catch (Exception e)
            {
                if (!isErrorState)
                {
                    Logger.Error(String.Format("{0}: {1}", e.GetType().FullName, e.Message));
                    WriteMessage("ERROR CHECKING FOR NEW MESSAGES. THIS IS LIKELY AN ERROR WITH THE HOPPIE NETWORK. THE SYSTEM WILL CONTINUE ATTEMPTING TO CONTACT THE SERVER AND LET YOU KNOW WHEN CONNECTION IS RE-ESTABLISHED.", "SYSTEM", "SYSTEM");
                    isErrorState = true;
                }
                UpdateSendingProgress(() => SendingProgress.Visible = false);
            }

            return;

        }
