        {
            string upperContents = contents?.Trim().ToUpperInvariant() ?? string.Empty;

            return upperContents.StartsWith("VATSIM CALLSIGN MISMATCH") ||
                   upperContents.StartsWith("CALLSIGN CHANGE PENDING");
        }

        private static Color CallsignMismatchAlarmColor()
        {
            return Color.FromArgb(255, 86, 74);
        }

        private static bool IsOpsMessageSender(string sender)
        {
            string clean = (sender ?? string.Empty).Trim().ToUpperInvariant();
            return clean.EndsWith("OPS", StringComparison.OrdinalIgnoreCase);
        }

        private static string BuildSystemListSummary(string contents)
        {
            string text = (contents ?? string.Empty)
                .Replace("\r\n", " ")
                .Replace("\r", " ")
                .Replace("\n", " ")
                .Replace("\t", " ")
                .Trim();

            text = Regex.Replace(text, @"\s+", " ");

            if (string.IsNullOrWhiteSpace(text))
            {
                return "SYSTEM MESSAGE";
            }

            text = text.ToUpperInvariant();

            if (text.Length > 54)
            {
                text = text.Substring(0, 54).TrimEnd();
            }

            return text;
        }

        private static string ExtractCpdlcPacketOverviewPayload(string contents)
        {
            string raw = (contents ?? string.Empty).Trim();

            if (string.IsNullOrWhiteSpace(raw))
            {
                return string.Empty;
            }

            Match packet = Regex.Match(
                raw,
                @"(?:^|\s)/data2/\d+/[^/\s]*/[A-Z]{1,2}/(?<payload>.*)$",
                RegexOptions.IgnoreCase | RegexOptions.Singleline);

            if (packet.Success)
            {
                string payload = packet.Groups["payload"].Value.Trim();
                if (!string.IsNullOrWhiteSpace(payload))
                {
                    return payload;
                }
            }

            if (raw.StartsWith("/data2/", StringComparison.OrdinalIgnoreCase))
            {
                int lastSlash = raw.LastIndexOf('/');
                if (lastSlash >= 0 && lastSlash + 1 < raw.Length)
                {
                    return raw.Substring(lastSlash + 1).Trim();
                }
            }

            return raw;
        }

        private static string NormalizeCpdlcOverviewText(string contents)
        {
            string source = ExtractCpdlcPacketOverviewPayload(contents);

            string clean = (source ?? string.Empty)
                .Replace("\r\n", " ")
                .Replace("\r", " ")
                .Replace("\n", " ")
                .Replace("@", " ")
                .Replace("_", " ")
                .Trim()
                .ToUpperInvariant();

            clean = Regex.Replace(clean, @"\s+", " ").Trim();
            return clean;
        }

        private static string ShortenOverviewText(string text, int maxChars)
        {
            string clean = Regex.Replace((text ?? string.Empty).Trim(), @"\s+", " ");

            if (clean.Length <= maxChars)
            {
                return clean;
            }

            return clean.Substring(0, Math.Max(1, maxChars - 1)).TrimEnd() + "…";
        }

        private static bool IsCpdlcReplyStatusText(string text)
        {
            string clean = NormalizeCpdlcOverviewText(text);

            if (clean.StartsWith("✓ ", StringComparison.OrdinalIgnoreCase))
            {
                clean = clean.Substring(2).Trim();
            }

            if (clean.EndsWith(" SENT", StringComparison.OrdinalIgnoreCase))
            {
                clean = clean.Substring(0, clean.Length - 5).Trim();
            }

            return clean == "WILCO" ||
                   clean == "UNABLE" ||
                   clean == "STANDBY" ||
                   clean == "STBY" ||
                   clean == "ROGER" ||
                   clean == "AFFIRMATIVE" ||
                   clean == "NEGATIVE";
        }

        private static bool IsCpdlcDirectStatusText(string contents)
        {
            string clean = NormalizeCpdlcOverviewText(contents);

            if (string.IsNullOrWhiteSpace(clean))
            {
                return false;
            }

            return IsCpdlcReplyStatusText(clean) ||
                   IsCpdlcSentReplyOverviewText(clean) ||
                   IsCpdlcFailedReplyOverviewText(clean) ||
                   clean == "REQUEST LOGON" ||
                   clean == "LOGOFF" ||
                   clean.Contains("CONNECTED TO") ||
                   clean.Contains("LOGON ACCEPTED") ||
                   clean.Contains("LOGON REJECTED") ||
                   clean.Contains("LOGON FAILED") ||
                   clean.Contains("LOGON REQUEST") ||
                   clean.Contains("CONNECTION TERMINATED") ||
                   clean.Contains("LOGOFF");
        }

        private static string ExtractConnectedAtcUnitFromCpdlcText(string cleanText, string fallback)
        {
            string cleanFallback = (fallback ?? string.Empty).Trim().ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(cleanText))
            {
                return cleanFallback;
            }

            Match connected = Regex.Match(cleanText, @"\bCONNECTED\s+TO\s*:?\s*([A-Z0-9_]{3,16})\b");
            if (connected.Success)
            {
                return connected.Groups[1].Value.Trim().ToUpperInvariant();
            }

            Match accepted = Regex.Match(cleanText, @"\bLOGON\s+(?:ACCEPTED|CONFIRMED|ESTABLISHED)(?:\s+(?:BY|WITH|TO))?\s*([A-Z0-9_]{3,16})?\b");
            if (accepted.Success && accepted.Groups.Count > 1 && !string.IsNullOrWhiteSpace(accepted.Groups[1].Value))
            {
                return accepted.Groups[1].Value.Trim().ToUpperInvariant();
            }

            return cleanFallback;
        }

        private string BuildCpdlcListText(string contents, string recipient, bool outbound)
        {
            string clean = NormalizeCpdlcOverviewText(contents);
            string unit = (recipient ?? string.Empty).Trim().ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(clean))
            {
                return outbound
                    ? "CPDLC MESSAGE TO " + unit
                    : "CPDLC MESSAGE FROM " + unit;
            }

            if (outbound)
            {
                if (IsCpdlcSendingReplyOverviewText(clean) || IsCpdlcFailedReplyOverviewText(clean))
                {
                    return ShortenOverviewText(clean, 62);
                }

                if (clean == "REQUEST LOGON")
                {
                    return string.IsNullOrWhiteSpace(unit)
                        ? "REQUEST LOGON"
                        : "REQUEST LOGON TO: " + unit;
                }

                if (clean == "LOGOFF")
                {
                    return string.IsNullOrWhiteSpace(unit)
                        ? "LOGOFF SENT"
                        : "LOGOFF SENT TO: " + unit;
                }

                if (IsCpdlcReplyStatusText(clean))
                {
                    return BuildCpdlcSentReplyOverviewText(clean);
                }

                return string.IsNullOrWhiteSpace(unit)
                    ? ShortenOverviewText(clean, 62)
                    : ShortenOverviewText(clean + " TO " + unit, 62);
            }

            if (clean.Contains("CONNECTED TO") || clean.Contains("LOGON ACCEPTED") || clean.Contains("LOGON CONFIRMED") || clean.Contains("LOGON ESTABLISHED"))
            {
                string connectedUnit = ExtractConnectedAtcUnitFromCpdlcText(clean, unit);
                return string.IsNullOrWhiteSpace(connectedUnit)
                    ? "CPDLC CONNECTED"
                    : "CPDLC CONNECTED TO: " + connectedUnit;
            }

            if (clean.Contains("LOGON REJECTED") || clean.Contains("LOGON FAILED"))
            {
                return string.IsNullOrWhiteSpace(unit)
                    ? "CPDLC LOGON REJECTED"
                    : "CPDLC LOGON REJECTED BY: " + unit;
            }

            if (clean.Contains("LOGOFF") || clean.Contains("CONNECTION TERMINATED"))
            {
                return string.IsNullOrWhiteSpace(unit)
                    ? "CPDLC LOGOFF"
                    : "CPDLC LOGOFF FROM: " + unit;
            }

            // For real CPDLC uplinks, show the actual instruction directly in the
            // message overview instead of the generic "CPDLC MESSAGE FROM XXXX".
            return ShortenOverviewText(clean, 66);
        }

        private static bool IsCpdlcSendingReplyOverviewText(string text)
        {
            string clean = NormalizeCpdlcOverviewText(text);
            return clean.StartsWith("◷ ", StringComparison.OrdinalIgnoreCase) ||
                   clean.StartsWith("◶ ", StringComparison.OrdinalIgnoreCase) ||
                   clean.StartsWith("◵ ", StringComparison.OrdinalIgnoreCase) ||
                   clean.StartsWith("◴ ", StringComparison.OrdinalIgnoreCase);
        }

        private static bool IsCpdlcFailedReplyOverviewText(string text)
        {
            string clean = NormalizeCpdlcOverviewText(text);
            return clean.StartsWith("✕ ", StringComparison.OrdinalIgnoreCase) &&
                   clean.Contains(" FAILED");
        }

        private static bool IsCpdlcSentReplyOverviewText(string text)
        {
            string clean = NormalizeCpdlcOverviewText(text);

            if (clean.StartsWith("✓ ", StringComparison.OrdinalIgnoreCase))
            {
                clean = clean.Substring(2).Trim();
            }

            clean = clean.Replace(" SENT", string.Empty).Trim();

            return IsCpdlcReplyStatusText(clean);
        }

        private static string BuildCpdlcSentReplyOverviewText(string reply)
        {
            string clean = NormalizeCpdlcOverviewText(reply);
            if (clean.StartsWith("✓ ", StringComparison.OrdinalIgnoreCase))
            {
                clean = clean.Substring(2).Trim();
            }
            if (clean == "STBY")
            {
                clean = "STANDBY";
            }

            if (string.IsNullOrWhiteSpace(clean))
            {
                clean = "CPDLC";
            }

            return "✓ " + clean;
        }

        private bool ShouldUseDeleteOnlyOverviewAction(CPDLCMessage message)
        {
            if (message == null)
            {
                return false;
            }

            if (!message.outbound ||
                !string.Equals(message.type, "CPDLC", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            // LOGON / LOGOFF / WILCO / STANDBY etc. are short status rows and use
            // the existing auto-delete handling. Actual outbound CPDLC requests are
            // just sent request history lines: delete-only, no open action.
            if (IsCpdlcSendingReplyOverviewText(message.message) ||
                IsCpdlcFailedReplyOverviewText(message.message))
            {
                return false;
            }

            return !IsCpdlcDirectStatusText(message.message);
        }

        private static bool IsCpdlcInformationalStatusText(string text)
        {
            string clean = NormalizeCpdlcOverviewText(text);

            if (string.IsNullOrWhiteSpace(clean))
            {
                return false;
            }

            bool clearanceConfirmed =
                (clean.Contains("CDA RECEIVED") ||
                 clean.Contains("CLEARANCE RECEIVED") ||
                 clean.Contains("CLEARENCE RECEIVED")) &&
                (clean.Contains("CLEARANCE CONFIRMED") ||
                 clean.Contains("CLEARENCE CONFIRMED") ||
                 clean.Contains("CONFIRMED"));

            return clearanceConfirmed;
        }

        private static string StripOverviewReplyStatusPrefix(string text)
        {
            if (ReplyStatusOverviewMessage.TrySplitStatusPrefix(text, out _, out string rest))
            {
                return rest;
            }

            return (text ?? string.Empty).TrimStart();
        }

        private static bool HasOverviewReplyStatusPrefix(CPDLCMessage message)
        {
            return message != null &&
                   ReplyStatusOverviewMessage.TrySplitStatusPrefix(message.Text, out _, out _);
        }

        private static bool HasSuccessfulOverviewReplyStatus(CPDLCMessage message)
        {
            return message != null &&
                   ReplyStatusOverviewMessage.TrySplitStatusPrefix(message.Text, out string prefix, out _) &&
                   string.Equals(prefix, "✓", StringComparison.Ordinal);
        }

        private static bool MessageNeedsOverviewReplyIndicator(string messageType, bool outbound, CPDLCResponse header)
        {
            return !outbound &&
                   string.Equals(messageType ?? string.Empty, "CPDLC", StringComparison.OrdinalIgnoreCase) &&
                   header != null &&
                   !string.Equals(header.Responses ?? string.Empty, "NE", StringComparison.OrdinalIgnoreCase);
        }

        private void SetOriginalOverviewReplyStatus(CPDLCMessage message, TimerLabel menuLabel, string marker, Color markerColor, bool acknowledged)
        {
            SafeUi(() =>
            {
                if (message == null || message.IsDisposed)
                {
                    return;
                }

                message.Text = StripOverviewReplyStatusPrefix(message.Text);
                message.Font = GetMessageTextFont(false);
                message.ForeColor = acknowledged ? SystemColors.ControlDark : MainPrimaryTextColor();
                SetReplyStatusTimeLabel(message, marker, markerColor);

                if (acknowledged)
                {
                    message.acknowledged = true;
                }

                unreadMessages.Remove(message);
                if (unreadMessages.Count == 0)
                {
                    unreadReminderTimer.Stop();
                }

                if (menuLabel != null && !menuLabel.IsDisposed)
                {
                    ConfigureOpenMessageIndicator(menuLabel);
                    menuLabel.CanFlash = false;
                    menuLabel.ForeColor = markerColor;
                    menuLabel.Invalidate();
                }

                message.Invalidate();
                ApplyMessageFilter();
            });
        }

        private System.Windows.Forms.Timer StartOriginalOverviewReplySpinner(CPDLCMessage message, TimerLabel menuLabel)
        {
            string[] frames = { "◷", "◶", "◵", "◴" };
            int frame = 0;

            System.Windows.Forms.Timer timer = new()
            {
                Interval = 250
            };

            timer.Tick += (_, __) =>
            {
                frame = (frame + 1) % frames.Length;
                SetOriginalOverviewReplyStatus(message, menuLabel, frames[frame], DcduTheme.Amber, false);
            };

            timer.Start();
            return timer;
        }

        private void MarkOriginalMessageRepliedFromOverview(CPDLCMessage message, TimerLabel menuLabel, string reply)
        {
            string cleanReply = NormalizeCpdlcOverviewText(reply);
            bool successfulWilco = cleanReply == "WILCO";

            SetOriginalOverviewReplyStatus(
                message,
                menuLabel,
                successfulWilco ? "✓" : "✓",
                successfulWilco ? DcduTheme.Green : SystemColors.ControlDark,
                true);
        }

        private static bool IsCpdlcAtcProcessingStatusText(string text)
        {
            string clean = NormalizeCpdlcOverviewText(text);

            return clean.Contains("RCD RECEIVED") &&
                   clean.Contains("REQUEST BEING PROCESSED") &&
                   clean.Contains("STANDBY");
        }

        private bool CanDirectRogerFromOverview(CPDLCMessage message)
        {
            if (message == null ||
                message.outbound ||
                message.acknowledged ||
                !string.Equals(message.type, "CPDLC", StringComparison.OrdinalIgnoreCase) ||
                message.header == null)
            {
                return false;
            }

            string responseCode = (message.header.Responses ?? string.Empty).Trim().ToUpperInvariant();
            return string.Equals(responseCode, "R", StringComparison.OrdinalIgnoreCase) &&
                   IsCpdlcAtcProcessingStatusText(message.message);
        }

        private bool ShouldShowOverviewActionPopup(CPDLCMessage message)
        {
            if (message == null)
            {
                return false;
            }

            return CanDirectWilcoFromOverview(message) ||
                   CanDirectRogerFromOverview(message) ||
                   (!message.outbound &&
                    string.Equals(message.type, "CPDLC", StringComparison.OrdinalIgnoreCase) &&
                    (IsCpdlcAtcProcessingStatusText(message.message) ||
                     IsCpdlcInformationalStatusText(message.message)));
        }

        private bool CanDirectWilcoFromOverview(CPDLCMessage message)
        {
            if (message == null ||
                message.outbound ||
                message.acknowledged ||
                !string.Equals(message.type, "CPDLC", StringComparison.OrdinalIgnoreCase) ||
                message.header == null)
            {
                return false;
            }

            string responseCode = (message.header.Responses ?? string.Empty).Trim().ToUpperInvariant();
            return string.Equals(responseCode, "WU", StringComparison.OrdinalIgnoreCase);
        }

        private string CreateMessageListText(string contents, string type, string recipient, bool outbound)
        {
            string normalizedType = (type ?? string.Empty).Trim().ToUpperInvariant();

            if (normalizedType == "SYSTEM")
            {
                if (IsCpdlcStationDetectedText(contents))
                {
                    return "CPDLC STATION DETECTED";
                }

                if (IsCallsignMismatchAlarmText(contents))
                {
                    return "VATSIM CALLSIGN MISMATCH";
                }

                return BuildSystemListSummary(contents);
            }

            if (ShouldUseAtisListText(contents, normalizedType, recipient))
            {
                string target = outbound
                    ? FormatAtisTargetForList(recipient)
                    : GetAtisListTarget(contents, recipient, true);
                string upperContents = (contents ?? string.Empty).ToUpperInvariant();

                if (outbound)
                {
                    return "REQUESTING ATIS FOR " + target;
                }

                if (upperContents.Contains("NOT AVAILABLE"))
                {
                    return BuildAtisListSummary(target, "NOT AVAILABLE");
                }

                string atisLetter = GetAtisOverviewLetter(contents, target);
                string atisStatus = BuildAtisStatusForOverview(target, atisLetter);
                string atisSummary = atisStatus + BuildWeatherOverviewSuffix(contents, 44, false, target);

                CacheWeatherMessage("ATIS", target, contents, atisSummary);
                return BuildAtisListSummary(target, atisSummary);
            }

            if (ShouldUseMetarListText(contents, normalizedType, recipient))
            {
                string target = outbound
                    ? FormatAtisTargetForList(recipient)
                    : GetMetarListTarget(contents, recipient, true);
                string upperContents = (contents ?? string.Empty).ToUpperInvariant();

                if (outbound)
                {
                    return "REQUESTING METAR FOR " + target;
                }

                if (upperContents.Contains("NOT AVAILABLE") ||
                    upperContents.Contains("NO METAR") ||
                    upperContents.Contains("METAR NOT"))
                {
                    return BuildMetarListSummary(target, "NOT AVAILABLE");
                }

                string metarSummary = "RECEIVED" + BuildWeatherOverviewSuffix(contents, 30, true);
                CacheWeatherMessage("METAR", target, contents, metarSummary);
                return BuildMetarListSummary(target, metarSummary);
            }

            if (normalizedType == "CPDLC")
            {
                return BuildCpdlcListText(contents, recipient, outbound);
            }

            if (!outbound &&
                IsOpsMessageSender(recipient) &&
                (normalizedType == "TELEX" ||
                 normalizedType == "INFO" ||
                 normalizedType == "INFOREQ"))
            {
                return "OPS MESSAGE FROM " + recipient.Trim().ToUpperInvariant();
            }

            return outbound
                ? string.Format("{1} MESSAGE TO {0}", recipient, normalizedType)
                : string.Format("{1} MESSAGE FROM {0}", recipient, normalizedType);
        }

        private bool ShouldUseAtisListText(string contents, string normalizedType, string recipient)
        {
            if (normalizedType == "ATIS")
            {
                return true;
            }

            string upperContents = (contents ?? string.Empty).ToUpperInvariant();
            string upperRecipient = (recipient ?? string.Empty).ToUpperInvariant();

            if (upperRecipient == "VATATIS")
            {
                return true;
            }

            if (upperContents.Contains("VATATIS") ||
                upperContents.Contains("_ATIS") ||
                Regex.IsMatch(upperContents, @"\b[A-Z0-9]{4}_[AD]\b"))
            {
                return true;
            }

            // Generic VATATIS replies can arrive as INFO/ACARS and may be very generic.
            // If an ATIS request is pending and no METAR request is pending, treat the next
            // ACARS/INFO response as ATIS. This fixes "INFO MESSAGE FROM ACARS" after ATIS requests.
            if (upperRecipient == "ACARS" && HasPendingAtisRequest())
            {
                if (LooksLikeGenericAtisInformation(upperContents) ||
                    LooksLikeAtisBroadcastText(upperContents) ||
                    upperContents.Contains("ATIS"))
                {
                    return true;
                }

                return !HasPendingMetarRequest();
            }

            // A CPDLC clearance can also contain "ATIS C", so only map generic text
            // to ATIS when an ATIS request is actually pending.
            return (LooksLikeGenericAtisInformation(upperContents) || LooksLikeAtisBroadcastText(upperContents)) &&
                   HasPendingAtisRequest();
        }

        private bool ShouldUseMetarListText(string contents, string normalizedType, string recipient)
        {
            if (normalizedType == "METAR")
            {
                return true;
            }

            string upperContents = (contents ?? string.Empty).ToUpperInvariant();
            string upperRecipient = (recipient ?? string.Empty).ToUpperInvariant();

            if (upperContents.Contains("METAR ") ||
                upperContents.StartsWith("METAR") ||
                upperContents.StartsWith("SPECI") ||
                Regex.IsMatch(upperContents, @"\b[A-Z][A-Z0-9]{3}\s+\d{6}Z\b"))
            {
                return true;
            }

            // METAR replies may also arrive as generic "INFO FROM ACARS".
            // If a METAR request is pending, map the next ACARS info reply to it.
            return upperRecipient == "ACARS" && HasPendingMetarRequest();
        }

        private void RememberMetarRequestTarget(string target)
        {
            string formatted = FormatAtisTargetForList(target);
            if (formatted == "ATIS")
            {
                return;
            }

            lock (pendingMetarRequestLock)
            {
                pendingMetarRequestTargets.Enqueue(formatted);

                while (pendingMetarRequestTargets.Count > 8)
                {
                    pendingMetarRequestTargets.Dequeue();
                }
            }
        }

        private bool HasPendingMetarRequest()
        {
            lock (pendingMetarRequestLock)
            {
                return pendingMetarRequestTargets.Count > 0;
            }
        }

        private string GetPendingMetarRequestTarget(bool consume)
        {
            lock (pendingMetarRequestLock)
            {
                if (pendingMetarRequestTargets.Count == 0)
                {
                    return "METAR";
                }

                return consume
                    ? pendingMetarRequestTargets.Dequeue()
                    : pendingMetarRequestTargets.Peek();
            }
        }

        private string GetMetarListTarget(string contents, string recipient, bool consumePending)
        {
            string pendingRequestTarget = GetPendingMetarRequestTarget(consumePending);
            if (pendingRequestTarget != "METAR")
            {
                return pendingRequestTarget;
            }

            string combined = ((contents ?? string.Empty) + "\n" + (recipient ?? string.Empty)).ToUpperInvariant();

            Match explicitMetar = Regex.Match(combined, @"\b(?:METAR|SPECI)\s+([A-Z][A-Z0-9]{3})\b");
            if (explicitMetar.Success && IsAirportCodeToken(explicitMetar.Groups[1].Value))
            {
                return explicitMetar.Groups[1].Value.ToUpperInvariant();
            }

            Match timedMetar = Regex.Match(combined, @"\b([A-Z][A-Z0-9]{3})\s+\d{6}Z\b");
            if (timedMetar.Success && IsAirportCodeToken(timedMetar.Groups[1].Value))
            {
                return timedMetar.Groups[1].Value.ToUpperInvariant();
            }

            MatchCollection matches = Regex.Matches(combined, @"\b[A-Z][A-Z0-9]{3}\b");
            foreach (Match match in matches)
            {
                string candidate = match.Value.Trim().ToUpperInvariant();

                if (IsAirportCodeToken(candidate))
                {
                    return candidate;
                }
            }

            return "METAR";
        }

        private static bool IsAirportCodeToken(string token)
        {
            if (string.IsNullOrWhiteSpace(token))
            {
                return false;
            }

            string upper = token.Trim().ToUpperInvariant();

            string[] reserved =
            {
                "METAR", "SPECI", "AUTO", "CORR", "CAVOK", "NOSIG",
                "TEMPO", "BECMG", "PROB", "WIND", "RWYS", "RWY",
                "QNH", "INFO", "FROM", "ACARS", "DATA", "LINK",
                "ATIS", "THIS", "WITH", "TEXT", "NIL",
                "RNAV", "RNP", "GPS", "ILS", "VOR", "NDB", "DME",
                "STAR", "SID", "APCH", "ARR", "DEP", "DEW", "POINT",
                "DEGREES", "KNOTS", "FEET"
            };

            if (reserved.Contains(upper))
            {
                return false;
            }

            return Regex.IsMatch(upper, @"^[A-Z][A-Z0-9]{3}$");
        }

        private static string BuildMetarListSummary(string target, string status)
        {
            string cleanTarget = FormatAtisTargetForList(target);
            string cleanStatus = (status ?? string.Empty).Trim().ToUpperInvariant();

            return cleanTarget == "ATIS" || cleanTarget == "METAR"
                ? "METAR " + cleanStatus
                : cleanTarget + " METAR " + cleanStatus;
        }

        private void CacheWeatherMessage(string type, string target, string contents, string summary)
        {
            string cleanType = string.IsNullOrWhiteSpace(type) ? "WX" : type.ToUpperInvariant();
            string cleanTarget = FormatAtisTargetForList(target);

            if (cleanTarget == "ATIS" || cleanTarget == "METAR")
            {
                return;
            }

            string key = cleanType + ":" + cleanTarget;
            weatherCache[key] = new WeatherCacheItem
            {
                Type = cleanType,
                Target = cleanTarget,
                Summary = string.IsNullOrWhiteSpace(summary) ? "RECEIVED" : summary.Trim().ToUpperInvariant(),
                Contents = contents ?? string.Empty,
                TimestampUtc = DateTime.UtcNow
            };
        }

        private static string BuildWeatherOverviewSuffix(string contents, int maxChars, bool includeWind, string target = "")
        {
            string summary = BuildWeatherOverviewSummary(contents, includeWind, target);

            if (string.IsNullOrWhiteSpace(summary))
            {
                return string.Empty;
            }

            summary = summary.Trim().ToUpperInvariant();

            if (summary.Length > maxChars)
            {
                summary = summary.Substring(0, maxChars).TrimEnd();
            }

            return " " + summary;
        }

        private static string BuildWeatherOverviewSummary(string contents, bool includeWind, string target = "")
        {
            if (string.IsNullOrWhiteSpace(contents))
            {
                return string.Empty;
            }

            string upper = contents
                .Replace("\r\n", " ")
                .Replace("\r", " ")
                .Replace("\n", " ")
                .Replace("\t", " ")
                .ToUpperInvariant();

            upper = Regex.Replace(upper, @"\s+", " ").Trim();

            string normalizedTarget = (target ?? string.Empty).Trim().ToUpperInvariant();
            bool targetIsArrivalAtis = normalizedTarget.EndsWith("_A", StringComparison.OrdinalIgnoreCase) ||
                                       normalizedTarget.EndsWith("_A_ATIS", StringComparison.OrdinalIgnoreCase);
            bool targetIsDepartureAtis = normalizedTarget.EndsWith("_D", StringComparison.OrdinalIgnoreCase) ||
                                         normalizedTarget.EndsWith("_D_ATIS", StringComparison.OrdinalIgnoreCase);

            List<string> parts = new();

            Match qnh = Regex.Match(upper, @"\bQNH\s*([0-9]{3,4})\b|\bQ([0-9]{4})\b");
            if (qnh.Success)
            {
                string qnhValue = qnh.Groups[1].Success ? qnh.Groups[1].Value : qnh.Groups[2].Value;
                parts.Add("QNH " + qnhValue);
            }
            else
            {
                Match altimeter = Regex.Match(upper, @"\bA([0-9]{4})\b");
                if (altimeter.Success)
                {
                    parts.Add("A" + altimeter.Groups[1].Value);
                }
            }

            if (includeWind)
            {
                Match wind = Regex.Match(upper, @"\b((?:[0-3][0-9]{2}|VRB)[0-9]{2,3}(?:G[0-9]{2,3})?KT)\b");
                if (wind.Success)
                {
                    parts.Add("WIND " + NormalizeWindForOverview(wind.Groups[1].Value));
                }
                else
                {
                    Match spokenWind = Regex.Match(upper, @"\bWIND\s+((?:[0-3][0-9]{2}|VRB)[0-9]{2,3}(?:G[0-9]{2,3})?)\b");
                    if (spokenWind.Success)
                    {
                        parts.Add("WIND " + NormalizeWindForOverview(spokenWind.Groups[1].Value));
                    }
                }
            }

            Match arrRwy = Regex.Match(
                upper,
                @"\b(?:ARR(?:IVAL)?\s+RWYS?|ILS\s+APCH\s+RWY|ILS\s+APPROACH\s+RWY|RNP\s+RWY|RNAV\s+RWY|APPROACH\s+RWY|APCH\s+RWY)\s*(?<rwy>[0-9]{2})(?:\s*(?<side>L|C|R|LEFT|RIGHT|CENTER|CENTRE))?\b");
            if (arrRwy.Success)
            {
                string arrValue = NormalizeRunwayDesignatorForOverview(arrRwy.Groups["rwy"].Value, arrRwy.Groups["side"].Value);
                parts.Add("ARR " + arrValue);
            }

            // Departure runway must be explicit. Do not parse "DP15" from METAR
            // as DEP 15; DP is dew point, not departure runway.
            Match depRwy = Regex.Match(
                upper,
                @"\b(?:DEP(?:ARTURE)?\s+RWYS?|DEP(?:ARTURE)?\s*RWY)\s*(?<rwy>[0-9]{2})(?:\s*(?<side>L|C|R|LEFT|RIGHT|CENTER|CENTRE))?\b");
            if (depRwy.Success)
            {
                string depValue = NormalizeRunwayDesignatorForOverview(depRwy.Groups["rwy"].Value, depRwy.Groups["side"].Value);
                if (!parts.Any(part => string.Equals(part, "DEP " + depValue, StringComparison.OrdinalIgnoreCase)))
                {
                    parts.Add("DEP " + depValue);
                }
            }

            if (!parts.Any(part => part.StartsWith("ARR ", StringComparison.OrdinalIgnoreCase) ||
                                   part.StartsWith("DEP ", StringComparison.OrdinalIgnoreCase)))
            {
                Match rwy = Regex.Match(
                    upper,
                    @"\b(?:RWYS?|RUNWAYS?)\s+(?:(?:IN\s+USE|USE|USED|ACTIVE|IN\s+OPERATION|AVAILABLE)(?:\s+(?:ARE|IS))?\s+)?(?<rwys>[0-9]{2}(?:\s*(?:L|C|R|LEFT|RIGHT|CENTER|CENTRE))?(?:\s*(?:AND|/|,)\s*[0-9]{2}(?:\s*(?:L|C|R|LEFT|RIGHT|CENTER|CENTRE))?)?)\b");
                if (rwy.Success)
                {
                    string runwayValue = NormalizeRunwayListForOverview(rwy.Groups["rwys"].Value);
                    if (targetIsArrivalAtis)
                    {
                        parts.Add("ARR " + runwayValue);
                    }
                    else if (targetIsDepartureAtis)
                    {
                        parts.Add("DEP " + runwayValue);
                    }
                    else
                    {
                        parts.Add("RWY " + runwayValue);
                    }
                }
            }

            if (parts.Count == 0)
            {
                return string.Empty;
            }

            if (!includeWind)
            {
                parts = parts
                    .OrderBy(part =>
                        part.StartsWith("ARR ", StringComparison.OrdinalIgnoreCase) ? 0 :
                        part.StartsWith("DEP ", StringComparison.OrdinalIgnoreCase) ? 1 :
                        part.StartsWith("RWY ", StringComparison.OrdinalIgnoreCase) ? 2 :
                        part.StartsWith("QNH ", StringComparison.OrdinalIgnoreCase) ? 3 :
                        part.StartsWith("A", StringComparison.OrdinalIgnoreCase) ? 3 :
                        4)
                    .ToList();
            }

            return string.Join(" ", parts.Take(4));
        }

        private static string NormalizeRunwayDesignatorForOverview(string runway, string side)
        {
            string cleanRunway = (runway ?? string.Empty).Trim().ToUpperInvariant();
            string cleanSide = (side ?? string.Empty).Trim().ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(cleanRunway))
            {
                return string.Empty;
            }

            string suffix = cleanSide switch
            {
                "LEFT" => "L",
                "RIGHT" => "R",
                "CENTER" => "C",
                "CENTRE" => "C",
                "L" => "L",
                "R" => "R",
                "C" => "C",
                _ => string.Empty
            };

            return cleanRunway + suffix;
        }

        private static string NormalizeRunwayListForOverview(string runways)
        {
            if (string.IsNullOrWhiteSpace(runways))
            {
                return string.Empty;
            }

            string normalized = Regex.Replace(runways.Trim().ToUpperInvariant(), @"\s+", " ");

            normalized = Regex.Replace(
                normalized,
                @"\b(?<rwy>[0-9]{2})\s*(?<side>L|C|R|LEFT|RIGHT|CENTER|CENTRE)?\b",
                match => NormalizeRunwayDesignatorForOverview(match.Groups["rwy"].Value, match.Groups["side"].Value));

            normalized = Regex.Replace(normalized, @"\s*,\s*", ", ");
            normalized = Regex.Replace(normalized, @"\s*/\s*", "/");
            normalized = Regex.Replace(normalized, @"\s+AND\s+", " AND ");

            return normalized.Trim();
        }

        private static string NormalizeWindForOverview(string wind)
        {
            if (string.IsNullOrWhiteSpace(wind))
            {
                return string.Empty;
            }

            string clean = wind.Trim().ToUpperInvariant();

            if (clean.EndsWith("KT", StringComparison.OrdinalIgnoreCase))
            {
                clean = clean.Substring(0, clean.Length - 2);
            }

            Match match = Regex.Match(clean, @"^((?:[0-3][0-9]{2}|VRB))([0-9]{2,3})(G[0-9]{2,3})?$");
            if (!match.Success)
            {
                return clean;
            }

            string direction = match.Groups[1].Value;
            string speed = match.Groups[2].Value.TrimStart('0');
            if (speed.Length == 0)
            {
                speed = "0";
            }

            string gust = match.Groups[3].Success ? match.Groups[3].Value : string.Empty;
            return direction + "/" + speed + gust;
        }

        private void RememberAtisRequestTarget(string target)
        {
            string formatted = FormatAtisTargetForList(target);
            if (formatted == "ATIS")
            {
                return;
            }

            lock (pendingAtisRequestLock)
            {
                PurgeOldPendingAtisRequestsNoLock();

                // VATATIS/ACARS replies often do not include the ICAO.
                // Keep request order for close-together requests, but timestamp entries
                // so an old airport cannot be reused for a later ATIS response.
                pendingAtisRequestTargets.Enqueue(new PendingAtisRequest(formatted, DateTime.UtcNow));

                while (pendingAtisRequestTargets.Count > 8)
                {
                    pendingAtisRequestTargets.Dequeue();
                }
            }
        }

        private void PurgeOldPendingAtisRequestsNoLock()
        {
            DateTime cutoff = DateTime.UtcNow - pendingAtisRequestLifetime;

            while (pendingAtisRequestTargets.Count > 0 &&
                   pendingAtisRequestTargets.Peek().CreatedUtc < cutoff)
            {
                pendingAtisRequestTargets.Dequeue();
            }
        }

        private bool HasPendingAtisRequest()
        {
            lock (pendingAtisRequestLock)
            {
                PurgeOldPendingAtisRequestsNoLock();
                return pendingAtisRequestTargets.Count > 0;
            }
        }

        private void RemovePendingAtisRequestTarget(string target)
        {
            string formatted = FormatAtisTargetForList(target);
            if (formatted == "ATIS")
            {
                return;
            }

            lock (pendingAtisRequestLock)
            {
                if (pendingAtisRequestTargets.Count == 0)
                {
                    return;
                }

                List<PendingAtisRequest> entries = pendingAtisRequestTargets.ToList();
                pendingAtisRequestTargets.Clear();

                bool removed = false;

                foreach (PendingAtisRequest entry in entries)
                {
                    if (!removed &&
                        string.Equals(entry.Target, formatted, StringComparison.OrdinalIgnoreCase))
                    {
                        removed = true;
                        continue;
                    }

                    pendingAtisRequestTargets.Enqueue(entry);
                }
            }
        }

        private string GetPendingAtisRequestTarget(bool consume)
        {
            lock (pendingAtisRequestLock)
            {
                PurgeOldPendingAtisRequestsNoLock();

                if (pendingAtisRequestTargets.Count == 0)
                {
                    return "ATIS";
                }

                // If an old request somehow stayed in the queue and a clearly newer ATIS
                // request was made later, prefer the newer one for generic ACARS replies.
                // This prevents "LOWW ATIS..." being shown for a later EPKK request.
                if (consume && pendingAtisRequestTargets.Count > 1)
                {
                    PendingAtisRequest[] entries = pendingAtisRequestTargets.ToArray();
                    PendingAtisRequest first = entries[0];
                    PendingAtisRequest last = entries[entries.Length - 1];

                    if (last.CreatedUtc - first.CreatedUtc > pendingAtisStaleJumpThreshold)
                    {
                        pendingAtisRequestTargets.Clear();
                        return last.Target;
                    }
                }

                return consume
                    ? pendingAtisRequestTargets.Dequeue().Target
                    : pendingAtisRequestTargets.Peek().Target;
            }
        }

        private string GetAtisListTarget(string contents, string recipient, bool consumePending)
        {
            string pendingRequestTarget = GetPendingAtisRequestTarget(consumePending);
            if (pendingRequestTarget != "ATIS")
            {
                return pendingRequestTarget;
            }

            string contentsUpper = (contents ?? string.Empty).ToUpperInvariant();
            string recipientUpper = (recipient ?? string.Empty).ToUpperInvariant();
            string combined = (contentsUpper + "\n" + recipientUpper).ToUpperInvariant();

            string target = ExtractAtisTarget(combined);
            if (target != "ATIS")
            {
                string formattedTarget = FormatAtisTargetForList(target);

                if (consumePending)
                {
                    RemovePendingAtisRequestTarget(formattedTarget);
                }

                return formattedTarget;
            }

            MatchCollection matches = Regex.Matches(combined, @"\b[A-Z0-9]{4}(?:_[AD])?(?:_ATIS)?\b");
            foreach (Match match in matches)
            {
                string candidate = match.Value.Trim('_', ' ', '\r', '\n', '\t');

                if (IsAtisTargetToken(candidate))
                {
                    string formattedTarget = FormatAtisTargetForList(candidate);

                    if (consumePending)
                    {
                        RemovePendingAtisRequestTarget(formattedTarget);
                    }

                    return formattedTarget;
                }
            }

            return "ATIS";
        }

        private static bool LooksLikeGenericAtisInformation(string upperContents)
        {
            if (string.IsNullOrWhiteSpace(upperContents))
            {
                return false;
            }

            return upperContents.Contains("THIS IS ") &&
                   upperContents.Contains(" INFORMATION ");
        }

        private static bool LooksLikeAtisBroadcastText(string upperContents)
        {
            if (string.IsNullOrWhiteSpace(upperContents))
            {
                return false;
            }

            string upper = Regex.Replace(upperContents, @"\s+", " ").Trim();

            bool hasInformationDesignator =
                Regex.IsMatch(upper, @"\bINFORMATION\s+[A-Z]\b") ||
                Regex.IsMatch(upper, @"\bINFO\s+[A-Z]\b");

            if (!hasInformationDesignator)
            {
                return false;
            }

            return upper.Contains(" QNH ") ||
                   upper.Contains(" RWY ") ||
                   upper.Contains(" RUNWAY ") ||
                   upper.Contains(" CAVOK ") ||
                   upper.Contains(" NOSIG") ||
                   upper.Contains(" ARRIVALS ") ||
                   upper.Contains(" DEPARTURES ") ||
                   upper.Contains(" EXPECT ") ||
                   upper.Contains(" TRANSITION ") ||
                   upper.Contains(" APPROACH ");
        }

        private static bool IsAtisTargetToken(string token)
        {
            if (string.IsNullOrWhiteSpace(token))
            {
                return false;
            }

            string upper = token.Trim().ToUpperInvariant();

            string[] reserved =
            {
                "ATIS", "THIS", "FROM", "INFO", "WIND", "QNH", "CAVOK", "RWYS",
                "RWY", "DUE", "FOR", "NOT", "WITH", "TEXT", "DATA", "LINK",
                "ILS", "VOR", "NDB", "DME", "GPS", "RNP", "RNAV",
                "ALPHA", "BRAVO", "CHARLIE", "DELTA", "ECHO", "FOXTROT",
                "GOLF", "HOTEL", "INDIA", "JULIET", "KILO", "LIMA", "MIKE",
                "NOVEMBER", "OSCAR", "PAPA", "QUEBEC", "ROMEO", "SIERRA",
                "TANGO", "UNIFORM", "VICTOR", "WHISKEY", "XRAY", "X-RAY",
                "YANKEE", "ZULU"
            };

            if (reserved.Contains(upper))
            {
                return false;
            }

            if (!Regex.IsMatch(upper, @"^[A-Z][A-Z0-9]{3}(?:_[AD])?(?:_ATIS)?$"))
            {
                return false;
            }

            return upper.Take(4).Any(char.IsLetter);
        }

        private static string FormatAtisTargetForList(string target)
        {
            if (string.IsNullOrWhiteSpace(target))
            {
                return "ATIS";
            }

            string clean = target.Trim().Trim('_').ToUpperInvariant();

            if (clean.EndsWith("_ATIS", StringComparison.OrdinalIgnoreCase))
            {
                clean = clean.Substring(0, clean.Length - "_ATIS".Length);
            }

            // For the message overview, show only the airport ICAO.
            // Requests may internally use XXXX_A / XXXX_D for split ATIS,
            // but the list should stay clean: LOWW ATIS..., not LOWW_A ATIS...
            if (clean.EndsWith("_A", StringComparison.OrdinalIgnoreCase) ||
                clean.EndsWith("_D", StringComparison.OrdinalIgnoreCase))
            {
                clean = clean.Substring(0, clean.Length - 2);
            }

            return string.IsNullOrWhiteSpace(clean) ? "ATIS" : clean;
        }

        private static string BuildAtisListSummary(string target, string status)
        {
            string cleanTarget = FormatAtisTargetForList(target);
            string cleanStatus = (status ?? string.Empty).Trim().ToUpperInvariant();

            string prefix = cleanTarget == "ATIS"
                ? "ATIS "
                : cleanTarget + " ATIS ";

            string combined = prefix + cleanStatus;

            // Keep the first line stable/readable and put the compact weather/runway summary
            // on a second line. This prevents "ARR 30L DEP 30R QNH 998" from being cut off
            // in the narrow DCDU message list.
            Match received = Regex.Match(
                combined,
                @"^(?<head>.+?\b(?:INFO\s+[A-Z?]\s+RECEIVED|UPDATED\s+[A-Z?]->[A-Z?]|\?\s+RECEIVED))\s+(?<tail>.+)$",
                RegexOptions.IgnoreCase);

            if (received.Success)
            {
                string head = received.Groups["head"].Value.Trim().ToUpperInvariant();
                string tail = received.Groups["tail"].Value.Trim().ToUpperInvariant();

                if (!string.IsNullOrWhiteSpace(tail))
                {
                    return head + "\n" + tail;
                }
            }

            return combined;
        }

        private string GetAtisOverviewLetter(string contents, string target)
        {
            string letter = ExtractAtisInformationLetter(contents);

            if (!string.IsNullOrWhiteSpace(letter))
            {
                return letter;
            }

            return ExtractAtisLetterFromVatsimData(target);
        }

        private string ExtractAtisLetterFromVatsimData(string target)
        {
            if (vatsimData?.atis == null || string.IsNullOrWhiteSpace(target))
            {
                return string.Empty;
            }

            string cleanTarget = FormatAtisTargetForList(target);
            if (cleanTarget == "ATIS" || cleanTarget == "METAR")
            {
                return string.Empty;
            }

            string exactGeneric = cleanTarget + "_ATIS";

            Atis[] candidates = vatsimData.atis
                .Where(atis => !string.IsNullOrWhiteSpace(atis.callsign))
                .OrderBy(atis => string.Equals(atis.callsign, exactGeneric, StringComparison.OrdinalIgnoreCase) ? 0 : 1)
                .ThenBy(atis => atis.callsign)
                .ToArray();

            foreach (Atis atis in candidates)
            {
                string callsign = atis.callsign.ToUpperInvariant();

                if (!string.Equals(callsign, exactGeneric, StringComparison.Ordinal) &&
                    !callsign.StartsWith(cleanTarget + "_", StringComparison.Ordinal))
                {
                    continue;
                }

                string code = (atis.atis_code ?? string.Empty).Trim().ToUpperInvariant();
                if (code.Length > 0 && char.IsLetter(code[0]))
                {
                    return code[0].ToString();
                }

                if (atis.text_atis != null && atis.text_atis.Length > 0)
                {
                    string fromText = ExtractAtisInformationLetter(string.Join(" ", atis.text_atis));
                    if (!string.IsNullOrWhiteSpace(fromText))
                    {
                        return fromText;
                    }
                }
            }

            return string.Empty;
        }

        private static string ExtractAtisInformationLetter(string contents)
        {
            if (string.IsNullOrWhiteSpace(contents))
            {
                return string.Empty;
            }

            string upper = contents.ToUpperInvariant();

            const string natoOrLetter = "ALPHA|BRAVO|CHARLIE|DELTA|ECHO|FOXTROT|GOLF|HOTEL|INDIA|JULIET|KILO|LIMA|MIKE|NOVEMBER|OSCAR|PAPA|QUEBEC|ROMEO|SIERRA|TANGO|UNIFORM|VICTOR|WHISKEY|XRAY|X-RAY|YANKEE|ZULU|[A-Z]";

            Match match = Regex.Match(
                upper,
                @"\b(?:INFORMATION|INFO)\s*[:\-]?\s*(" + natoOrLetter + @")\b");

            if (!match.Success)
            {
                match = Regex.Match(upper, @"\bATIS\s+(" + natoOrLetter + @")\s+(?:RECEIVED|AT|VALID|QNH|RWY|RUNWAY)\b");
            }

            if (!match.Success)
            {
                match = Regex.Match(
                    upper,
                    @"\b[A-Z0-9]{4}\s+(?:DEP\s+ARR|ARR\s+DEP|DEP|ARR)(?:\s+ATIS)?\s+(" + natoOrLetter + @")\b");
            }

            if (!match.Success)
            {
                return string.Empty;
            }

            string value = match.Groups[1].Value.Replace("-", string.Empty);

            return value.Length == 1 ? value : value[0].ToString();
        }

        private bool ShouldEmphasizeAtisLetter(CPDLCMessage message)
        {
            if (message == null || message.outbound)
            {
                return false;
            }

            return Regex.IsMatch(message.Text ?? string.Empty, @"\bATIS\s+[A-Z?]\s+RECEIVED\b");
        }

        private CPDLCMessage CreateCPDLCMessage(string _contents, string _type, string _recipient, bool _outbound = false, CPDLCResponse _header = null)
        {
            string previewType = (_type ?? string.Empty).Trim().ToUpperInvariant();
            string listText = CreateMessageListText(_contents, _type, _recipient, _outbound);
            bool emphasizeAtisLetter = !_outbound &&
                !listText.Contains("\n") &&
                Regex.IsMatch(listText, @"\bATIS\s+[A-Z?]\s+RECEIVED\b");

            bool needsReplyIndicator = MessageNeedsOverviewReplyIndicator(previewType, _outbound, _header);

            CPDLCMessage _message = emphasizeAtisLetter
                ? new AtisOverviewMessage(_type, _recipient, _contents, _outbound, _header)
                : new CPDLCMessage(_type, _recipient, _contents, _outbound, _header);

            if (_message is AtisOverviewMessage atisMessage)
            {
                atisMessage.BoldAtisLetter = true;
                atisMessage.AtisLetterBoldFont = CreateDpiStablePixelFont(GetMessageTextFont(true).FontFamily, GetMessageTextFont(true).Size + 0.25f, FontStyle.Bold);
            }

            _message.AutoSize = true;
            _message.BackColor = Color.Transparent;
            _message.ForeColor = MainPrimaryTextColor();
            _message.Font = GetMessageTextFont(false);
            _message.Text = listText;

            if (IsCpdlcStationDetectedText(_contents))
            {
                _message.ForeColor = DcduTheme.Amber;
                _message.Font = GetMessageTextFont(true);
            }
            else if (IsCallsignMismatchAlarmText(_contents))
            {
                _message.ForeColor = CallsignMismatchAlarmColor();
                _message.Font = GetMessageTextFont(true);
            }

            _message.BorderStyle = BorderStyle.None;
            _message.TabStop = true;
            _message.TabIndex = 0;
            _message.Margin = SPad(new Padding(0, 3, 0, 0));

            return _message;
        }

        private Control CreateOverviewTimeLabel(string timeText, CPDLCMessage message)
        {
            if (MessageNeedsOverviewReplyIndicator(message?.type, message?.outbound ?? false, message?.header))
            {
                ReplyStatusTimeLabel label = new()
                {
                    AutoSize = false,
                    Width = S(70),
                    Height = S(18),
                    BackColor = Color.Transparent,
                    ForeColor = MainPrimaryTextColor(),
                    Font = textFont,
                    Text = timeText,
                    TimeText = timeText,
                    StatusMarker = "◷",
                    StatusMarkerColor = DcduTheme.Amber,
                    BorderStyle = BorderStyle.None,
                    Margin = SPad(new Padding(5, 3, 0, 0)),
                    TabStop = false
                };

                return label;
            }

            return CreateLabel(timeText);
        }

        private ReplyStatusTimeLabel FindReplyStatusTimeLabelForMessage(CPDLCMessage message)
        {
            if (message == null || outputTable == null || outputTable.IsDisposed)
            {
                return null;
            }

            try
            {
                TableLayoutPanelCellPosition pos = outputTable.GetPositionFromControl(message);
                if (pos.Row >= 0 && outputTable.GetControlFromPosition(0, pos.Row) is ReplyStatusTimeLabel label)
                {
                    return label;
                }
            }
            catch
            {
                // Visual helper only.
            }

            return null;
        }

        private void SetReplyStatusTimeLabel(CPDLCMessage message, string marker, Color markerColor)
        {
            ReplyStatusTimeLabel label = FindReplyStatusTimeLabelForMessage(message);
            if (label == null || label.IsDisposed)
            {
                return;
            }

            label.StatusMarker = marker ?? string.Empty;
            label.StatusMarkerColor = markerColor;
            label.ForeColor = MainPrimaryTextColor();
            label.Invalidate();
        }

        private AccessibleLabel CreateLabel(string _text, bool _useMaxSize = true)
        {
            Size maxSize = new()
            {
                Width = 65
            };

            bool isPreviewMessageText = !_useMaxSize;

            AccessibleLabel _message = new(MainPrimaryTextColor())
            {
                Width = 65,
                AutoSize = true,
                BackColor = Color.Transparent,
                ForeColor = MainPrimaryTextColor(),
                Font = isPreviewMessageText ? GetMessageTextFont(false) : textFont,
                Text = _text,
                BorderStyle = BorderStyle.None,
                Margin = new Padding(5, 3, 0, 0),
                TabStop = true,
                TabIndex = 0,
                Tag = isPreviewMessageText ? MessagePreviewTextTag : null
            };

            if (_useMaxSize)
            {
                _message.MaximumSize = maxSize;
            }
            else
            {
                int previewWidth = Math.Max(220, (messageFormatPanel?.ClientSize.Width ?? 430) - 58);
                _message.Width = previewWidth;
                _message.MaximumSize = new Size(previewWidth, 0);
            }

            SetStyle(ControlStyles.Selectable, true);
            return _message;
        }

        private AccessibleLabel CreateSpecialLabel(string _text, bool _useMaxSize = true)
        {
            string displayText = NormalizeActionButtonText(_text);
            Color buttonColor = ActionButtonColor(displayText);
            Color idleTextColor = DcduStyleManager.IsBoeing ? MainPrimaryTextColor() : Color.FromArgb(224, 242, 248);
            Size buttonSize = ActionButtonSize(displayText);

            AccessibleLabel _message = new(buttonColor)
            {
                AutoSize = false,
                BackColor = Color.Transparent,
                ForeColor = idleTextColor,
                Font = DcduStyleManager.IsBoeing
                    ? CreateDpiStablePointFont("Segoe UI Semibold", 7.8f, FontStyle.Regular)
                    : CreateDpiStablePixelFont(textFontBold.FontFamily, Math.Max(8.2f, textFontBold.Size - 1.7f), FontStyle.Bold),
                Text = displayText,
                BorderStyle = BorderStyle.None,
                TextAlign = ContentAlignment.MiddleCenter,
                Padding = DcduStyleManager.IsBoeing ? new Padding(7, 0, 7, 0) : new Padding(7, 0, 7, 1),
                Margin = DcduStyleManager.IsBoeing ? new Padding(4, 4, 3, 4) : new Padding(4, 5, 3, 2),
                TabStop = true,
                TabIndex = 0,
                Cursor = Cursors.Hand,
                Size = buttonSize,
                MinimumSize = buttonSize
            };

            _message.Paint += ActionButton_Paint;
            _message.MouseEnter += (_, __) =>
            {
                _message.ForeColor = Color.White;
                _message.Invalidate();
            };
            _message.MouseLeave += (_, __) =>
            {
                _message.ForeColor = idleTextColor;
                _message.Invalidate();
            };
            _message.MouseDown += (_, __) =>
            {
                _message.Tag = "PRESSED";
                _message.Invalidate();
            };
            _message.MouseUp += (_, __) =>
            {
                _message.Tag = null;
                _message.Invalidate();
            };

            return _message;
        }

        private string NormalizeActionButtonText(string text)
        {
            string cleaned = (text ?? string.Empty)
                .Replace(">", string.Empty)
                .Replace("<", string.Empty)
                .Replace("*", string.Empty)
                .Trim()
                .ToUpperInvariant();

            return cleaned switch
            {
                "FREE TEXT" => "FREE TXT",
                "AFFIRMATIVE" => "AFFIRM",
                "NEGATIVE" => "NEG",
                _ => cleaned
            };
        }

        private Size ActionButtonSize(string text)
        {
            string displayText = string.IsNullOrWhiteSpace(text) ? "ACTION" : text.Trim().ToUpperInvariant();
            Size measured = TextRenderer.MeasureText(displayText, textFontBold);
            int width = Math.Max(58, measured.Width + 22);

            if (displayText.Contains("STANDBY"))
            {
                width = Math.Max(width, 78);
            }
            else if (displayText.Contains("FREE"))
            {
                width = Math.Max(width, 78);
            }
            else if (displayText.Contains("AFFIRM"))
            {
                width = Math.Max(width, 74);
            }

            return new Size(width, 22);
        }

        private Color ActionButtonColor(string text)
        {
            string upper = (text ?? string.Empty).ToUpperInvariant();

            if (upper.Contains("ACCEPT") ||
                upper.Contains("WILCO") ||
                upper.Contains("ROGER") ||
                upper.Contains("AFFIRM") ||
                upper.Contains("LOGON"))
            {
                return DcduTheme.Green;
            }

            if (upper.Contains("REJECT") ||
                upper.Contains("UNABLE") ||
                upper == "NEG" ||
                upper.Contains("DELETE"))
            {
                return DcduTheme.Amber;
            }

            if (upper.Contains("STANDBY"))
            {
                return DcduTheme.Amber;
            }

            return MainAccentColor();
        }

        private bool IsColoredActionHover(string text)
        {
            string upper = (text ?? string.Empty).ToUpperInvariant();

            return upper.Contains("DELETE") ||
                   upper.Contains("REJECT") ||
                   upper.Contains("UNABLE") ||
                   upper == "NEG" ||
                   upper.Contains("STANDBY") ||
                   upper.Contains("ACCEPT") ||
                   upper.Contains("WILCO") ||
                   upper.Contains("ROGER") ||
                   upper.Contains("AFFIRM") ||
                   upper.Contains("LOGON") ||
                   upper.Contains("FREE TXT");
        }

        private Color ActionButtonIdleAccent()
        {
            return DcduStyleManager.IsBoeing
                ? Color.FromArgb(122, 132, 141)
                : Color.FromArgb(88, 136, 152);
        }

        private Color ActionButtonHoverAccent(string text)
        {
            if (IsColoredActionHover(text))
            {
                return DcduStyleManager.IsBoeing
                    ? Color.FromArgb(206, 166, 96)
                    : Color.FromArgb(214, 176, 104);
            }

            return DcduStyleManager.IsBoeing
                ? Color.FromArgb(196, 202, 208)
                : Color.FromArgb(86, 186, 216);
        }

        private void ActionButton_Paint(object sender, PaintEventArgs e)
        {
            if (sender is not System.Windows.Forms.Label label)
            {
                return;
            }

            Rectangle bounds = new Rectangle(0, 0, Math.Max(1, label.Width - 1), Math.Max(1, label.Height - 1));
            bool focused = label.Focused;
            bool hovered = label.ClientRectangle.Contains(label.PointToClient(Cursor.Position));
            bool pressed = string.Equals(label.Tag as string, "PRESSED", StringComparison.OrdinalIgnoreCase);

            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;

            Color hoverAccent = ActionButtonHoverAccent(label.Text);
            Color idleAccent = ActionButtonIdleAccent();
            Color softAccent = (focused || hovered) ? hoverAccent : idleAccent;

            Color fillTop = pressed
                ? Color.FromArgb(28, 35, 42)
                : Color.FromArgb(DcduStyleManager.IsBoeing ? 14 : 10, 20, 28);
            Color fillBottom = pressed
                ? Color.FromArgb(4, 8, 12)
                : Color.FromArgb(DcduStyleManager.IsBoeing ? 3 : 2, 6, 11);

            using GraphicsPath path = RoundedButtonRect(bounds, DcduStyleManager.IsBoeing ? 3 : 4);
            using LinearGradientBrush fill = new LinearGradientBrush(bounds, fillTop, fillBottom, LinearGradientMode.Vertical);
            using SolidBrush subtleWash = new SolidBrush(Color.FromArgb((focused || hovered) ? 24 : 3, softAccent));
            using Pen border = new Pen(Color.FromArgb((focused || hovered) ? 245 : 72, softAccent), (focused || hovered) ? 1.55f : 1.0f);
            using Pen topLine = new Pen(Color.FromArgb((focused || hovered) ? 62 : 18, Color.White), 1.0f);

            e.Graphics.FillPath(fill, path);
            e.Graphics.FillPath(subtleWash, path);
            e.Graphics.DrawPath(border, path);
            e.Graphics.DrawLine(topLine, bounds.Left + 5, bounds.Top + 1, bounds.Right - 5, bounds.Top + 1);

            Rectangle textRect = Rectangle.Inflate(bounds, -5, -2);
            Color textColor = (focused || hovered)
                ? (DcduStyleManager.IsBoeing ? Color.FromArgb(242, 248, 252) : Color.FromArgb(238, 252, 255))
                : (DcduStyleManager.IsBoeing ? MainPrimaryTextColor() : Color.FromArgb(224, 242, 248));

            TextRenderer.DrawText(
                e.Graphics,
                label.Text,
                label.Font,
                pressed ? new Rectangle(textRect.X + 1, textRect.Y + 1, textRect.Width, textRect.Height) : textRect,
                textColor,
                TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter | TextFormatFlags.NoPadding);
        }

        private static GraphicsPath RoundedButtonRect(Rectangle bounds, int radius)
        {
            int diameter = Math.Max(2, radius * 2);
            Rectangle arc = new Rectangle(bounds.Location, new Size(diameter, diameter));
            GraphicsPath path = new();

            path.AddArc(arc, 180, 90);
            arc.X = bounds.Right - diameter;
            path.AddArc(arc, 270, 90);
            arc.Y = bounds.Bottom - diameter;
            path.AddArc(arc, 0, 90);
            arc.X = bounds.Left;
            path.AddArc(arc, 90, 90);
            path.CloseFigure();

            return path;
        }

        private bool ShouldAutoDeleteRequestMessage(CPDLCMessage message)
        {
            if (message == null || !AutoDeleteRequestMessages)
            {
                return false;
            }

            string type = (message.type ?? string.Empty).Trim().ToUpperInvariant();
            string text = (message.message ?? string.Empty).Trim().ToUpperInvariant();

            // Harmless generic SYSTEM lines can be auto-cleaned. Keep interactive /
            // safety-critical system messages visible below.
            if (type == "SYSTEM" || text == "SYSTEM MESSAGE")
            {
                if (IsCallsignMismatchAlarmText(text) ||
                    IsCpdlcStationDetectedText(text) ||
                    text.Contains("CPDLC WATCH") ||
                    text.Contains("VERIFIED ACTIVE FREQUENCY") ||
                    text.Contains("ACTIVE FREQUENCY CPDLC") ||
                    text.Contains("POSSIBLE CPDLC STATION") ||
                    text.Contains("VATSIM CALLSIGN MISMATCH") ||
                    text.Contains("NEW FP") ||
                    IsClearanceStatusText(text))
                {
                    return false;
                }

                return true;
            }

            // Short CPDLC connection/reply status noise can be auto-cleaned.
            // Actual controller uplinks remain visible/interactive.
            if (type == "CPDLC" && IsCpdlcDirectStatusText(text))
            {
                return true;
            }

            // Keep important/interactive messages visible.
            if (type == "CPDLC" ||
                IsCallsignMismatchAlarmText(text) ||
                IsCpdlcStationDetectedText(text) ||
                text.Contains("PREDEP") ||
                text.Contains("PDC") ||
                text.Contains("CLEARANCE") ||
                text.Contains("NEW FP") ||
                IsClearanceStatusText(text))
            {
                return false;
            }

            // Unavailable weather responses are status noise and can be auto-cleaned.
            if ((type == "ATIS" || type == "METAR") &&
                (text.Contains("NOT AVAILABLE") ||
                 text.Contains("NO METAR") ||
                 text.Contains("METAR NOT") ||
                 text.Contains("ATIS NOT")))
            {
                return true;
            }

            // Only outgoing request lines should be auto-cleaned. Inbound actual METAR/ATIS
            // responses must keep their normal open button.
            if (!message.outbound)
            {
                return false;
            }

            return type == "ATIS" ||
                   type == "METAR" ||
                   text.Contains("REQUESTING ") ||
                   text.Contains(" REQUEST");
        }

        private static int ClampAutoDeleteSeconds(int remainingSeconds)
        {
            return Math.Max(0, Math.Min(99, remainingSeconds));
        }

        private void ConfigureAutoDeleteRequestIndicator(TimerLabel menuLabel)
        {
            if (menuLabel == null)
            {
                return;
            }

            menuLabel.Text = string.Empty;
            menuLabel.AutoSize = false;
            menuLabel.Width = OpenMessageActionsIndicatorWidth();
            menuLabel.Height = S(18);
            menuLabel.TextAlign = ContentAlignment.MiddleRight;
            menuLabel.Paint -= AutoDeleteRequestIndicator_Paint;
            menuLabel.Paint += AutoDeleteRequestIndicator_Paint;
        }

        private void AutoDeleteRequestIndicator_Paint(object sender, PaintEventArgs e)
        {
            if (sender is not TimerLabel label)
            {
                return;
            }

            int remainingSeconds;
            if (label.Tag is AutoDeleteCountdownState state)
            {
                remainingSeconds = state.DisplayedSeconds;
            }
            else if (label.Tag is int legacyRemainingSeconds)
            {
                remainingSeconds = legacyRemainingSeconds;
            }
            else
            {
                return;
            }

            remainingSeconds = ClampAutoDeleteSeconds(remainingSeconds);

            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;

            bool blinkOn = remainingSeconds % 2 == 0;
            Color accent = blinkOn ? DcduTheme.Amber : NeutralStatusBadgeColor();

            int rightMargin = ScaleUi(2);
            int secondsWidth = ScaleUi(24);
            int secondsHeight = Math.Max(1, label.Height - ScaleUi(1));
            Rectangle secondsRect = new Rectangle(
                Math.Max(0, label.Width - secondsWidth - rightMargin),
                ScaleUi(1),
                secondsWidth,
                secondsHeight);

            Rectangle trash = new Rectangle(
                Math.Max(0, secondsRect.Left - ScaleUi(17)),
                ScaleUi(2),
                ScaleUi(13),
                ScaleUi(14));

            using Pen pen = new Pen(accent, Math.Max(1.0f, ScaleUi(1.2f)));

            // Draw a small trash can icon manually instead of relying on emoji font support.
            e.Graphics.DrawLine(pen, trash.Left + ScaleUi(2), trash.Top + ScaleUi(2), trash.Right - ScaleUi(2), trash.Top + ScaleUi(2));       // lid
            e.Graphics.DrawLine(pen, trash.Left + ScaleUi(5), trash.Top, trash.Right - ScaleUi(5), trash.Top);             // handle
            e.Graphics.DrawRectangle(pen, trash.Left + ScaleUi(3), trash.Top + ScaleUi(4), trash.Width - ScaleUi(6), trash.Height - ScaleUi(5));
            e.Graphics.DrawLine(pen, trash.Left + ScaleUi(6), trash.Top + ScaleUi(6), trash.Left + ScaleUi(6), trash.Bottom - ScaleUi(2));
            e.Graphics.DrawLine(pen, trash.Right - ScaleUi(6), trash.Top + ScaleUi(6), trash.Right - ScaleUi(6), trash.Bottom - ScaleUi(2));

            string secondsText = remainingSeconds.ToString("00");
            using Font smallFont = new Font(
                label.Font.FontFamily,
                Math.Max(1.0f, label.Font.Size - ScaleUi(2.2f)),
                FontStyle.Bold,
                GraphicsUnit.Pixel);

            TextRenderer.DrawText(
                e.Graphics,
                secondsText,
                smallFont,
                secondsRect,
                accent,
                TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter | TextFormatFlags.NoPadding | TextFormatFlags.NoClipping);
        }

