        private void ApplyAutoDeleteToExistingEligibleMessages()
        {
            if (outputTable == null || outputTable.IsDisposed || !AutoDeleteRequestMessages)
            {
                return;
            }

            try
            {
                foreach (CPDLCMessage message in outputTable.Controls.OfType<CPDLCMessage>().ToList())
                {
                    if (message == null ||
                        message.IsDisposed ||
                        autoDeleteRequestTimers.ContainsKey(message) ||
                        !ShouldAutoDeleteRequestMessage(message))
                    {
                        continue;
                    }

                    TableLayoutPanelCellPosition pos = outputTable.GetPositionFromControl(message);
                    if (pos.Row < 0)
                    {
                        continue;
                    }

                    if (outputTable.GetControlFromPosition(2, pos.Row) is TimerLabel menuLabel)
                    {
                        StartAutoDeleteRequestMessageIfNeeded(message, menuLabel);
                    }
                }
            }
            catch
            {
                // Cosmetic cleanup only.
            }
        }

        private void StartAutoDeleteRequestMessageIfNeeded(CPDLCMessage message, TimerLabel menuLabel)
        {
            if (message == null || menuLabel == null || !ShouldAutoDeleteRequestMessage(message))
            {
                return;
            }

            StopAutoDeleteRequestMessage(message, false);

            TimeSpan requestMessageAutoDeleteDelay = RequestMessageAutoDeleteDelay;
            DateTime dueUtc = DateTime.UtcNow + requestMessageAutoDeleteDelay;
            AutoDeleteCountdownState countdownState = new()
            {
                DueUtc = dueUtc,
                DisplayedSeconds = ClampAutoDeleteSeconds((int)Math.Ceiling(requestMessageAutoDeleteDelay.TotalSeconds)),
                DueReached = false
            };

            System.Windows.Forms.Timer timer = new()
            {
                // Use a sub-second UI timer and smooth the visible value. If the UI thread
                // stalls for a moment, the countdown no longer jumps from e.g. 20 to 17.
                Interval = 250
            };

            timer.Tick += (_, __) =>
            {
                if (message.IsDisposed || outputTable == null || outputTable.IsDisposed)
                {
                    StopAutoDeleteRequestMessage(message, false);
                    return;
                }

                int actualRemaining = ClampAutoDeleteSeconds((int)Math.Ceiling((countdownState.DueUtc - DateTime.UtcNow).TotalSeconds));
                int displayRemaining = countdownState.DisplayedSeconds;

                if (actualRemaining <= 0)
                {
                    if (displayRemaining > 0)
                    {
                        displayRemaining -= 1;
                    }
                    else
                    {
                        countdownState.DueReached = true;
                    }
                }
                else if (actualRemaining < displayRemaining)
                {
                    // Smooth catch-up: never skip visible numbers.
                    displayRemaining -= 1;
                }
                else if (actualRemaining > displayRemaining)
                {
                    displayRemaining = actualRemaining;
                }

                countdownState.DisplayedSeconds = ClampAutoDeleteSeconds(displayRemaining);

                if (!menuLabel.IsDisposed)
                {
                    menuLabel.Tag = countdownState;
                    menuLabel.ForeColor = DcduTheme.Amber;
                    menuLabel.CanFlash = false;
                    menuLabel.Invalidate();
                }

                if (countdownState.DueReached)
                {
                    StopAutoDeleteRequestMessage(message, false);
                    AutoDeleteMessageRow(message);
                }
            };

            autoDeleteRequestTimers[message] = timer;
            ConfigureAutoDeleteRequestIndicator(menuLabel);
            menuLabel.Tag = countdownState;
            menuLabel.Text = string.Empty;
            menuLabel.ForeColor = DcduTheme.Amber;
            menuLabel.CanFlash = false;
            menuLabel.Invalidate();
            timer.Start();
        }

        private bool StopAutoDeleteRequestMessage(CPDLCMessage message, bool showKept)
        {
            if (message == null)
            {
                return false;
            }

            if (!autoDeleteRequestTimers.TryGetValue(message, out System.Windows.Forms.Timer timer))
            {
                return false;
            }

            timer.Stop();
            timer.Dispose();
            autoDeleteRequestTimers.Remove(message);

            if (autoDeleteActionPopupMessage == message && !showKept)
            {
                HideAutoDeleteActionPopup();
            }

            if (showKept && outputTable != null && !outputTable.IsDisposed)
            {
                try
                {
                    int index = outputTable.Controls.GetChildIndex(message);
                    if (index >= 0 && index + 1 < outputTable.Controls.Count &&
                        outputTable.Controls[index + 1] is TimerLabel menuLabel)
                    {
                        if (ShouldUseDeleteOnlyOverviewAction(message))
                        {
                            ConfigureDeleteOnlyMessageIndicator(menuLabel);
                        }
                        else
                        {
                            ConfigureOpenMessageIndicator(menuLabel);
                        }

                        menuLabel.ForeColor = MainPrimaryTextColor();
                        menuLabel.CanFlash = false;
                        menuLabel.Invalidate();
                    }
                }
                catch
                {
                    // Cosmetic only.
                }
            }

            return true;
        }

        private void StopAllAutoDeleteRequestTimers()
        {
            foreach (System.Windows.Forms.Timer timer in autoDeleteRequestTimers.Values.ToList())
            {
                timer.Stop();
                timer.Dispose();
            }

            autoDeleteRequestTimers.Clear();
        }

        private void AutoDeleteMessageRow(CPDLCMessage message)
        {
            if (message == null || outputTable == null || outputTable.IsDisposed)
            {
                return;
            }

            SafeUi(() =>
            {
                if (message.IsDisposed || outputTable == null || outputTable.IsDisposed)
                {
                    return;
                }

                try
                {
                    if (autoDeleteActionPopupMessage == message)
                    {
                        HideAutoDeleteActionPopup();
                    }

                    MarkMessageRead(message);
                    TableLayoutPanelCellPosition pos = outputTable.GetPositionFromControl(message);
                    int row = pos.Row;

                    if (row < 0)
                    {
                        return;
                    }

                    List<Control> rowControls = outputTable.Controls
                        .Cast<Control>()
                        .Where(control => outputTable.GetPositionFromControl(control).Row == row)
                        .ToList();

                    foreach (Control control in rowControls)
                    {
                        outputTable.Controls.Remove(control);
                        control.Dispose();
                    }

                    if (row < outputTable.RowStyles.Count)
                    {
                        outputTable.RowStyles[row].SizeType = SizeType.Absolute;
                        outputTable.RowStyles[row].Height = 0F;
                    }

                    ClearPreview();
                    ApplyMessageFilter();
                    HideNativeOutputScrollbars();
                }
                catch (Exception ex)
                {
                    Logger.Debug("Auto-delete request message failed: " + ex.Message);
                }
            });
        }

        private TimerLabel CreateTimerLabel(string _text, bool _useMaxSize = true)
        {
            int actionWidth = OpenMessageActionsIndicatorWidth();
            Size maxSize = new()
            {
                Width = actionWidth
            };
            TimerLabel _message = new()
            {
                Width = actionWidth,
                Height = S(18),
                AutoSize = false,
                BackColor = Color.Transparent,
                ForeColor = MainPrimaryTextColor(),
                Font = textFontBold,
                Text = _text,
                BorderStyle = BorderStyle.None,
                Margin = SPad(new Padding(0, 0, 2, 0)),
                Anchor = AnchorStyles.Top | AnchorStyles.Right,
                TextAlign = ContentAlignment.MiddleRight,
            };
            if (_useMaxSize)
            {
                _message.MaximumSize = maxSize;
            }

            if (string.Equals(_text, ">>", StringComparison.OrdinalIgnoreCase))
            {
                ConfigureOpenMessageIndicator(_message);
            }

            return _message;
        }
        private void DeleteMessageRow(CPDLCMessage control)
        {
            if (control == null || outputTable == null || outputTable.IsDisposed)
            {
                return;
            }

            StopAutoDeleteRequestMessage(control, false);
            HideManualDeleteConfirmPopup();
            HideAutoDeleteActionPopup();
            MarkMessageRead(control);
            TableLayoutHelper.RemoveArbitraryRow(outputTable, outputTable.GetPositionFromControl(control).Row);
            ClearPreview();
            ApplyMessageFilter();
            HideNativeOutputScrollbars();
        }

        private void DeleteElement(EventArgs e, CPDLCMessage control)
        {
            try
            {
                KeyEventArgs kE = (KeyEventArgs)e;
                if (kE.KeyCode == Keys.Enter || kE.KeyCode == Keys.Space)
                {
                    throw new Exception();
                }
                else
                {
                    return;
                }
            }
            catch
            {
                DeleteMessageRow(control);
            }
        }

        private void DeleteAllElement(object sender, EventArgs e)
        {
            HideAutoDeleteActionPopup();
            HideManualDeleteConfirmPopup();
            StopAllAutoDeleteRequestTimers();
            ClearUnreadMessages();
            outputTable.Controls.Clear();
            UpdateMessageFilterLabel();
        }

        private void ExportLogElement(object sender, EventArgs e)
        {
            try
            {
                string path = ExportMessageLog();
                WriteMessage("MESSAGE LOG EXPORTED\n" + path, "SYSTEM", "SYSTEM");
            }
            catch (Exception ex)
            {
                Logger.Error("Unable to export message log: " + ex.Message);
                WriteMessage("UNABLE TO EXPORT MESSAGE LOG", "SYSTEM", "SYSTEM");
            }
        }

        private string ExportMessageLog()
        {
            string filename = "EasyCPDLC_MessageLog_" + DateTime.Now.ToString("yyyyMMdd_HHmmss") + ".txt";
            string path = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, filename);

            List<CPDLCMessage> messages = outputTable == null || outputTable.IsDisposed
                ? new List<CPDLCMessage>()
                : outputTable.Controls.OfType<CPDLCMessage>().ToList();

            messages = messages
                .OrderBy(message => outputTable.GetPositionFromControl(message).Row)
                .ToList();

            using StreamWriter writer = new StreamWriter(path, false);

            writer.WriteLine("EasyCPDLC Message Export");
            writer.WriteLine("Created: " + DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss"));
            writer.WriteLine();

            foreach (CPDLCMessage message in messages)
            {
                int row = outputTable.GetPositionFromControl(message).Row;
                string time = string.Empty;

                if (outputTable.GetControlFromPosition(0, row) is System.Windows.Forms.Label timeLabel)
                {
                    time = timeLabel.Text;
                }

                writer.WriteLine("[" + time + "] " + message.Text);
                writer.WriteLine("TYPE: " + message.type + "  " + (message.outbound ? "OUTBOUND" : "INBOUND") + "  STATION: " + message.recipient);
                writer.WriteLine(message.message ?? string.Empty);
                writer.WriteLine(new string('-', 72));
            }

            return path;
        }

        private void WeatherCacheElement(object sender, EventArgs e)
        {
            WriteMessage(BuildWeatherCacheMessage(), "SYSTEM", "SYSTEM");
        }

        private string BuildWeatherCacheMessage()
        {
            if (weatherCache.Count == 0)
            {
                return "WX CACHE EMPTY";
            }

            List<string> lines = new()
            {
                "WX CACHE"
            };

            foreach (WeatherCacheItem item in weatherCache.Values.OrderByDescending(item => item.TimestampUtc).Take(8))
            {
                lines.Add(item.TimestampUtc.ToLocalTime().ToString("HH:mm") + " " +
                    item.Target + " " + item.Type + " " + item.Summary);
            }

            return string.Join("\n", lines);
        }

        private string GetPreviewMessageText(CPDLCMessage message)
        {
            if (message == null)
            {
                return string.Empty;
            }

            string text = message.message ?? string.Empty;
            string normalizedType = (message.type ?? string.Empty).Trim().ToUpperInvariant();
            string normalizedRecipient = (message.recipient ?? string.Empty).Trim().ToUpperInvariant();

            if (ShouldUseAtisListText(text, normalizedType, normalizedRecipient) ||
                MessageLooksAtis(message) ||
                string.Equals(normalizedRecipient, "VATATIS", StringComparison.OrdinalIgnoreCase) ||
                text.IndexOf(" ATIS ", StringComparison.OrdinalIgnoreCase) >= 0 ||
                Regex.IsMatch(text, @"\b[A-Z0-9]{4}_[AD](?:_ATIS)?\b", RegexOptions.IgnoreCase))
            {
                return FormatAtisPreviewText(text);
            }

            return WrapPreviewText(text, GetPreviewWrapLength());
        }

        private int GetPreviewWrapLength()
        {
            // Boeing uses a wider visual font/spacing in the styled preview.
            // 52 chars can pass the character wrap check but still clip on the
            // physical DCDU screen, e.g. "... REQUEST BEING PROCESSED STANDBY".
            return DcduStyleManager.IsBoeing ? 45 : 50;
        }

        private string FormatAtisPreviewText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return string.Empty;
            }

            string normalized = text
                .Replace("\r\n", "\n")
                .Replace("\r", "\n")
                .Replace("\t", " ")
                .ToUpperInvariant();

            normalized = Regex.Replace(normalized, @"[ ]+", " ");
            normalized = Regex.Replace(normalized, @" *\n *", "\n").Trim();

            if (string.IsNullOrWhiteSpace(normalized))
            {
                return string.Empty;
            }

            // If VATSIM/vPilot already gave us real ATIS lines, keep them.
            // Only apply section splitting to single-line or obviously overlong lines.
            List<string> sourceLines = normalized
                .Split('\n')
                .Select(line => Regex.Replace(line.Trim(), @"\s+", " "))
                .Where(line => !string.IsNullOrWhiteSpace(line))
                .ToList();

            List<string> outputLines = new();

            foreach (string sourceLine in sourceLines)
            {
                if (sourceLine.Length > GetAtisPreviewWrapLength() * 2 || !normalized.Contains("\n"))
                {
                    outputLines.AddRange(InsertAtisPreviewSectionBreaks(sourceLine)
                        .Split('\n')
                        .Select(line => Regex.Replace(line.Trim(), @"\s+", " "))
                        .Where(line => !string.IsNullOrWhiteSpace(line)));
                }
                else
                {
                    outputLines.Add(sourceLine);
                }
            }

            string formatted = string.Join("\n", outputLines);
            formatted = Regex.Replace(
                formatted,
                @"\bAT\s*\n\s*TIME\b",
                "AT TIME",
                RegexOptions.IgnoreCase);

            return WrapPreviewText(formatted, GetAtisPreviewWrapLength());
        }

        private int GetAtisPreviewWrapLength()
        {
            return DcduStyleManager.IsBoeing ? 45 : 48;
        }

        private static string InsertAtisPreviewSectionBreaks(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return string.Empty;
            }

            string result = Regex.Replace(text.Trim(), @"\s+", " ");

            string[] sectionStarts =
            {
                @"AT\s+TIME\b",
                @"DEP\s+RWY\b",
                @"DEP\s+RWYS\b",
                @"ARR\s+RWY\b",
                @"ARR\s+RWYS\b",
                @"EXP\s+",
                @"SFC\s+WIND\b",
                @"CAVOK\b",
                @"T\s+[-+]?[0-9]{1,2}\b",
                @"DP\s+[-+]?[0-9]{1,2}\b",
                @"QNH\s*[0-9]{3,4}\b",
                @"NOSIG\b",
                @"ADZ\s+",
                @"DURING\s+",
                @"MNM\s+",
                @"ACFT\s+",
                @"ENHANCE\s+",
                @"SQUAWK\s+",
                @"CAUTION\s+",
                @"ADVS\s+",
                @"CONFIRM\s+",
                @"END\s+OF\s+ATIS\b"
            };

            foreach (string sectionStart in sectionStarts)
            {
                result = Regex.Replace(
                    result,
                    @"(?<!^)\s+(" + sectionStart + @")",
                    "\n$1",
                    RegexOptions.IgnoreCase);
            }

            result = Regex.Replace(result, @"\bAT\s*\n\s*TIME\b", "AT TIME", RegexOptions.IgnoreCase);
            return Regex.Replace(result, @"\n{2,}", "\n").Trim();
        }

        private static int GetPreviewVisibleLength(string text)
        {
            if (string.IsNullOrEmpty(text))
            {
                return 0;
            }

            // @...@ markers are formatting markers only. They are not visible
            // characters on the DCDU and must not affect wrapping.
            return text.Count(character => character != '@');
        }

        private static int FindPreviewWrapBreakIndex(string line, int maxVisibleChars)
        {
            if (string.IsNullOrEmpty(line))
            {
                return -1;
            }

            int visible = 0;
            int lastSpaceIndex = -1;
            int visibleAtLastSpace = 0;

            for (int i = 0; i < line.Length; i++)
            {
                char character = line[i];

                if (character != '@')
                {
                    visible++;
                }

                if (character == ' ')
                {
                    lastSpaceIndex = i;
                    visibleAtLastSpace = visible;
                }

                if (visible > maxVisibleChars)
                {
                    if (lastSpaceIndex >= 0 && visibleAtLastSpace >= maxVisibleChars / 2)
                    {
                        return lastSpaceIndex;
                    }

                    return i;
                }
            }

            return -1;
        }

        private static string WrapPreviewText(string text, int maxChars)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return string.Empty;
            }

            maxChars = Math.Max(24, maxChars);

            List<string> wrappedLines = new();

            foreach (string rawLine in text.Replace("\r\n", "\n").Replace("\r", "\n").Split('\n'))
            {
                string line = Regex.Replace(rawLine.Trim(), @"[ ]+", " ");

                if (line.Length == 0)
                {
                    continue;
                }

                while (GetPreviewVisibleLength(line) > maxChars)
                {
                    int breakAt = FindPreviewWrapBreakIndex(line, maxChars);

                    if (breakAt < 1)
                    {
                        breakAt = Math.Min(line.Length, maxChars);
                    }

                    wrappedLines.Add(line.Substring(0, breakAt).Trim());
                    line = line.Substring(Math.Min(breakAt + 1, line.Length)).Trim();
                }

                if (line.Length > 0)
                {
                    wrappedLines.Add(line);
                }
            }

            return string.Join("\n", wrappedLines);
        }

        private static string NormalizeClearanceHoverText(string contents)
        {
            if (string.IsNullOrWhiteSpace(contents))
            {
                return string.Empty;
            }

            string normalized = contents
                .Replace("\r\n", "\n")
                .Replace("\r", "\n")
                .Replace("@@", " N/A ")
                .Replace("_", " ")
                .ToUpperInvariant();

            // @...@ marks values for the styled message preview. In the CLR hover
            // popup these markers must become plain inline text, not hard line breaks.
            normalized = Regex.Replace(normalized, @"@([^@]+)@", " $1 ");
            normalized = normalized.Replace("@", " ");

            List<string> sourceLines = normalized
                .Split('\n')
                .Select(line => Regex.Replace(line, @"\s+", " ").Trim())
                .Where(line => !string.IsNullOrWhiteSpace(line))
                .ToList();

            if (sourceLines.Count == 0)
            {
                return string.Empty;
            }

            List<string> outputLines = new()
            {
                "CLR RECEIVED"
            };

            foreach (string sourceLine in sourceLines)
            {
                string line = sourceLine;

                while (line.Length > 38)
                {
                    int split = line.LastIndexOf(' ', Math.Min(38, line.Length - 1));
                    if (split < 14)
                    {
                        split = Math.Min(38, line.Length);
                    }

                    outputLines.Add(line.Substring(0, split).Trim());
                    line = line.Substring(split).Trim();
                }

                if (!string.IsNullOrWhiteSpace(line))
                {
                    outputLines.Add(line);
                }
            }

            return string.Join("\n", outputLines);
        }

        private static bool IsClearanceConfirmationText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            string upper = text.ToUpperInvariant();

            return upper.Contains("CLEARANCE CONFIRMED") ||
                   upper.Contains("CLEARANCE CONFIRM") ||
                   (upper.Contains("RECEIVED CLEARANCE") && upper.Contains("CONFIRM")) ||
                   upper.Contains("CLR CONFIRMED");
        }

        private static bool IsClearanceDeliveryText(string text)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return false;
            }

            string upper = text.ToUpperInvariant();

            if (IsClearanceConfirmationText(upper))
            {
                return false;
            }

            return upper.Contains("CLR TO") ||
                   upper.Contains("CLRD TO") ||
                   upper.Contains("CLEARED TO") ||
                   upper.Contains("PREDEP") ||
                   upper.Contains("PDC");
        }

        private string BuildClearanceHoverPopupText()
        {
            if (IsAirborneForStatusBadges())
            {
                return "NOT AVAIL WHEN AIRBORNE";
            }

            if (!string.IsNullOrWhiteSpace(lastClearanceHoverText))
            {
                return lastClearanceHoverText;
            }

            string status = (clearanceStatusText ?? string.Empty).ToUpperInvariant();
            if (status.Contains("ACK") && status.Contains("AUTO"))
            {
                return "CONFIRMATION SEND BUT NOT CONFIRMED BY ATC";
            }

            return BuildClearanceTimeline(previewMessage).Replace("CLR TIMELINE  ", string.Empty);
        }

        private Color ClearanceHoverPopupColor()
        {
            if (IsAirborneForStatusBadges())
            {
                return Color.FromArgb(255, 86, 74);
            }

            if (!string.IsNullOrWhiteSpace(lastClearanceHoverText))
            {
                string status = (clearanceStatusText ?? string.Empty).ToUpperInvariant();

                if (status.Contains("REJ"))
                {
                    return Color.FromArgb(255, 86, 74);
                }

                if (status.Contains("ACK") && status.Contains("AUTO"))
                {
                    return DcduTheme.Amber;
                }

                if (status.Contains("ACC"))
                {
                    return DcduTheme.Green;
                }

                return MainPrimaryTextColor();
            }

            return ClearanceTimelineColor(BuildClearanceTimeline(previewMessage));
        }

        private void UpdateClearanceHoverPopupText()
        {
            if (clearanceTimelinePopupPanel == null || clearanceTimelinePopupLabel == null)
            {
                return;
            }

            clearanceTimelinePopupPanel.AutoScrollPosition = Point.Empty;
            clearanceTimelinePopupLabel.MaximumSize = new Size(Math.Max(80, clearanceTimelinePopupPanel.ClientSize.Width - 24), 0);
            clearanceTimelinePopupLabel.Text = BuildClearanceHoverPopupText();
            clearanceTimelinePopupLabel.ForeColor = PopupContentTextColor(ClearanceHoverPopupColor());
            clearanceTimelinePopupLabel.AutoSize = true;
            clearanceTimelinePopupPanel.AutoScrollMinSize = new Size(0, clearanceTimelinePopupLabel.Height + 6);
            clearanceTimelinePopupPanel.Invalidate();
        }

        private void ConfigureClearanceTimelinePopup()
        {
            if (screenPanel == null)
            {
                return;
            }

            if (clearanceTimelinePopupPanel == null)
            {
                clearanceTimelinePopupPanel = new Panel
                {
                    BackColor = Color.Transparent,
                    Visible = false,
                    AutoScroll = true
                };
                clearanceTimelinePopupPanel.Paint += ClearanceTimelinePopup_Paint;
                clearanceTimelinePopupPanel.MouseLeave += (_, __) =>
                {
                    if (!clearanceTimelinePopupPinned)
                    {
                        HideClearanceTimelinePopup();
                    }
                };
                clearanceTimelinePopupPanel.Click += (_, __) => ToggleClearanceTimelinePopup();
                screenPanel.Controls.Add(clearanceTimelinePopupPanel);
            }

            if (clearanceTimelinePopupLabel == null)
            {
                clearanceTimelinePopupLabel = new System.Windows.Forms.Label
                {
                    AutoSize = true,
                    BackColor = Color.Transparent,
                    Font = PopupHeaderFont(),
                    TextAlign = ContentAlignment.TopLeft,
                    Location = SP(new Point(7, 2)),
                    MaximumSize = new Size(S(208), 0),
                    Padding = SPad(new Padding(0, 0, 4, 2)),
                    Cursor = Cursors.Hand
                };
                clearanceTimelinePopupLabel.Click += (_, __) => ToggleClearanceTimelinePopup();
                clearanceTimelinePopupPanel.Controls.Add(clearanceTimelinePopupLabel);
            }
        }

        private void ClearanceTimelinePopup_Paint(object sender, PaintEventArgs e)
        {
            if (sender is not Panel panel)
            {
                return;
            }

            Color accent = clearanceTimelinePopupLabel?.ForeColor ?? MainAccentColor();

            if (DcduStyleManager.IsBoeing)
            {
                PaintStyleAwarePopupPanel(panel, e, accent, clearanceTimelinePopupPinned);
                return;
            }

            Rectangle bounds = new Rectangle(0, 0, Math.Max(1, panel.Width - 1), Math.Max(1, panel.Height - 1));

            e.Graphics.SmoothingMode = SmoothingMode.AntiAlias;
            e.Graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;

            using GraphicsPath path = RoundedButtonRect(bounds, 6);
            using LinearGradientBrush fill = new LinearGradientBrush(
                bounds,
                Color.FromArgb(42, accent),
                Color.FromArgb(13, accent),
                LinearGradientMode.Vertical);
            using Pen border = new Pen(Color.FromArgb(clearanceTimelinePopupPinned ? 190 : 118, accent), clearanceTimelinePopupPinned ? ScaleUi(1.35f) : ScaleUi(1.0f));
            using Pen topLine = new Pen(Color.FromArgb(55, Color.White), 1.0f);

            e.Graphics.FillPath(fill, path);
            e.Graphics.DrawPath(border, path);
            e.Graphics.DrawLine(topLine, bounds.Left + S(6), bounds.Top + S(1), bounds.Right - S(6), bounds.Top + S(1));
        }

        private void ShowClearanceTimelinePopup(bool pin)
        {
            HideAtisAvailabilityPopup();
            ConfigureClearanceTimelinePopup();

            if (clearanceTimelinePopupPanel == null || clearanceTimelinePopupLabel == null)
            {
                return;
            }

            clearanceTimelinePopupPinned = pin || clearanceTimelinePopupPinned;
            UpdateClearanceHoverPopupText();
            clearanceTimelinePopupPanel.Visible = true;
            clearanceTimelinePopupPanel.BringToFront();
            clearanceTimelinePopupPanel.Invalidate();
        }

        private void HideClearanceTimelinePopup()
        {
            clearanceTimelinePopupPinned = false;

            if (clearanceTimelinePopupPanel != null)
            {
                clearanceTimelinePopupPanel.Visible = false;
            }
        }

        private void ToggleClearanceTimelinePopup()
        {
            if (clearanceTimelinePopupPanel != null && clearanceTimelinePopupPanel.Visible && clearanceTimelinePopupPinned)
            {
                HideClearanceTimelinePopup();
                return;
            }

            clearanceTimelinePopupPinned = true;
            ShowClearanceTimelinePopup(true);
        }

        private System.Windows.Forms.Label CreateClearanceTimelineLabel(CPDLCMessage message)
        {
            string timeline = BuildClearanceTimeline(message);

            AccessibleLabel label = new(MainPrimaryTextColor())
            {
                AutoSize = false,
                BackColor = Color.Transparent,
                ForeColor = ClearanceTimelineColor(timeline),
                Font = CreateDpiStablePixelFont(textFontBold.FontFamily, Math.Max(8.0f, textFontBold.Size - 1.2f), FontStyle.Bold),
                Text = timeline,
                TextAlign = ContentAlignment.MiddleLeft,
                Width = Math.Max(240, (messageFormatPanel?.ClientSize.Width ?? 430) - 54),
                Height = 20,
                Margin = new Padding(5, 2, 0, 4),
                TabStop = true,
                TabIndex = 0
            };

            return label;
        }

        private string BuildClearanceTimeline(CPDLCMessage message)
        {
            string status = (clearanceStatusText ?? string.Empty).ToUpperInvariant();

            if (status.Contains("ACK") && status.Contains("AUTO"))
            {
                return "CLR TIMELINE  REQ -> RX -> WILCO ✓ ATC PENDING";
            }

            if (status.Contains("ACC"))
            {
                return "CLR TIMELINE  REQ -> RX -> WILCO ✓";
            }

            if (status.Contains("REJ"))
            {
                return "CLR TIMELINE  REQ -> REJECTED ✕";
            }

            if (status.Contains("RX") || status.Contains("RECEIVED") ||
                (message != null && !message.outbound && IsClearanceStatusText(message.message)))
            {
                return "CLR TIMELINE  REQ -> RX -> WILCO";
            }

            if (status.Contains("REQ"))
            {
                return "CLR TIMELINE  REQ -> WAITING";
            }

            return "CLR TIMELINE  STANDBY";
        }

        private Color ClearanceTimelineColor(string timeline)
        {
            string upper = (timeline ?? string.Empty).ToUpperInvariant();

            if (upper.Contains("ATC PENDING"))
            {
                return DcduTheme.Amber;
            }

            if (upper.Contains("✓"))
            {
                return DcduTheme.Green;
            }

            if (upper.Contains("REJECT"))
            {
                return Color.FromArgb(255, 86, 74);
            }

            if (upper.Contains("WAITING") || upper.Contains("REQ"))
            {
                return DcduTheme.Amber;
            }

            return MainPrimaryTextColor();
        }


        private void HideMainScreenForStyledMessagePreview()
        {
            HideManualDeleteConfirmPopup();
            HideClearanceTimelinePopup();
            HideAtisAvailabilityPopup();
            HideAtisAutoPopup();
            HideQuickWxPopup();
            HideQuickActionButtons();

            Control[] controlsToHide =
            {
                statusCaptionLabel, statusValueLabel, atcUnitLabel, atcUnitDisplay,
                nextAtcUnitLabel, nextAtcUnitDisplay, callsignCaptionLabel, callsignDisplayLabel,
                routeCaptionLabel, callsignRouteLabel, flightPhaseCaptionLabel, flightPhaseLabel,
                messageHeaderLabel, messageFilterLabel, clearanceStatusLabel, datalinkStatusLabel,
                atisStatusLabel, atisAutoStatusLabel, quickWxStatusLabel, cpdlcDiscoveryLabel,
                pdcActionDebugLabel, cpdlcActionDebugLabel, callsignUpdateLabel,
                outputTable, outputScrollBar, SendingProgress
            };

            foreach (Control control in controlsToHide)
            {
                if (control != null && !control.IsDisposed)
                {
                    control.Visible = false;
                    control.Enabled = false;
                }
            }
        }

        private string StyledPreviewHeaderText(CPDLCMessage message)
        {
            string station = (message?.recipient ?? string.Empty).Trim().ToUpperInvariant();
            if (string.IsNullOrWhiteSpace(station))
            {
                station = "----";
            }

            string direction = message != null && message.outbound ? " TO " : " FROM ";
            return DateTime.UtcNow.ToString("HHmm") + "Z" + direction + station;
        }

        private System.Windows.Forms.Label AddStyledPreviewText(Control parent, string text, int x, int y, int width, int height, Color color, Font font, ContentAlignment align = ContentAlignment.MiddleLeft)
        {
            System.Windows.Forms.Label label = new()
            {
                AutoSize = false,
                BackColor = Color.Transparent,
                ForeColor = color,
                Font = font,
                Text = text ?? string.Empty,
                TextAlign = align,
                Location = new Point(x, y),
                Size = new Size(width, height),
                Margin = Padding.Empty,
                Padding = Padding.Empty,
                UseCompatibleTextRendering = false
            };

            parent.Controls.Add(label);
            label.BringToFront();
            return label;
        }

        private void AddStyledPreviewBody(Control parent, string text, int x, int y, int width, int height, Font font)
        {
            if (parent == null || string.IsNullOrEmpty(text))
            {
                return;
            }

            Color baseColor = DcduStyleManager.IsBoeing ? MainPrimaryTextColor() : DcduTheme.CyanWhite;
            Color highlightColor = DcduStyleManager.IsBoeing ? DcduTheme.Green : DcduTheme.Cyan;

            Panel bodyHost = new()
            {
                BackColor = Color.Transparent,
                Margin = Padding.Empty,
                Padding = Padding.Empty,
                Location = new Point(x, y),
                Size = new Size(width, height)
            };
            parent.Controls.Add(bodyHost);
            bodyHost.BringToFront();

            string normalized = (text ?? string.Empty).Replace("\r\n", "\n").Replace("\r", "\n");
            string[] lines = normalized.Split('\n');
            int lineHeight = DcduStyleManager.IsBoeing ? 23 : 24;

            for (int lineIndex = 0; lineIndex < lines.Length; lineIndex++)
            {
                string line = lines[lineIndex] ?? string.Empty;
                int currentX = 0;
                int currentY = lineIndex * lineHeight;
                if (currentY + lineHeight > bodyHost.Height)
                {
                    break;
                }

                foreach (Match match in Regex.Matches(line, "@[^@]+@|[^@]+"))
                {
                    string rawSegment = match.Value;
                    if (string.IsNullOrEmpty(rawSegment))
                    {
                        continue;
                    }

                    bool isHighlighted = rawSegment.Length >= 2 && rawSegment.StartsWith("@") && rawSegment.EndsWith("@");
                    string visibleSegment = isHighlighted ? rawSegment.Substring(1, rawSegment.Length - 2) : rawSegment;
                    if (visibleSegment.Length == 0)
                    {
                        continue;
                    }

                    Size segmentSize = TextRenderer.MeasureText(
                        visibleSegment,
                        font,
                        new Size(int.MaxValue, lineHeight),
                        TextFormatFlags.NoPadding | TextFormatFlags.NoPrefix | TextFormatFlags.SingleLine);

                    System.Windows.Forms.Label label = new()
                    {
                        AutoSize = false,
                        BackColor = Color.Transparent,
                        ForeColor = isHighlighted ? highlightColor : baseColor,
                        Font = font,
                        Text = visibleSegment,
                        TextAlign = ContentAlignment.TopLeft,
                        Location = new Point(currentX, currentY),
                        Size = new Size(Math.Max(2, segmentSize.Width + 12), lineHeight),
                        Margin = Padding.Empty,
                        Padding = Padding.Empty,
                        UseCompatibleTextRendering = false,
                        Tag = MessagePreviewTextTag
                    };

                    bodyHost.Controls.Add(label);
                    label.BringToFront();
                    currentX += Math.Max(1, segmentSize.Width + 12);
                    if (currentX >= bodyHost.Width)
                    {
                        break;
                    }
                }
            }
        }

        private System.Windows.Forms.Label AddStyledMessageAction(
            Control parent,
            string text,
            int x,
            int y,
            int width,
            int height,
            ContentAlignment align,
            Action action)
        {
            System.Windows.Forms.Label label = new()
            {
                AutoSize = false,
                BackColor = Color.Transparent,
                ForeColor = DcduStyleManager.IsBoeing ? MainPrimaryTextColor() : DcduTheme.Cyan,
                Font = DcduStyleManager.IsBoeing
                    ? CreateDpiStablePointFont("Consolas", 11.5f, FontStyle.Bold)
                    : CreateDpiStablePointFont("Consolas", 12.0f, FontStyle.Bold),
                Text = text ?? string.Empty,
                TextAlign = align,
                Location = new Point(x, y),
                Size = new Size(width, height),
                Margin = Padding.Empty,
                Padding = Padding.Empty,
                BorderStyle = BorderStyle.None,
                Cursor = Cursors.Default,
                TabStop = false,
                AccessibleDescription = "DCDU_STYLED_MESSAGE_ACTION"
            };

            // Display-only: the actual clickspot is the physical side button hotspot.
            label.MouseEnter += (_, __) =>
            {
                label.ForeColor = DcduStyleManager.IsBoeing ? MainPrimaryTextColor() : DcduTheme.Cyan;
                label.Invalidate();
            };
            label.MouseLeave += (_, __) =>
            {
                label.ForeColor = DcduStyleManager.IsBoeing ? MainPrimaryTextColor() : DcduTheme.Cyan;
                label.Invalidate();
            };

            parent.Controls.Add(label);
            label.BringToFront();
            return label;
        }


        private bool TryGetStyledMessagePreviewLineSelect(Point location, out bool rightSide, out int index)
        {
            rightSide = false;
            index = 0;

            if (styledMessageReplySendInProgress ||
                previewMessage == null ||
                messageFormatPanel == null ||
                messageFormatPanel.IsDisposed ||
                !messageFormatPanel.Visible)
            {
                return false;
            }

            if (DcduStyleManager.IsBoeing)
            {
                // Boeing message page: lower right rows 5/6 for DELETE/CLOSE or STBY/WILCO.
                if (BoeingTelexRightLskBounds(5).Contains(location))
                {
                    rightSide = true;
                    index = 5;
                    return true;
                }

                if (BoeingTelexRightLskBounds(6).Contains(location))
                {
                    rightSide = true;
                    index = 6;
                    return true;
                }

                if (BoeingTelexLeftLskBounds(5).Contains(location))
                {
                    rightSide = false;
                    index = 5;
                    return true;
                }

                if (BoeingTelexLeftLskBounds(6).Contains(location))
                {
                    rightSide = false;
                    index = 6;
                    return true;
                }
            }
            else
            {
                // Airbus message page: lower right rows 4/5 for DELETE/CLOSE or STBY/WILCO.
                if (AirbusAocRightLskBounds(4).Contains(location))
                {
                    rightSide = true;
                    index = 4;
                    return true;
                }

                if (AirbusAocRightLskBounds(5).Contains(location))
                {
                    rightSide = true;
                    index = 5;
                    return true;
                }

                if (AirbusAocLeftLskBounds(4).Contains(location))
                {
                    rightSide = false;
                    index = 4;
                    return true;
                }

                if (AirbusAocLeftLskBounds(5).Contains(location))
                {
                    rightSide = false;
                    index = 5;
                    return true;
                }
            }

            return false;
        }

        private bool IsStyledMessagePreviewLineSelectHit(Point location)
        {
            return TryGetStyledMessagePreviewLineSelect(location, out _, out _);
        }

        private bool HandleStyledMessagePreviewLineSelectClick(Point location)
        {
            if (!TryGetStyledMessagePreviewLineSelect(location, out bool rightSide, out int index))
            {
                return false;
            }

            HandleStyledMessagePreviewLineSelect(rightSide, index);
            return true;
        }

        private void HandleStyledMessagePreviewLineSelect(bool rightSide, int index)
        {
            CPDLCMessage message = previewMessage;
            if (message == null)
            {
                return;
            }

            string responseCode = (message.header?.Responses ?? "NE").Trim().ToUpperInvariant();
            bool canReply =
                string.Equals(message.type, "CPDLC", StringComparison.OrdinalIgnoreCase) &&
                !message.outbound &&
                !message.acknowledged &&
                message.header != null &&
                !string.IsNullOrWhiteSpace(responseCode) &&
                !string.Equals(responseCode, "NE", StringComparison.OrdinalIgnoreCase);

            bool row1 = DcduStyleManager.IsBoeing ? index == 5 : index == 4;
            bool row2 = DcduStyleManager.IsBoeing ? index == 6 : index == 5;

            if (canReply)
            {
                if (rightSide && row1)
                {
                    ReplyMessage(EventArgs.Empty, message, "STANDBY");
                    return;
                }

                if (!rightSide && row2)
                {
                    ClearPreview();
                    return;
                }

                switch (responseCode)
                {
                    case "WU":
                        if (!rightSide && row1)
                        {
                            ReplyMessage(EventArgs.Empty, message, "UNABLE");
                        }
                        else if (rightSide && row2)
                        {
                            ReplyMessage(EventArgs.Empty, message, "WILCO");
                        }
                        return;

                    case "AN":
                        if (!rightSide && row1)
                        {
                            ReplyMessage(EventArgs.Empty, message, "NEGATIVE");
                        }
                        else if (rightSide && row2)
                        {
                            ReplyMessage(EventArgs.Empty, message, "AFFIRMATIVE");
                        }
                        return;

                    case "R":
                        if (rightSide && row2)
                        {
                            ReplyMessage(EventArgs.Empty, message, "ROGER");
                        }
                        return;
                }

                return;
            }

            if (IsStyledPreviewPrintLsk(DcduStyleManager.IsBoeing, rightSide, index) &&
                DatalinkPrinter.IsPrintableMessage(message))
            {
                PrintDatalinkMessage(message);
                return;
            }

            if (IsStyledPreviewReprintLsk(DcduStyleManager.IsBoeing, rightSide, index) &&
                latestPrintedDatalinkPrintJob != null)
            {
                ReprintButton_Click(boeingReprintButton, EventArgs.Empty);
                return;
            }

            if (rightSide && row1)
            {
                DeleteElement(EventArgs.Empty, message);
                return;
            }

            if (rightSide && row2)
            {
                ClearPreview();
            }
        }

        internal static bool IsStyledPreviewPrintLsk(bool isBoeing, bool rightSide, int index)
        {
            return !rightSide && index == (isBoeing ? 5 : 4);
        }

        internal static bool IsStyledPreviewReprintLsk(bool isBoeing, bool rightSide, int index)
        {
            return !rightSide && index == (isBoeing ? 6 : 5);
        }

        private void AddStyledPreviewActions(Control page, CPDLCMessage message, int separatorY)
        {
            int actionH = 26;
            int leftX = DcduStyleManager.IsBoeing ? 8 : 10;
            int leftW = DcduStyleManager.IsBoeing ? 128 : 132;
            int rightW = DcduStyleManager.IsBoeing ? 104 : 96;
            int rightX = Math.Max(8, page.Width - rightW - (DcduStyleManager.IsBoeing ? 6 : 6));

            int leftRow1 = DcduStyleManager.IsBoeing
                ? BoeingTelexLskTextY(page, 5)
                : AirbusAocLskTextY(page, 4);
            int leftRow2 = DcduStyleManager.IsBoeing
                ? BoeingTelexLskTextY(page, 6)
                : AirbusAocLskTextY(page, 5);

            int rightRow1 = DcduStyleManager.IsBoeing
                ? BoeingTelexLskTextY(page, 5)
                : AirbusAocRightLskTextY(page, 4);
            int rightRow2 = DcduStyleManager.IsBoeing
                ? BoeingTelexLskTextY(page, 6)
                : AirbusAocRightLskTextY(page, 5);

            leftRow1 = Math.Min(page.Height - actionH - 6, Math.Max(separatorY + 2, leftRow1));
            leftRow2 = Math.Min(page.Height - actionH - 6, Math.Max(leftRow1 + 30, leftRow2));
            rightRow1 = Math.Min(page.Height - actionH - 6, Math.Max(separatorY + 2, rightRow1));
            rightRow2 = Math.Min(page.Height - actionH - 6, Math.Max(rightRow1 + 30, rightRow2));

            // Airbus artwork lower LSK text sits a touch below the generic menu table.
            if (!DcduStyleManager.IsBoeing)
            {
                leftRow1 = Math.Min(page.Height - actionH - 6, leftRow1 + 3);
                leftRow2 = Math.Min(page.Height - actionH - 6, leftRow2 + 8);
                rightRow1 = Math.Min(page.Height - actionH - 6, rightRow1 + 8);
                rightRow2 = Math.Min(page.Height - actionH - 6, rightRow2 + 18);
            }

            string responseCode = (message?.header?.Responses ?? "NE").Trim().ToUpperInvariant();
            bool canReply = message != null &&
                string.Equals(message.type, "CPDLC", StringComparison.OrdinalIgnoreCase) &&
                !message.outbound &&
                !message.acknowledged &&
                message.header != null &&
                !string.IsNullOrWhiteSpace(responseCode) &&
                !string.Equals(responseCode, "NE", StringComparison.OrdinalIgnoreCase);

            if (canReply)
            {
                switch (responseCode)
                {
                    case "WU":
                        AddStyledMessageAction(page, "*UNABLE", leftX, leftRow1, leftW, actionH, ContentAlignment.MiddleLeft, () => ReplyMessage(EventArgs.Empty, message, "UNABLE"));
                        AddStyledMessageAction(page, "*RETURN", leftX, leftRow2, leftW, actionH, ContentAlignment.MiddleLeft, () => ClearPreview());
                        AddStyledMessageAction(page, "STBY*", rightX, rightRow1, rightW, actionH, ContentAlignment.MiddleRight, () => ReplyMessage(EventArgs.Empty, message, "STANDBY"));
                        AddStyledMessageAction(page, "WILCO*", rightX, rightRow2, rightW, actionH, ContentAlignment.MiddleRight, () => ReplyMessage(EventArgs.Empty, message, "WILCO"));
                        return;

                    case "AN":
                        AddStyledMessageAction(page, "*NEG", leftX, leftRow1, leftW, actionH, ContentAlignment.MiddleLeft, () => ReplyMessage(EventArgs.Empty, message, "NEGATIVE"));
                        AddStyledMessageAction(page, "*RETURN", leftX, leftRow2, leftW, actionH, ContentAlignment.MiddleLeft, () => ClearPreview());
                        AddStyledMessageAction(page, "STBY*", rightX, rightRow1, rightW, actionH, ContentAlignment.MiddleRight, () => ReplyMessage(EventArgs.Empty, message, "STANDBY"));
                        AddStyledMessageAction(page, "AFFIRM*", rightX, rightRow2, rightW, actionH, ContentAlignment.MiddleRight, () => ReplyMessage(EventArgs.Empty, message, "AFFIRMATIVE"));
                        return;

                    case "R":
                        AddStyledMessageAction(page, "*RETURN", leftX, leftRow2, leftW, actionH, ContentAlignment.MiddleLeft, () => ClearPreview());
                        AddStyledMessageAction(page, "STBY*", rightX, rightRow1, rightW, actionH, ContentAlignment.MiddleRight, () => ReplyMessage(EventArgs.Empty, message, "STANDBY"));
                        AddStyledMessageAction(page, "ROGER*", rightX, rightRow2, rightW, actionH, ContentAlignment.MiddleRight, () => ReplyMessage(EventArgs.Empty, message, "ROGER"));
                        return;
                }
            }

            if (DatalinkPrinter.IsPrintableMessage(message))
            {
                AddStyledMessageAction(page, "*PRINT", leftX, leftRow1, leftW, actionH, ContentAlignment.MiddleLeft, () => PrintDatalinkMessage(message));
                if (latestPrintedDatalinkPrintJob != null)
                {
                    AddStyledMessageAction(page, "*REPRINT", leftX, leftRow2, leftW, actionH, ContentAlignment.MiddleLeft, () => ReprintButton_Click(boeingReprintButton, EventArgs.Empty));
                }
            }

            AddStyledMessageAction(page, "DELETE*", rightX, rightRow1, rightW, actionH, ContentAlignment.MiddleRight, () => DeleteElement(EventArgs.Empty, message));
            AddStyledMessageAction(page, "CLOSE*", rightX, rightRow2, rightW, actionH, ContentAlignment.MiddleRight, () => ClearPreview());
        }

        private void ShowStyledMessagePreview(CPDLCMessage message, List<System.Windows.Forms.Label> responses)
        {
            if (messageFormatPanel == null || messageFormatPanel.IsDisposed || screenPanel == null)
            {
                return;
            }

            HideMainScreenForStyledMessagePreview();

            messageFormatPanel.SuspendLayout();
            messageFormatPanel.Controls.Clear();
            messageFormatPanel.Visible = true;
            messageFormatPanel.Enabled = true;
            messageFormatPanel.Location = new Point(0, 0);
            messageFormatPanel.Size = screenPanel.ClientSize;
            messageFormatPanel.BackColor = Color.Transparent;
            messageFormatPanel.AutoScroll = false;
            messageFormatPanel.AutoScrollMinSize = Size.Empty;
            messageFormatPanel.FlowDirection = FlowDirection.LeftToRight;
            messageFormatPanel.WrapContents = false;
            messageFormatPanel.BringToFront();

            Panel page = new()
            {
                BackColor = Color.Transparent,
                Margin = Padding.Empty,
                Padding = Padding.Empty,
                Size = messageFormatPanel.ClientSize
            };

            int separatorY = DcduStyleManager.IsBoeing
                ? Math.Max(154, page.Height - 82)
                : Math.Max(142, page.Height - 118);
            int bottomTop = separatorY + 8;

            page.Paint += (_, e) =>
            {
                using Pen linePen = new Pen(DcduStyleManager.IsBoeing ? Color.FromArgb(220, 220, 232, 236) : DcduTheme.CyanWhite, 1.0f);
                e.Graphics.DrawLine(linePen, 20, separatorY, Math.Max(20, page.Width - 10), separatorY);

                if (!DcduStyleManager.IsBoeing)
                {
                    int leftDivider = Math.Max(130, page.Width / 3);
                    int rightDivider = Math.Max(leftDivider + 80, page.Width - page.Width / 3);
                    e.Graphics.DrawLine(linePen, leftDivider, separatorY, leftDivider, Math.Max(separatorY, page.Height - 8));
                    e.Graphics.DrawLine(linePen, rightDivider, separatorY, rightDivider, Math.Max(separatorY, page.Height - 8));
                }
            };

            messageFormatPanel.Controls.Add(page);

            Font headerFont = DcduStyleManager.IsBoeing
                ? CreateDpiStablePointFont("Consolas", 10.8f, FontStyle.Bold)
                : CreateDpiStablePointFont("Consolas", 11.2f, FontStyle.Bold);
            Font bodyFont = GetMessageTextFont(true);

            AddStyledPreviewText(page, StyledPreviewHeaderText(message), 20, 4, Math.Max(1, page.Width - 132), 24, DcduTheme.Green, headerFont);
            AddStyledPreviewText(page, "OPEN", page.Width - 96, 4, 88, 24, DcduStyleManager.IsBoeing ? DcduTheme.Cyan : DcduTheme.Cyan, headerFont, ContentAlignment.MiddleRight);

            string previewText = GetPreviewMessageText(message).ToUpperInvariant();
            if (IsClearanceStatusText(message?.message ?? string.Empty))
            {
                previewText = previewText.Trim();
            }

            AddStyledPreviewBody(
                page,
                previewText,
                20,
                36,
                Math.Max(1, page.Width - 40),
                Math.Max(40, separatorY - 44),
                bodyFont);

            AddStyledPreviewActions(page, message, separatorY);

            messageFormatPanel.ResumeLayout(false);
            HidePreviewHorizontalScrollbar();
            page.BringToFront();
            page.Focus();
        }

        private void MessageClicked(object sender, EventArgs e)
        {
            if (sender is not System.Windows.Forms.Label clickedLabel || outputTable == null)
            {
                return;
            }

            int messageIndex = outputTable.Controls.GetChildIndex(clickedLabel) - 1;
            try
            {
                KeyEventArgs kE = (KeyEventArgs)e;
                if (kE.KeyCode == Keys.Enter || kE.KeyCode == Keys.Space)
                {
                    messageIndex++;
                    throw new Exception();
                }
                else
                {
                    return;
                }
            }
            catch
            {
                if (messageIndex < 0 || messageIndex >= outputTable.Controls.Count)
                {
                    return;
                }

                if (outputTable.Controls[messageIndex] is not CPDLCMessage _sender)
                {
                    return;
                }
                previewMessage = _sender;
                MarkMessageRead(_sender);
                System.Windows.Forms.Label _timeStamp = (System.Windows.Forms.Label)outputTable.Controls[messageIndex - 1];
                List<System.Windows.Forms.Label> responses = new();


                string responseCode = (_sender.header?.Responses ?? "NE").Trim().ToUpperInvariant();
                bool hasReplyHeader = _sender.header != null &&
                    !string.IsNullOrWhiteSpace(responseCode) &&
                    !string.Equals(responseCode, "NE", StringComparison.OrdinalIgnoreCase);

                if (string.Equals(_sender.type, "CPDLC", StringComparison.OrdinalIgnoreCase) &&
                    !_sender.outbound &&
                    !_sender.acknowledged &&
                    hasReplyHeader)
                {
                    string messageText = _sender.message ?? string.Empty;
                    if (messageText.Contains("CLR TO") || messageText.Contains("CLRD TO") || messageText.Contains("CLEARED TO"))
                    {
                        AccessibleLabel acceptLabel = CreateSpecialLabel("> ACCEPT", false);
                        AccessibleLabel rejectLabel = CreateSpecialLabel("> REJECT", false);
                        switch (responseCode)
                        {
                            case "WU":
                                acceptLabel.Click += (lSender, le) => ReplyMessage(e, previewMessage, "WILCO");
                                acceptLabel.KeyDown += (lSender, le) => ReplyMessage(e, previewMessage, "WILCO");
                                rejectLabel.Click += (lSender, le) => ReplyMessage(e, previewMessage, "UNABLE");
                                rejectLabel.KeyDown += (lSender, le) => ReplyMessage(e, previewMessage, "UNABLE");
                                break;

                            case "AN":
                                acceptLabel.Click += (lSender, le) => ReplyMessage(e, previewMessage, "AFFIRMATIVE");
                                acceptLabel.KeyDown += (lSender, le) => ReplyMessage(e, previewMessage, "AFFIRMATIVE");
                                rejectLabel.Click += (lSender, le) => ReplyMessage(e, previewMessage, "NEGATIVE");
                                rejectLabel.KeyDown += (lSender, le) => ReplyMessage(e, previewMessage, "NEGATIVE");
                                break;

                            case "R":
                                acceptLabel.Click += (lSender, le) => ReplyMessage(e, previewMessage, "ROGER");
                                acceptLabel.KeyDown += (lSender, le) => ReplyMessage(e, previewMessage, "ROGER");
                                rejectLabel.Click += (lSender, le) => ReplyMessage(e, previewMessage, "UNABLE");
                                rejectLabel.KeyDown += (lSender, le) => ReplyMessage(e, previewMessage, "UNABLE");
                                break;
                        }

                        if (!string.IsNullOrWhiteSpace(acceptLabel.Text) && !string.IsNullOrWhiteSpace(rejectLabel.Text))
                        {
                            responses.Add(acceptLabel);
                            responses.Add(rejectLabel);
                        }

                        responses.Add(standbyLabel);
                    }
                    else
                    {
                        switch (responseCode)
                        {
                            case "WU":
                                responses.Add(wilcoLabel);
                                responses.Add(unableLabel);
                                responses.Add(standbyLabel);
                                break;

                            case "AN":
                                responses.Add(affirmativeLabel);
                                responses.Add(negativeLabel);
                                responses.Add(standbyLabel);
                                break;

                            case "R":
                                responses.Add(rogerLabel);
                                responses.Add(standbyLabel);
                                break;
                        }
                    }

                    responses.Add(freeTextLabel);
                }
                else if (string.Equals(_sender.type, "CPDLC", StringComparison.OrdinalIgnoreCase) &&
                         !_sender.outbound &&
                         !_sender.acknowledged)
                {
                    // Some locally generated/debug CPDLC messages have no CPDLCResponse header.
                    // They must still open in the styled preview, but without reply action buttons.
                    responses.Add(freeTextLabel);
                }
                else if (string.Equals(_sender.type, "TELEX", StringComparison.OrdinalIgnoreCase) && !_sender.outbound)
                {
                    responses.Add(freeTextLabel);
                }
                else if (string.Equals(_sender.type, "SYSTEM", StringComparison.OrdinalIgnoreCase) &&
                         IsCpdlcStationDetectedText(_sender.message))
                {
                    System.Windows.Forms.Label logonLabel = CreateCpdlcStationDetectedLogonLabel(_sender);
                    if (logonLabel != null)
                    {
                        responses.Add(logonLabel);
                    }
                }

                ShowStyledMessagePreview(_sender, responses);
            }
        }
        private Task ADSCParser(string _response, string _sender)
        {
            string[] responseElements = _response.Split(' ');
            try
            {
                Convert.ToInt32(responseElements[2]);
            }
            catch
            {
                return Task.CompletedTask;
            }
            Contract _contract;
            switch (responseElements[1])
            {
                case "PERIODIC":
                    _contract = new Contract(this, _sender, responseElements[2]);
                    contracts.Add(_contract);
                    _contract.StartContract();

                    break;

                case "CANCEL":
                    _contract = contracts.Where(x => x.sender == _sender && x.contractLength == responseElements[2]).FirstOrDefault();
                    if (_contract != null)
                    {
                        _contract.StopContract();
                        contracts.Remove(_contract);
                    }

                    break;
            }

            return Task.CompletedTask;
        }


        private string ExtractAtisTarget(string upperText)
        {
            if (string.IsNullOrWhiteSpace(upperText))
            {
                return "ATIS";
            }

            Match afterVatat = Regex.Match(upperText, @"\bVATATIS\s+([A-Z0-9]{4}(?:_[AD])?(?:_ATIS)?)\b");
            if (afterVatat.Success)
            {
                return afterVatat.Groups[1].Value;
            }

            Match atisTarget = Regex.Match(upperText, @"\b[A-Z0-9]{4}(?:_[AD])?_ATIS\b|\b[A-Z0-9]{4}_[AD]\b");
            return atisTarget.Success ? atisTarget.Value : "ATIS";
        }

        private bool TryWriteAtisUnavailableResponse(string response)
        {
            if (string.IsNullOrWhiteSpace(response))
            {
                return false;
            }

            string normalized = response
                .Replace("\r\n", "\n")
                .Replace("\r", "\n")
                .Trim();

            string upper = normalized.ToUpperInvariant();

            if (!upper.Contains("THIS ATIS IS NOT") && !upper.Contains("ATIS IS NOT AVAILABLE"))
            {
                return false;
            }

            string explicitTarget = ExtractAtisTarget(upper);
            string target = explicitTarget != "ATIS"
                ? FormatAtisTargetForList(explicitTarget)
                : GetAtisListTarget(normalized, "VATATIS", true);

            string displayMessage = target + "\nTHIS ATIS IS NOT AVAILABLE";

            if (TryCaptureSilentAtisHoverResponse(displayMessage, "ATIS", "VATATIS", false))
            {
                return true;
            }

            WriteMessage(displayMessage, "ATIS", "VATATIS");
            FlashWindow.Flash(this);
            Logger.Debug("Displayed Hoppie ATIS unavailable response: " + displayMessage.Replace("\n", " "));
            return true;
        }

        private bool TryWriteFlatInfoResponse(string sender, string type, string payload)
        {
            if (string.IsNullOrWhiteSpace(payload))
            {
                return false;
            }

            string normalizedPayload = payload
                .Replace("\r\n", "\n")
                .Replace("\r", "\n")
                .Trim();

            if (TryWriteAtisUnavailableResponse(normalizedPayload))
            {
                return true;
            }

            string upperPayload = normalizedPayload.ToUpperInvariant();

            if (!upperPayload.Contains("_ATIS") && !upperPayload.Contains("VATATIS") &&
                !Regex.IsMatch(upperPayload, @"\b[A-Z0-9]{4}_[AD]\b"))
            {
                return false;
            }

            string target = ExtractAtisTarget(upperPayload);
            if (target == "ATIS")
            {
                return false;
            }

            int targetIndex = upperPayload.IndexOf(target, StringComparison.Ordinal);
            string displayMessage = targetIndex >= 0
                ? normalizedPayload.Substring(targetIndex).Trim()
                : normalizedPayload.Trim();
            if (string.IsNullOrWhiteSpace(displayMessage))
            {
                displayMessage = target;
            }

            WriteMessage(displayMessage, "ATIS", string.IsNullOrWhiteSpace(sender) ? "VATATIS" : sender);
            FlashWindow.Flash(this);
            Logger.Debug("Displayed flat Hoppie ATIS/info response: " + displayMessage.Replace("\n", " "));
            return true;
        }

        private async Task TelexParser(string response)
        {
            var responses = hoppieParse.Matches(response);

            Logger.Debug("HOPPIE PARSER: raw response length=" + (response?.Length ?? 0) + ", packets=" + responses.Count);

            if (responses.Count == 0)
            {
                if (!TryWriteFlatInfoResponse("VATATIS", "ATIS", response) &&
                    !await TryWriteRawFlatHoppieResponseAsync(response))
                {
                    Logger.Debug("HOPPIE PARSER: response without braces ignored: " + (response ?? string.Empty));
                }

                return;
            }

            foreach (Match _response in responses)
            {
                string[] chunks = _response.Groups[1].Value.Replace("}", "").Split('{');

                string[] headerParts = chunks[0]
                    .Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);

                string sender = headerParts.Length > 0 ? headerParts[0].Trim().ToUpperInvariant() : "UNKNOWN";
                string type = headerParts.Length > 1 ? headerParts[1].Trim().ToUpperInvariant() : "INFO";

                Logger.Debug("HOPPIE PARSER: packet sender=" + sender + ", type=" + type + ", chunks=" + chunks.Length);

                bool handled = false;

                for (int i = 1; i < chunks.Length; i++)
                {
                    string payload = (chunks[i] ?? string.Empty).Trim();

                    if (payload.Length <= 2)
                    {
                        continue;
                    }

                    if (payload.StartsWith("/DATA2/", StringComparison.OrdinalIgnoreCase))
                    {
                        Logger.Debug("CPDLC Message identified, attempting to parse from " + sender);
                        await CPDLCParser(payload, sender);
                        handled = true;
                        continue;
                    }

                    if (string.Equals(type, "ADS-C", StringComparison.OrdinalIgnoreCase))
                    {
                        if (UseFSUIPC)
                        {
                            Logger.Debug("ADS-C Message identified, attempting to parse from " + sender);
                            await ADSCParser(payload, sender);
                            handled = true;
                            continue;
                        }

                        Logger.Debug("ADS-C Message identified, but no simulator connection was recognised. Ignoring.");
                        handled = true;
                        continue;
                    }

                    if (TryWriteFlatInfoResponse(sender, type, payload))
                    {
                        handled = true;
                        continue;
                    }

                    WriteMessage(payload, type, sender);
                    FlashWindow.Flash(this);
                    Logger.Debug("Displayed nested Hoppie message: sender=" + sender + ", type=" + type + ", payload=" + payload);
                    handled = true;
                }

                if (!handled)
                {
                    string flatPayload = chunks.Length > 0 ? chunks[0] : _response.Groups[1].Value;

                    if (!TryWriteFlatInfoResponse(sender, type, flatPayload))
                    {
                        handled = await TryWriteFlatHoppieMessageAsync(sender, type, flatPayload);
                    }

                    if (!handled)
                    {
                        Logger.Debug("HOPPIE PARSER: packet ignored after parse: " + flatPayload);
                    }
                }
            }

            return;
        }

        private async Task<bool> TryWriteRawFlatHoppieResponseAsync(string response)
        {
            string payload = (response ?? string.Empty)
                .Replace("\r\n", "\n")
                .Replace("\r", "\n")
                .Trim();

            if (string.IsNullOrWhiteSpace(payload) ||
                string.Equals(payload, "OK", StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            if (payload.StartsWith("OK ", StringComparison.OrdinalIgnoreCase))
            {
                payload = payload.Substring(3).Trim();
            }

            Match flat = Regex.Match(
                payload,
                @"^([A-Z0-9_]{2,20})\s+(TELEX|CPDLC|INFO|INFOREQ|ADS-C)\s+([\s\S]+)$",
                RegexOptions.IgnoreCase);

            if (!flat.Success)
            {
                return false;
            }

            string sender = flat.Groups[1].Value.Trim().ToUpperInvariant();
            string type = flat.Groups[2].Value.Trim().ToUpperInvariant();

            return await TryWriteFlatHoppieMessageAsync(sender, type, payload);
        }

        private async Task<bool> TryWriteFlatHoppieMessageAsync(string sender, string type, string flatPayload)
        {
            string payload = ExtractFlatHoppiePayload(flatPayload, sender, type);

            if (string.IsNullOrWhiteSpace(payload))
            {
                return false;
            }

            string normalizedType = string.IsNullOrWhiteSpace(type)
                ? "TELEX"
                : type.Trim().ToUpperInvariant();

            string normalizedSender = string.IsNullOrWhiteSpace(sender)
                ? "UNKNOWN"
                : sender.Trim().ToUpperInvariant();

            if (payload.StartsWith("/DATA2/", StringComparison.OrdinalIgnoreCase))
            {
                Logger.Debug("Flat CPDLC message identified, attempting to parse from " + normalizedSender);
                await CPDLCParser(payload, normalizedSender);
                return true;
            }

            if (string.Equals(normalizedType, "ADS-C", StringComparison.OrdinalIgnoreCase))
            {
                if (UseFSUIPC)
                {
                    Logger.Debug("Flat ADS-C message identified, attempting to parse from " + normalizedSender);
                    await ADSCParser(payload, normalizedSender);
                }
                else
                {
                    Logger.Debug("Flat ADS-C message identified, but no simulator connection was recognised. Ignoring.");
                }

                return true;
            }

            // This is the important TELEX fix:
            // Some Hoppie TELEX packets arrive as {SENDER TELEX MESSAGE} without an inner {MESSAGE} block.
            // Older code only displayed nested packets and silently dropped this flat form.
            WriteMessage(payload, normalizedType, normalizedSender);
            FlashWindow.Flash(this);
            Logger.Debug("Displayed flat Hoppie message: sender=" + normalizedSender + ", type=" + normalizedType + ", payload=" + payload);
            return true;
        }

        private static string ExtractFlatHoppiePayload(string flatPayload, string sender, string type)
        {
            string payload = (flatPayload ?? string.Empty).Replace("}", "").Trim();

            if (string.IsNullOrWhiteSpace(payload))
            {
                return string.Empty;
            }

            string normalizedSender = (sender ?? string.Empty).Trim();
            string normalizedType = (type ?? string.Empty).Trim();

            if (!string.IsNullOrWhiteSpace(normalizedSender) &&
                payload.StartsWith(normalizedSender, StringComparison.OrdinalIgnoreCase))
            {
                payload = payload.Substring(normalizedSender.Length).Trim();
            }

            if (!string.IsNullOrWhiteSpace(normalizedType) &&
                payload.StartsWith(normalizedType, StringComparison.OrdinalIgnoreCase))
            {
                payload = payload.Substring(normalizedType.Length).Trim();
            }

            return payload.Trim();
        }

        private async Task CPDLCParser(string _response, string _sender)
        {
            bool _showUser = true;
            string messageString;

            var unit = cpdlcUnitParse.Match(_response);
            if (unit.Success)
            {
                CurrentATCUnit = unit.Value.Trim('_', '@');
            }

            var responses = cpdlcHeaderParse.Matches(_response);
            if (responses.Count < 4)
            {
                Logger.Debug("Malformed CPDLC packet ignored: header field count=" + responses.Count);
                return;
            }

            if (!int.TryParse(responses[1].Value.Trim('/'), out int parsedMessageId))
            {
                Logger.Debug("Malformed CPDLC packet ignored: invalid message id.");
                return;
            }

            string responseIdText = responses[2].Value.Trim('/');
            int parsedResponseId = 0;
            if (!string.IsNullOrWhiteSpace(responseIdText) && !int.TryParse(responseIdText, out parsedResponseId))
            {
                Logger.Debug("Malformed CPDLC packet ignored: invalid response id.");
                return;
            }

            CPDLCResponse header = new()
            {
                DataType = responses[0].Value.Trim('/'),
                MessageID = parsedMessageId,
                ResponseID = parsedResponseId,
                Responses = responses[3].Value.Trim('/')
            };

            string[] messageContent = _response.Split(new string[] { header.Responses + "/" }, StringSplitOptions.None);
            if (messageContent.Length < 2)
            {
                Logger.Debug("Malformed CPDLC packet ignored: missing message content.");
                return;
            }

            if (!string.IsNullOrWhiteSpace(callsign) && messageContent[1].Contains(callsign))
            {
                messageString = messageContent[1].Split(new string[] { callsign }, StringSplitOptions.None).Last();
            }
            else
            {
                messageString = messageContent[1];
            }
            if (messageString.StartsWith("HANDOVER"))
            {
                string nextATCUnit = messageString.Split(' ').Last().Trim('@').Trim();
                SetNextAtcUnitDisplay(nextATCUnit);
                CurrentATCUnit = null;
                pendingLogon = nextATCUnit;
                StartCpdlcHandoverFrequencyWatch(nextATCUnit);
                await SendCPDLCMessage(nextATCUnit, "CPDLC", String.Format("/data2/{0}//Y/REQUEST LOGON", messageOutCounter), false);
                messageOutCounter += 1;
                _showUser = false;
            }
            else if (messageString.StartsWith("LOGON ACCEPTED"))
            {
                string connectedUnit = !string.IsNullOrWhiteSpace(pendingLogon)
                    ? pendingLogon
                    : NormalizeAtcUnitCallsign(_sender);

                CurrentATCUnit = connectedUnit;
                ClearNextAtcUnitDisplay();
                if (string.Equals(cpdlcHandoverTargetCode, connectedUnit, StringComparison.OrdinalIgnoreCase) &&
                    IsCpdlcUnitVerifiedOnActiveFrequency(connectedUnit))
                {
                    StopCpdlcHandoverFrequencyWatch();
                }

                WriteMessage("CPDLC CONNECTED TO: " + CurrentATCUnit, "CPDLC", _sender, false, header);
                _showUser = false;
            }
            else if (messageString.StartsWith("CURRENT ATC UNIT") || messageString.StartsWith("CURRENT ATS UNIT"))
            {
                string connectedUnit = ExtractCurrentAtcUnitFromMessage(messageString, _sender);
                if (!string.IsNullOrWhiteSpace(connectedUnit))
                {
                    CurrentATCUnit = connectedUnit;
                    if (string.Equals(nextAtcUnitText, connectedUnit, StringComparison.OrdinalIgnoreCase))
                    {
                        ClearNextAtcUnitDisplay();
                    }
                }

                _showUser = false;
            }

            // Keep @...@ tokens intact: the styled DCDU preview uses them to highlight
            // clearance values such as runway, SID, squawk, frequency and flight level.
            string message = callsign + " " + messageString.Replace("@@", "N/A").Replace("_", "");
            message = Regex.Replace(message, @"\s+", " ");

            Logger.Debug(message);

            if (message.Contains("LOGOFF"))
            {
                StartCpdlcVerifiedSuggestionCooldownForCurrentConnection("CPDLC logoff received", _sender);
                CurrentATCUnit = null;
                pendingLogon = null;
                ClearNextAtcUnitDisplay();
                StopCpdlcHandoverFrequencyWatch();
            }
            else if (IsCpdlcGoodbyeOrUnicomInstruction(message))
            {
                StartCpdlcVerifiedSuggestionCooldownForCurrentConnection("CPDLC goodbye / monitor advisory", _sender);
                CurrentATCUnit = null;
                pendingLogon = null;
                ClearNextAtcUnitDisplay();
                StopCpdlcHandoverFrequencyWatch();
            }

            if (_showUser)
            {
                WriteMessage(message, "CPDLC", _sender, false, header);

                FlashWindow.Flash(this);
            }

            return;
        }

        private TimerLabel FindMenuLabelForMessage(CPDLCMessage message)
        {
            try
            {
                if (message == null || outputTable == null || outputTable.IsDisposed)
                {
                    return null;
                }

                int index = outputTable.Controls.GetChildIndex(message);
                if (index >= 0 &&
                    index + 1 < outputTable.Controls.Count &&
                    outputTable.Controls[index + 1] is TimerLabel menuLabel)
                {
                    return menuLabel;
                }
            }
            catch
            {
                // Cosmetic lookup only.
            }

            return null;
        }

        private void SetInlineCpdlcReplyStatus(CPDLCMessage statusMessage, TimerLabel statusMenuLabel, string statusText, Color color, bool startAutoDelete)
        {
            SafeUi(() =>
            {
                if (statusMessage == null || statusMessage.IsDisposed)
                {
                    return;
                }

                statusMessage.message = statusText;
                statusMessage.Text = statusText;
                statusMessage.ForeColor = color;
                statusMessage.Invalidate();

                TimerLabel targetMenuLabel = statusMenuLabel ?? FindMenuLabelForMessage(statusMessage);
                if (targetMenuLabel != null && !targetMenuLabel.IsDisposed)
                {
                    targetMenuLabel.Text = string.Empty;
                    targetMenuLabel.Tag = null;
                    targetMenuLabel.Paint -= OpenMessageIndicator_Paint;
                    targetMenuLabel.CanFlash = false;
                    targetMenuLabel.ForeColor = color;
                    targetMenuLabel.Invalidate();

                    if (startAutoDelete)
                    {
                        StartAutoDeleteRequestMessageIfNeeded(statusMessage, targetMenuLabel);
                    }
                }

                ApplyMessageFilter();
            });
        }

        private System.Windows.Forms.Timer StartInlineCpdlcReplySpinner(CPDLCMessage statusMessage, TimerLabel statusMenuLabel, string replyText)
        {
            string[] frames = { "◷", "◶", "◵", "◴" };
            int frame = 0;
            string cleanReply = NormalizeCpdlcOverviewText(replyText);
            if (cleanReply == "STBY")
            {
                cleanReply = "STANDBY";
            }
            if (string.IsNullOrWhiteSpace(cleanReply))
            {
                cleanReply = "CPDLC";
            }

            System.Windows.Forms.Timer timer = new()
            {
                Interval = 250
            };

            timer.Tick += (_, __) =>
            {
                frame = (frame + 1) % frames.Length;
                SetInlineCpdlcReplyStatus(statusMessage, statusMenuLabel, frames[frame] + " " + cleanReply, DcduTheme.Amber, false);
            };

            timer.Start();
            return timer;
        }

        private async Task<bool> TrySendCpdlcPacketForInlineStatusAsync(string recipient, string messageType, string packetData)
        {
            var connectionValues = new Dictionary<string, string> {
                {"logon", logonCode ?? String.Empty},
                {"from", callsign ?? String.Empty},
                {"to", recipient ?? String.Empty},
                {"type", messageType ?? String.Empty},
                {"packet", packetData ?? String.Empty}
            };

            if (DebugUiPreviewMode)
            {
                Logger.Debug(String.Format("DEBUG UI PREVIEW: simulated inline CPDLC send to={0} | type={1} | packetLen={2}", SafeLogValue(recipient), SafeLogValue(messageType), (packetData ?? string.Empty).Length));
                await Task.Delay(350);
                return true;
            }

            try
            {
                UpdateSendingProgress(() => SendingProgress.Visible = true);
                UpdateSendingProgress(() => SendingProgress.Value = 0);
                UpdateSendingProgress(() => SendingProgress.PerformStep());

                using FormUrlEncodedContent content = new(connectionValues);
                HttpResponseMessage response = await webclient.PostAsync(HoppieConnectUrl, content);

                UpdateSendingProgress(() => SendingProgress.PerformStep());

                string responseString = await response.Content.ReadAsStringAsync();
                string printString = responseString.ToString().ToUpper().Trim();

                Logger.Debug(String.Format("INLINE PACKET SENT: to={0} | type={1} | packetLen={2}", SafeLogValue(recipient), SafeLogValue(messageType), (packetData ?? string.Empty).Length));
                Logger.Debug(String.Format("INLINE HOPPIE RESPONSE: status={0} | length={1}", ClassifyHoppieResponseForLog(responseString), (responseString ?? string.Empty).Length));

                if (IsHoppieNetworkLoadResponse(printString))
                {
                    HandleHoppieNetworkLoadResponse(printString);
                    UpdateSendingProgress(() => SendingProgress.Visible = false);
                    return false;
                }

                if (printString.Contains("ERROR") || !response.IsSuccessStatusCode)
                {
                    UpdateSendingProgress(() => SendingProgress.Visible = false);
                    return false;
                }

                if (isErrorState)
                {
                    WriteMessage("HOPPIE CONNECTIVITY RESTORED.", "SYSTEM", "SYSTEM");
                    isErrorState = false;
                }

                UpdateSendingProgress(() => SendingProgress.PerformStep());

                if (printString != "OK")
                {
                    await TelexParser(printString);
                }

                UpdateSendingProgress(() => SendingProgress.Visible = false);
                return true;
            }
            catch (Exception ex)
            {
                Logger.Debug("Inline CPDLC send failed: " + ex.Message);
                UpdateSendingProgress(() => SendingProgress.Visible = false);
                return false;
            }
        }

        private async Task SendDirectWilcoFromOverviewAsync(CPDLCMessage message, TimerLabel menuLabel)
        {
            if (!CanDirectWilcoFromOverview(message) || styledMessageReplySendInProgress)
            {
                return;
            }

            System.Windows.Forms.Timer spinnerTimer = null;

            try
            {
                styledMessageReplySendInProgress = true;

                if (menuLabel != null && !menuLabel.IsDisposed)
                {
                    menuLabel.CanFlash = false;
                    menuLabel.ForeColor = DcduTheme.Amber;
                    ConfigureOpenMessageIndicator(menuLabel);
                    menuLabel.Invalidate();
                }

                string replyText = "WILCO";
                SetOriginalOverviewReplyStatus(message, menuLabel, "◷", DcduTheme.Amber, false);
                spinnerTimer = StartOriginalOverviewReplySpinner(message, menuLabel);

                message.header.ResponseID = messageOutCounter;
                string packet = string.Format(
                    "/data2/{0}/{1}/N/WILCO",
                    message.header.ResponseID,
                    message.header.MessageID);

                TrackClearanceReply(message, replyText);

                Task<bool> sendTask = TrySendCpdlcPacketForInlineStatusAsync(message.recipient, message.type, packet);
                await Task.WhenAll(sendTask, Task.Delay(900));

                bool sent = sendTask.Result;

                spinnerTimer.Stop();
                spinnerTimer.Dispose();
                spinnerTimer = null;

                if (sent)
                {
                    MarkOriginalMessageRepliedFromOverview(message, menuLabel, replyText);
                    messageOutCounter += 1;
                }
                else
                {
                    SetOriginalOverviewReplyStatus(message, menuLabel, "✕", CallsignMismatchAlarmColor(), false);

                    if (menuLabel != null && !menuLabel.IsDisposed)
                    {
                        menuLabel.ForeColor = CallsignMismatchAlarmColor();
                        ConfigureOpenMessageIndicator(menuLabel);
                        menuLabel.Invalidate();
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.Debug("Direct WILCO from overview failed: " + ex.Message);

                if (spinnerTimer != null)
                {
                    spinnerTimer.Stop();
                    spinnerTimer.Dispose();
                    spinnerTimer = null;
                }

                SetOriginalOverviewReplyStatus(message, menuLabel, "✕", CallsignMismatchAlarmColor(), false);

                if (menuLabel != null && !menuLabel.IsDisposed)
                {
                    menuLabel.ForeColor = CallsignMismatchAlarmColor();
                    ConfigureOpenMessageIndicator(menuLabel);
                    menuLabel.Invalidate();
                }
            }
            finally
            {
                if (spinnerTimer != null)
                {
                    spinnerTimer.Stop();
                    spinnerTimer.Dispose();
                }

                styledMessageReplySendInProgress = false;
            }
        }

