        private System.Windows.Forms.Label AddEmbeddedSetupLabel(Control parent, string text, int x, int y, int width, int height, ContentAlignment align = ContentAlignment.MiddleLeft, Color? color = null, Font font = null)
        {
            System.Windows.Forms.Label label = new()
            {
                AutoSize = false,
                BackColor = Color.Transparent,
                ForeColor = color ?? MainPrimaryTextColor(),
                Font = font ?? EmbeddedSetupMenuFont(),
                Text = text ?? string.Empty,
                TextAlign = align,
                Location = new Point(ScaleChildX(parent, x, width), ScaleChildY(parent, y, height)),
                Size = new Size(ScaleChildWidth(parent, x, width), ScaleChildHeight(parent, y, height)),
                Margin = SPad(new Padding(0)),
                Padding = SPad(new Padding(0))
            };

            parent.Controls.Add(label);
            label.BringToFront();
            return label;
        }

        private TextBox AddEmbeddedSetupTextBox(Control parent, string key, string value, int x, int y, int width, int maxLength, bool password = false)
        {
            TextBox box = new()
            {
                Name = "embeddedSetup_" + key,
                BackColor = Color.FromArgb(3, 8, 15),
                ForeColor = MainPrimaryTextColor(),
                BorderStyle = BorderStyle.FixedSingle,
                CharacterCasing = CharacterCasing.Normal,
                Font = EmbeddedSetupValueFont(),
                Location = new Point(x, y),
                Size = new Size(width, 24),
                MaxLength = maxLength,
                Text = value ?? string.Empty,
                UseSystemPasswordChar = password,
                Multiline = false
            };

            box.TextChanged += (_, __) => SaveEmbeddedSetupTextValue(key, box.Text ?? string.Empty);
            parent.Controls.Add(box);
            box.BringToFront();
            embeddedSetupInputs[key] = box;
            return box;
        }

        private ComboBox AddEmbeddedSetupPrinterDropdown(Control parent, int x, int y, int width)
        {
            IReadOnlyList<string> printers = DatalinkPrinter.GetInstalledPrinterNames();
            ComboBox selector = new()
            {
                Name = "embeddedSetup_PrinterName",
                BackColor = Color.FromArgb(3, 8, 15),
                ForeColor = MainPrimaryTextColor(),
                FlatStyle = FlatStyle.Popup,
                DropDownStyle = ComboBoxStyle.DropDownList,
                Font = CreateDpiStablePointFont("Consolas", DcduStyleManager.IsBoeing ? 7.3f : 7.7f, FontStyle.Bold),
                Location = new Point(ScaleChildX(parent, x, width), ScaleChildY(parent, y, 25)),
                Size = new Size(ScaleChildWidth(parent, x, width), S(25)),
                MaxDropDownItems = 12
            };

            const string selectPrinter = "<SELECT PRINTER>";
            selector.Items.Add(selectPrinter);
            foreach (string printer in printers)
            {
                selector.Items.Add(printer);
            }

            string configured = SelectedPrinterName;
            string selected = printers.FirstOrDefault(name => string.Equals(name, configured, StringComparison.OrdinalIgnoreCase));

            if (!string.IsNullOrWhiteSpace(selected))
            {
                selector.SelectedItem = selected;
            }
            else
            {
                selector.SelectedItem = selectPrinter;
            }

            selector.SelectedIndexChanged += (_, __) =>
            {
                if (selector.SelectedItem is string printerName && printers.Contains(printerName))
                {
                    SelectedPrinterName = printerName;
                    embeddedPrinterStatus = DatalinkPrinter.GetPrinterStatus(printerName).Message;
                }
            };

            parent.Controls.Add(selector);
            selector.BringToFront();
            return selector;
        }

        private string EmbeddedSetupOnOff(bool value)
        {
            return value ? "ON" : "OFF";
        }

        private void SaveEmbeddedSetupTextValue(string key, string value)
        {
            try
            {
                switch (key)
                {
                    case SetupInputCid:
                        if (string.IsNullOrWhiteSpace(value))
                        {
                            SavedCID = 0;
                        }
                        else if (int.TryParse(value.Trim(), out int cidValue) && cidValue > 0)
                        {
                            SavedCID = cidValue;
                        }
                        break;

                    case SetupInputHoppie:
                        SavedHoppieCode = value ?? string.Empty;
                        break;

                    case SetupInputSimbrief:
                        SimbriefID = value ?? string.Empty;
                        break;
                }

                Properties.Settings.Default.Save();
            }
            catch (Exception ex)
            {
                try
                {
                    Logger.Debug("Embedded setup save failed: " + ex.Message);
                }
                catch
                {
                }
            }
        }

        private void ShowEmbeddedSetupMainMenu()
        {
            PrepareEmbeddedSetupPage(EmbeddedSetupPage.MainMenu);
            Panel page = CreateEmbeddedSetupCanvas();
            Font titleFont = EmbeddedSetupTitleFont();
            Font menuFont = EmbeddedSetupMenuFont();
